/**
 * Extracts the goal count from a raw team object returned by any Statpal
 * football endpoint.  Different endpoints/subscriptions use different field
 * names for the same datum, so we try all known variants in priority order:
 *
 *   goals       — standard SportsAPI Pro / Statpal v2 field
 *   score       — alternate English name used by some Statpal plans
 *   pontuação   — Portuguese (with accent, UTF-8)
 *   pontuacao   — Portuguese (without accent, ASCII-safe)
 *   gols        — Portuguese word for "goals"
 *   goal        — singular variant
 *
 * If none are found the match-level `placar` / `score` / `resultado` string
 * ("2:1") is split and the correct half is returned.
 */
function extractStatpalTeamGoals(
  team: Record<string, unknown>,
  matchRaw: Record<string, unknown>,
  side: "home" | "away",
): string {
  const direct =
    team["goals"] ??
    team["score"] ??
    team["pontuação"] ??
    team["pontuacao"] ??
    team["gols"] ??
    team["goal"];
  if (direct !== undefined && direct !== null && String(direct).trim() !== "") {
    return String(direct);
  }
  // Fall back to a match-level "placar"/"score" string like "2:1"
  const placar = String(
    matchRaw["placar"] ?? matchRaw["score"] ?? matchRaw["resultado"] ?? "",
  );
  if (placar && /\d/.test(placar)) {
    const sep = placar.includes(":") ? ":" : placar.includes("-") ? "-" : null;
    if (sep) {
      const parts = placar.split(sep);
      return side === "home"
        ? (parts[0]?.trim() ?? "0")
        : (parts[1]?.trim() ?? "0");
    }
  }
  return "0";
}

function normalizeStatpalMatch(raw: Partial<SAPIMatchV2>): SAPIMatchV2 {
  const rawMap = raw as Record<string, unknown>;
  const home =
    raw.home && typeof raw.home === "object"
      ? (raw.home as Record<string, unknown>)
      : ({ id: "", name: "Unknown", goals: "0" } as Record<string, unknown>);
  const away =
    raw.away && typeof raw.away === "object"
      ? (raw.away as Record<string, unknown>)
      : ({ id: "", name: "Unknown", goals: "0" } as Record<string, unknown>);

  const homeGoals = extractStatpalTeamGoals(home, rawMap, "home");
  const awayGoals = extractStatpalTeamGoals(away, rawMap, "away");

  return {
    main_id: String(raw.main_id ?? ""),
    fallback_id_1: String(raw.fallback_id_1 ?? ""),
    fallback_id_2: String(raw.fallback_id_2 ?? ""),
    fallback_id_3: String(raw.fallback_id_3 ?? ""),
    status: String(raw.status ?? ""),
    date: String(raw.date ?? ""),
    time: String(raw.time ?? ""),
    inj_time: String(raw.inj_time ?? ""),
    inj_minute: String(raw.inj_minute ?? ""),
    venue: raw.venue,
    home: {
      id: String(home["id"] ?? ""),
      name: String(home["name"] ?? "Unknown"),
      goals: homeGoals,
      win_on_agg: home["win_on_agg"] as string | undefined,
    },
    away: {
      id: String(away["id"] ?? ""),
      name: String(away["name"] ?? "Unknown"),
      goals: awayGoals,
      win_on_agg: away["win_on_agg"] as string | undefined,
    },
    events: raw.events ?? null,
    ht: raw.ht,
    ft: raw.ft,
    et: raw.et ?? null,
    penalties: raw.penalties ?? null,
    has_live_stats: raw.has_live_stats,
    inplay_odds_running: String(raw.inplay_odds_running ?? "False"),
  };
}

function normalizeStatpalLeagues(
  leaguesRaw: SAPILeagueV2 | SAPILeagueV2[] | null | undefined,
): SAPILeagueV2[] {
  return statpalList(leaguesRaw)
    .filter((league): league is SAPILeagueV2 => !!league)
    .map((league) => ({
      id: String(league.id ?? ""),
      name: String(league.name ?? ""),
      country: String(league.country ?? ""),
      cup: String(league.cup ?? "False"),
      match: statpalList(league.match).map((match) =>
        normalizeStatpalMatch(match),
      ),
    }));
}

function extractStatpalLeagueFeed(
  raw: Record<string, unknown>,
  preferredRoot?: string,
): { leagues: SAPILeagueV2[]; updatedTs: number } {
  const isLeagueFeedEnvelope = (v: unknown): v is StatpalLeagueFeedEnvelope =>
    !!v && typeof v === "object" && !Array.isArray(v);

  // 1. Try the preferred root key (e.g. "live_matches")
  const preferred =
    preferredRoot && isLeagueFeedEnvelope(raw[preferredRoot])
      ? (raw[preferredRoot] as StatpalLeagueFeedEnvelope)
      : undefined;

  // 2. Fallback: scan all top-level keys for a league-feed envelope.
  //    Previously this only matched /^matches_/i — widened to also catch
  //    keys like "live_matches", "matches", "livescores", etc. so that a
  //    Statpal response-shape change doesn't silently return zero leagues.
  const dynamic = preferred
    ? undefined
    : (Object.entries(raw).find(
        ([key, value]) =>
          (/^matches_/i.test(key) ||
            /^live_/i.test(key) ||
            key === "matches" ||
            key === "livescores") &&
          isLeagueFeedEnvelope(value),
      )?.[1] as StatpalLeagueFeedEnvelope | undefined);

  const payload = preferred ?? dynamic;
  return {
    leagues: normalizeStatpalLeagues(payload?.league),
    updatedTs:
      typeof payload?.updated_ts === "number" && Number.isFinite(payload.updated_ts)
        ? payload.updated_ts
        : 0,
  };
}

function parseStatpalStartTimestamp(dateRaw: string, timeRaw: string): number | undefined {
  if (!/^\d{2}\.\d{2}\.\d{4}$/.test(dateRaw) || !/^\d{1,2}:\d{2}$/.test(timeRaw)) {
    return undefined;
  }
  const [dayStr, monthStr, yearStr] = dateRaw.split(".");
  const [hourStr, minuteStr] = timeRaw.split(":");
  const day = Number(dayStr);
  const month = Number(monthStr);
  const year = Number(yearStr);
  const hour = Number(hourStr);
  const minute = Number(minuteStr);
  if (
    !Number.isFinite(day) ||
    !Number.isFinite(month) ||
    !Number.isFinite(year) ||
    !Number.isFinite(hour) ||
    !Number.isFinite(minute)
  ) {
    return undefined;
  }

  // Statpal's raw `date`/`time` fields for football are already UTC (same
  // convention as every other sport in this file — see `addOneHour`'s doc
  // comment: "UTC -> Portugal UTC+1"). Do NOT subtract the Lisbon offset here;
  // that previously double-applied a timezone shift and made every match's
  // ground-truth kickoff appear up to 1 hour (DST) early, which defeated the
  // too-early live guard exactly when it mattered most.
  const utcMs = Date.UTC(year, month - 1, day, hour, minute, 0, 0);
  return Math.floor(utcMs / 1000);
}

function mapStatpalFootballStatus(
  match: SAPIMatchV2,
): { description: string; code?: number; round?: number } {
  const rawStatus = String(match.status ?? "").trim();

  // ── Guard: "HH:MM" is a scheduled kickoff time, NOT a match minute. ────────
  // parseInt("18:00", 10) returns 18 (stops at ':'), which would incorrectly
  // classify a pre-match fixture as "1st half 18'" and make it pass the live
  // filter with goals "?" → score 0-0 displayed to the user.
  // Reject any status that looks like a clock time before trying parseInt.
  if (/^\d{1,2}:\d{2}(:\d{2})?$/.test(rawStatus)) {
    // Return with no code so isFootballV2LiveStatus() treats it as not-live.
    return { description: `Scheduled ${rawStatus}` };
  }

  const minute = parseInt(rawStatus, 10);
  const extraMinute = parseInt(String(match.inj_minute ?? ""), 10);
  const round = Number.isFinite(minute)
    ? minute + (Number.isFinite(extraMinute) ? extraMinute : 0)
    : undefined;

  if (Number.isFinite(minute)) {
    return {
      description: minute <= 45 ? "1st half" : "2nd half",
      code: 1,
      round,
    };
  }

  const normalized = rawStatus.toLowerCase();
  if (normalized === "ht" || normalized.includes("half time")) {
    return { description: "HT", code: 1, round: 45 };
  }
  if (normalized === "et" || normalized.includes("extra")) {
    return { description: "Extra Time", code: 1, round: 105 };
  }
  if (normalized.includes("pen")) {
    return { description: "Penalties", code: 1, round: 120 };
  }

  return { description: rawStatus, round };
}

function statpalMatchToV2Event(
  league: SAPILeagueV2,
  match: SAPIMatchV2,
): SAPIV2Event {
  const id = Number(match.main_id);
  const homeTeamId = Number(match.home.id);
  const awayTeamId = Number(match.away.id);
  const tournamentId = Number(league.id);
  const status = mapStatpalFootballStatus(match);

  return {
    id: Number.isFinite(id) ? id : 0,
    tournament: {
      id: Number.isFinite(tournamentId) ? tournamentId : undefined,
      name: league.name,
      category: {
        name: league.country,
        country: { name: league.country },
      },
    },
    homeTeam: {
      id: Number.isFinite(homeTeamId) ? homeTeamId : undefined,
      name: match.home.name,
    },
    awayTeam: {
      id: Number.isFinite(awayTeamId) ? awayTeamId : undefined,
      name: match.away.name,
    },
    homeScore: Number.parseInt(match.home.goals, 10) || 0,
    awayScore: Number.parseInt(match.away.goals, 10) || 0,
    status: {
      code: status.code,
      description: status.description,
    },
    statusCode: status.code,
    startTimestamp: parseStatpalStartTimestamp(match.date, match.time),
    tournamentId: Number.isFinite(tournamentId) ? tournamentId : undefined,
    homeTeamId: Number.isFinite(homeTeamId) ? homeTeamId : undefined,
    awayTeamId: Number.isFinite(awayTeamId) ? awayTeamId : undefined,
    roundInfo: status.round ? { round: status.round } : undefined,
    finalResultOnly: SAPI_FINISHED_STATUSES.has(match.status),
    feedLocked: SAPI_FINISHED_STATUSES.has(match.status),
  };
}

// ─── Statpal live odds → SAPIV2Event converter ───────────────────────────────
// The Statpal /v2/soccer/odds/live endpoint returns Portuguese field names
// ("partidas_ao_vivo", "informação_da_partida", "lar", "ausente", etc.).
// This helper maps that structure to the SAPIV2Event shape used everywhere else.

function mapStatpalPtPeriodToStatus(
  period: string,
  minute: number,
): { description: string; code?: number } {
  const p = period.toLowerCase();
  if ((p.includes("1") || p.includes("primeiro")) && (p.includes("metade") || p.includes("half")))
    return { description: "1st half", code: 1 };
  if ((p.includes("2") || p.includes("segundo")) && (p.includes("metade") || p.includes("half")))
    return { description: "2nd half", code: 1 };
  if (p.includes("intervalo") || p === "ht" || p.includes("half time"))
    return { description: "HT", code: 1 };
  if (p.includes("extra") || p.includes("prorrogação"))
    return { description: "Extra Time", code: 1 };
  if (p.includes("penalt") || p.includes("pênalt"))
    return { description: "Penalties", code: 1 };
  if (minute > 0)
    return { description: minute <= 45 ? "1st half" : "2nd half", code: 1 };
  return { description: period };
}

function statpalOddsMatchToV2Event(
  m: Record<string, unknown>,
): SAPIV2Event | null {
  // Support both Portuguese ("informação_da_partida") and English ("match_info") keys
  const info = (m["informação_da_partida"] ?? m["match_info"]) as
    | Record<string, unknown>
    | undefined;
  const teamsRaw = (m["informações_da_equipe"] ?? m["team_info"]) as
    | Record<string, unknown>
    | undefined;
  const statusRaw = m["status"] as Record<string, unknown> | undefined;

  if (!info || !teamsRaw) return null;

  const id = Number(info["main_id"]);
  if (!Number.isFinite(id) || id === 0) return null;

  // Portuguese: lar/ausente; English: home/away
  const homeRaw = (teamsRaw["lar"] ?? teamsRaw["home"]) as
    | Record<string, unknown>
    | undefined;
  const awayRaw = (teamsRaw["ausente"] ?? teamsRaw["away"]) as
    | Record<string, unknown>
    | undefined;

  const homeName = String(homeRaw?.["nome"] ?? homeRaw?.["name"] ?? "").trim();
  const awayName = String(awayRaw?.["nome"] ?? awayRaw?.["name"] ?? "").trim();
  if (!homeName || !awayName) return null;

  // Score from per-team pontuação/score or placar/score string "1:1"
  const scoreParts = String(info["placar"] ?? info["score"] ?? "0:0").split(":");
  const homeScore =
    parseInt(String(homeRaw?.["pontuação"] ?? homeRaw?.["score"] ?? scoreParts[0] ?? "0"), 10) || 0;
  const awayScore =
    parseInt(String(awayRaw?.["pontuação"] ?? awayRaw?.["score"] ?? scoreParts[1] ?? "0"), 10) || 0;

  const period = String(info["período"] ?? info["period"] ?? "").trim();
  const minute = parseInt(String(info["minuto"] ?? info["minute"] ?? "0"), 10) || 0;
  const { description, code } = mapStatpalPtPeriodToStatus(period, minute);

  // Skip finished matches
  if (
    statusRaw?.["concluído"] === "1" ||
    statusRaw?.["finished"] === "1"
  )
    return null;

  const leagueName = String(info["liga"] ?? info["league"] ?? "").trim();
  const leagueId = Number(info["league_id"]);
  const rawTs = Number(info["start_ts"]);
  // Statpal returns start_ts in seconds; values > 1e11 suggest milliseconds — normalise.
  // Without a valid timestamp, leave it undefined so time-guards don't misfire.
  let startTimestamp: number | undefined;
  if (Number.isFinite(rawTs) && rawTs > 1_000_000_000) {
    startTimestamp = rawTs > 1e11 ? Math.round(rawTs / 1000) : rawTs;
  }

  return {
    id,
    tournament: {
      id: Number.isFinite(leagueId) && leagueId > 0 ? leagueId : undefined,
      name: leagueName,
      category: { name: "", country: { name: "" } },
    },
    homeTeam: {
      id: Number.isFinite(Number(homeRaw?.["id"])) ? Number(homeRaw?.["id"]) : undefined,
      name: homeName,
    },
    awayTeam: {
      id: Number.isFinite(Number(awayRaw?.["id"])) ? Number(awayRaw?.["id"]) : undefined,
      name: awayName,
    },
    homeScore,
    awayScore,
    status: { code, description },
    statusCode: code,
    startTimestamp,
    roundInfo: minute > 0 ? { round: minute } : undefined,
    finalResultOnly: false,
    feedLocked: false,
  };
}

async function fetchStatpalFootballLiveV2(): Promise<{
  events: SAPIV2Event[];
  updatedTs: number;
}> {
  if (!CONFIG.STATPAL_API_KEY) throw new Error("STATPAL_API_KEY is not configured");

  // Always fire odds/live in parallel so oddsLiveKnownIds is kept current regardless
  // of which primary path succeeds. Bookmakers only price live odds on matches actually
  // in progress — these IDs are guaranteed genuine and bypass the "never-seen + >20 min"
  // gate in buildFootballLiveV2, which is critical after a fresh server deploy when
  // liveMatchState is empty and cold-start grace (5 min) has expired.
  const oddsLivePromise = (async () => {
    try {
      const oddsResp = await fetch(buildStatpalUrl("/v2/soccer/odds/live"), {
        signal: AbortSignal.timeout(8_000),
        headers: statpalHeaders(),
      });
      if (!oddsResp.ok) return;
      const oddsRaw = (await oddsResp.json()) as Record<string, unknown>;
      const updatedTs =
        typeof oddsRaw["updated_ts"] === "number" ? oddsRaw["updated_ts"] : 0;
      const matchList = statpalList(
        (oddsRaw["partidas_ao_vivo"] ?? oddsRaw["live_matches"]) as unknown[] | null | undefined,
      );
      const oddsEvents = matchList.flatMap((m) => {
        const ev = statpalOddsMatchToV2Event(m as Record<string, unknown>);
        return ev ? [ev] : [];
      });
      for (const ev of oddsEvents) oddsLiveKnownIds.add(ev.id);
      logger.info(
        { eventCount: oddsEvents.length, source: "odds/live", knownLiveIds: oddsLiveKnownIds.size },
        "[statpal-football-live] odds/live confirmed-live ids updated",
      );
      return { events: oddsEvents, updatedTs };
    } catch (err) {
      logger.warn({ err }, "[statpal-football-live] odds/live parallel fetch failed (non-fatal)");
    }
  })();

  // 1. Try the standard matches/live endpoint (some Statpal subscriptions include it)
  try {
    const resp = await fetch(buildStatpalUrl("/v2/soccer/matches/live"), {
      signal: AbortSignal.timeout(5_000),
      headers: statpalHeaders(),
    });
    if (resp.ok) {
      const raw = (await resp.json()) as Record<string, unknown>;
      const topKeys = Object.keys(raw);
      const { leagues, updatedTs } = extractStatpalLeagueFeed(raw, "live_matches");
      const events = leagues.flatMap((league) =>
        statpalList(league.match).map((match) => statpalMatchToV2Event(league, match)),
      );
      // Diagnostic: log the raw home/away object from the first match of the first
      // league so we can see which field names the API actually uses for the score.
      const firstLeague = leagues[0];
      const firstMatch = firstLeague ? statpalList(firstLeague.match)[0] : undefined;
      const firstMatchRaw = firstLeague
        ? statpalList((firstLeague as unknown as Record<string, unknown>)["match"] as unknown)[0]
        : undefined;
      logger.info(
        {
          topKeys,
          leagueCount: leagues.length,
          eventCount: events.length,
          source: "matches/live",
          // Show what the first match's home/away objects look like so we can
          // identify the correct field name for the score.
          firstMatchHome: firstMatchRaw
            ? (firstMatchRaw as Record<string, unknown>)["home"]
            : undefined,
          firstMatchAway: firstMatchRaw
            ? (firstMatchRaw as Record<string, unknown>)["away"]
            : undefined,
          firstMatchNormalized: firstMatch
            ? { home: firstMatch.home, away: firstMatch.away, status: firstMatch.status }
            : undefined,
        },
        "[statpal-football-live] raw response shape",
      );
      if (events.length > 0) {
        // Wait for the parallel odds/live fetch so oddsLiveKnownIds is populated
        // before buildFootballLiveV2 runs its 20-min gate check.
        await oddsLivePromise;
        return { events, updatedTs };
      }
      // Falls through to odds endpoint when matches/live returns empty
    }
  } catch (err) {
    logger.warn({ err }, "[statpal-football-live] matches/live failed — trying odds/live");
  }

  // 2. Fallback: /v2/soccer/odds/live — confirmed to work with this subscription.
  const oddsResult = await oddsLivePromise;
  if (oddsResult && oddsResult.events.length > 0) {
    return oddsResult;
  }
  // If both failed, throw so the caller can return cached data
  throw new Error("Both matches/live and odds/live returned no events");
}

// Refresh the ground-truth kickoff map from Statpal's *daily* fixture feed
// (via getDailyLeagues, which shares the exact same `main_id`-based id space as
// the Statpal *live* feed used by buildFootballLiveV2 — unlike SportsAPI Pro's
// schedule endpoint, whose ids belong to a completely different provider and
// never line up with Statpal's live event ids). The daily feed is fetched once
// per day and cached (see CONFIG.DAILY_CACHE_TTL), so it is far less likely to
// be corrupted by the transient "fake early live status + fake early kickoff
// time" glitch sometimes seen when continuously polling the live feed.
async function refreshFootballGroundTruthKickoffs(): Promise<void> {
  try {
    const leagues = await getDailyLeagues();
    for (const league of leagues) {
      for (const match of statpalList(league.match)) {
        if (!match?.main_id) continue;
        const ev = statpalMatchToV2Event(league, match);
        if (ev.id && ev.startTimestamp) {
          footballScheduledKickoffSec.set(ev.id, ev.startTimestamp);
        }
      }
    }
  } catch {
    /* keep whatever ground-truth data we already have */
  }
}

async function fetchStatpalFootballDailyLeagues(): Promise<SAPILeagueV2[]> {
  if (!CONFIG.STATPAL_API_KEY) throw new Error("STATPAL_API_KEY is not configured");

  const mergeLeagues = (target: Map<string, SAPILeagueV2>, incoming: SAPILeagueV2[]) => {
    for (const league of incoming) {
      const key = `${league.id}|${league.country}|${league.name}`;
      const existing = target.get(key);
      const incomingMatches = statpalList(league.match);
      if (!existing) {
        target.set(key, { ...league, match: incomingMatches });
        continue;
      }
      const seenIds = new Set(statpalList(existing.match).map((match) => match.main_id));
      const mergedMatches = [...statpalList(existing.match)];
      for (const match of incomingMatches) {
        if (seenIds.has(match.main_id)) continue;
        seenIds.add(match.main_id);
        mergedMatches.push(match);
      }
      target.set(key, { ...existing, match: mergedMatches });
    }
  };

  const merged = new Map<string, SAPILeagueV2>();
  for (const offset of [0, -1]) {
    try {
      const resp = await fetch(
        buildStatpalUrl("/v2/soccer/matches/daily", { offset }),
        {
          signal: AbortSignal.timeout(8_000),
          headers: statpalHeaders(),
        },
      );
      if (!resp.ok) continue;
      const raw = (await resp.json()) as Record<string, unknown>;
      mergeLeagues(merged, extractStatpalLeagueFeed(raw).leagues);
    } catch {}
  }

  return Array.from(merged.values());
}

async function fetchSportsApiFootballDailyLeagues(): Promise<SAPILeagueV2[]> {
  if (!CONFIG.SPORTSAPI_KEY) throw new Error("SPORTSAPI_KEY is not configured");

  const resp = await fetch(
    `${SAPI_V2_FOOTBALL}/v2/soccer/matches/daily?offset=-1`,
    {
      signal: AbortSignal.timeout(8_000),
      headers: sapiHeaders(),
    },
  );
  if (!resp.ok) throw new Error(`SportsApiPro daily HTTP ${resp.status}`);

  const raw = (await resp.json()) as Record<string, unknown>;
  return extractStatpalLeagueFeed(raw).leagues;
}

// v1 odds types
// Root double-wrapper: response is { example: { odds_feed: {...} } } OR { odds_feed: {...} }
// getOddsMap() already handles both via: raw?.example?.odds_feed ?? raw?.odds_feed
type OddsOdd = { name: string; value: string };
type OddsTotal = {
  name: string;
  stop?: string;
  ismain?: string;
  odd: OddsOdd | OddsOdd[];
};
type OddsHandicap = {
  name: string;
  stop?: string;
  ismain?: string;
  odd: OddsOdd | OddsOdd[];
};
type OddsBookmaker = {
  id: string;
  name: string;
  stop?: string;
  ts?: string;
  odd?: OddsOdd | OddsOdd[]; // 1x2, Correct Score, BTTS, Double Chance
  total?: OddsTotal | OddsTotal[]; // Over/Under lines
  handicap?: OddsHandicap | OddsHandicap[]; // Asian Handicap lines (was unknown[])
};
type OddsType = {
  name: string;
  stop?: string;
  bookmaker: OddsBookmaker | OddsBookmaker[];
};
type OddsMatch = {
  id: string;
  alternate_id: string;
  alternate_id_2?: string;
  static_id?: string;
  date?: string;
  time?: string;
  status: string;
  venue?: string;
  home: { id: string; name: string; alternate_id?: string };
  away: { id: string; name: string; alternate_id?: string };
  odds?: { type: OddsType | OddsType[] };
};
type OddsLeague = {
  id: string;
  gid?: string;
  name: string;
  country: string;
  sub_id?: string;
  match: OddsMatch | OddsMatch[];
};

// ─── Priority leagues ─────────────────────────────────────────────────────────
// ORDERING RULE: more-specific patterns MUST come before less-specific ones
// within the same country (e.g. "laliga2" before "laliga", "2. bundesliga"
// before "bundesliga") because matching uses String.includes().

// International tournaments shown regardless of country
const INTL_TOURNAMENTS = [
  "champions league",
  "europa league",
  "conference league",
  "uefa super cup",
  "uefa european championship",
  "european championship",
  "nations league",
  "fifa world cup",
  "copa libertadores",
  "copa sudamericana",
  "concacaf gold cup",
  "gold cup",
  "africa cup of nations",
  "african cup of nations",
  "afc asian cup",
  "asian cup",
  "copa america",
  "world cup",
  "international friendly",
  "international friendlies",
  "amistosos internacionais",
  "club friendly",
  "amistoso de clubes",
  "amistosos de clubes",
  "club friendlies",
];

function isIntlTournamentName(leagueName: string): boolean {
  const base = String(leagueName ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .split(" - ")[0]
    .trim();
  if (!base) return false;
  return INTL_TOURNAMENTS.some((p) => base.includes(p));
}

// DOMESTIC_PRIORITY: [pattern, priority]
