async function getTennisLiveV2(): Promise<SAPIV2Event[]> {
  if (CONFIG.STATPAL_ONLY) return tennisLiveV2Cache ?? [];
  const now = Date.now();
  if (
    (wsConnected.has("tennis") || v1WsConnected.has("tennis")) &&
    tennisLiveV2Cache &&
    now - tennisLiveV2FetchedAt < WS_PREFERRED_MAX_STALE_MS &&
    (wsLastMessageAt.get("tennis") ?? 0) > now - WS_PREFERRED_MAX_STALE_MS
  )
    return tennisLiveV2Cache;
  if (tennisLiveV2Cache && now - tennisLiveV2FetchedAt < CONFIG.LIVE_CACHE_TTL)
    return tennisLiveV2Cache;
  try {
    // Race V1 vs V2 — tennis endpoint shape varies, handle both formats
    const headers = sapiHeaders();
    const tryTennis = async (base: string): Promise<SAPIV2Event[]> => {
      const resp = await fetch(`${base}/live`, {
        signal: AbortSignal.timeout(3000),
        headers,
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const raw = (await resp.json()) as {
        events?: SAPIV2Event[];
        data?: SAPIV2Event[] | { events?: SAPIV2Event[] };
      };
      const nested = raw.data;
      const events =
        raw.events ??
        (Array.isArray(nested)
          ? nested
          : (nested as { events?: SAPIV2Event[] } | undefined)?.events) ??
        [];
      if (events.length === 0) throw new Error("empty");
      return events;
    };
    const events = await Promise.any([
      tryTennis(SAPI_V1_TENNIS),
      tryTennis(SAPI_V2_TENNIS),
    ]).catch(() => []);
    if (events.length > 0) {
      tennisLiveV2Cache = events;
      tennisLiveV2FetchedAt = now;
      return tennisLiveV2Cache;
    }
    if (
      tennisLiveV2Cache &&
      now - tennisLiveV2FetchedAt > V2_LIVE_MAX_STALE_MS
    ) {
      tennisLiveV2Cache = [];
      tennisLiveV2FetchedAt = now;
      return [];
    }
    return tennisLiveV2Cache ?? [];
  } catch {
    return tennisLiveV2Cache ?? [];
  }
}

// ─── SportsAPI Pro V2 WebSocket — real-time live-scores ───────────────────────
//
// One persistent WS connection per sport. Incoming messages update the same
// in-memory caches used by the REST poll helpers, so the GET /live endpoint
// automatically returns fresh data on the next request without waiting for the
// 30-second polling interval.
//
// Message shapes handled (API may send any of these):
//   { events: SAPIV2Event[] }              – full snapshot (most common)
//   { event:  SAPIV2Event  }               – single-event delta
//   { type: string, events?: ..., event?: ... }  – wrapped variant

type SportKey = "football" | "basketball" | "hockey" | "baseball" | "tennis";

const WS_DOMAINS: Record<SportKey, string> = {
  football: "v2.football.sportsapipro.com",
  basketball: "v2.basketball.sportsapipro.com",
  hockey: "v2.hockey.sportsapipro.com",
  baseball: "v2.baseball.sportsapipro.com",
  tennis: "v2.tennis.sportsapipro.com",
};

// Track which sports currently have an open WS connection
const wsConnected = new Set<SportKey>();
// Track reconnect timers so we can avoid duplicate reconnects
const wsTimers = new Map<SportKey, ReturnType<typeof setTimeout>>();
const wsRetryDelay = new Map<SportKey, number>();
const wsLastMessageAt = new Map<SportKey, number>();
const v1PatchedAt = new Map<string, number>();
const V1_PATCH_PREFER_WINDOW_MS = 15_000;
const tennisV1WsScore = new Map<
  string,
  {
    home?: number;
    away?: number;
    status?: string;
    minute?: number;
    patchedAt: number;
  }
>();

function v1PatchKey(sport: SportKey, id: number | string): string {
  return `${sport}:${String(id)}`;
}

function isRecentlyV1Patched(
  sport: SportKey,
  id: number | string,
  now: number,
): boolean {
  const t = v1PatchedAt.get(v1PatchKey(sport, id));
  return t !== undefined && now - t < V1_PATCH_PREFER_WINDOW_MS;
}

function liveMatchIdForSportV2(sport: SportKey, id: number | string): string {
  switch (sport) {
    case "football":
      return `football-v2-${id}`;
    case "basketball":
      return `bball-v2-${id}`;
    case "hockey":
      return `hockey-v2-${id}`;
    case "baseball":
      return `baseball-v2-${id}`;
    case "tennis":
      return `tennis-v2-${id}`;
  }
}

function mergeIncomingPreferFastScore(
  sport: SportKey,
  incoming: SAPIV2Event[],
  existing: SAPIV2Event[] | null,
  now: number,
): SAPIV2Event[] {
  if (!existing || existing.length === 0) return incoming;
  const exById = new Map(existing.map((e) => [String(e.id), e] as const));
  return incoming.map((ev) => {
    const ex = exById.get(String(ev.id));
    if (!ex) return ev;
    const exH = v2CurrentScore(ex.homeScore);
    const exA = v2CurrentScore(ex.awayScore);
    const inH = v2CurrentScore(ev.homeScore);
    const inA = v2CurrentScore(ev.awayScore);
    const prefer = isRecentlyV1Patched(sport, ev.id, now);
    const keepScore = prefer && (inH < exH || inA < exA);
    if (!keepScore) return ev;
    return { ...ev, homeScore: ex.homeScore, awayScore: ex.awayScore };
  });
}

function applyV2WsMessage(sport: SportKey, raw: unknown): void {
  if (!raw || typeof raw !== "object") return;
  const msg = raw as Record<string, unknown>;

  // Extract event array from various possible message shapes
  let incoming: SAPIV2Event[] | null = null;

  if (Array.isArray(msg["events"])) {
    incoming = msg["events"] as SAPIV2Event[];
  } else if (msg["event"] && typeof msg["event"] === "object") {
    // Single-event delta — merge into existing cache
    const ev = msg["event"] as SAPIV2Event;
    incoming = null; // handled below
    mergeSingleV2Event(sport, ev);
    return;
  } else if (Array.isArray(msg["data"])) {
    incoming = msg["data"] as SAPIV2Event[];
  }

  if (!incoming) return;

  const now = Date.now();
  const deltas: Array<{ matchId: string; delta: Partial<LiveMatchState> }> = [];

  const captureDeltas = (events: SAPIV2Event[], sportKey: SportKey) => {
    for (const ev of events) {
      const id = liveMatchIdForSportV2(sportKey, ev.id);
      const existing = liveMatchState.get(id);
      if (!existing) continue;

      const homeScore = v2CurrentScore(ev.homeScore);
      const awayScore = v2CurrentScore(ev.awayScore);
      const status = v2StatusStr(ev.status);
      const minute = (ev.status as any)?.minute ?? 0;

      if (
        homeScore !== existing.homeScore ||
        awayScore !== existing.awayScore ||
        status !== existing.status
      ) {
        deltas.push({
          matchId: id,
          delta: { homeScore, awayScore, status, minute },
        });
      }
    }
  };

  switch (sport) {
    case "football":
      captureDeltas(incoming, "football");
      footballLiveV2Cache = mergeIncomingPreferFastScore(
        sport,
        incoming,
        footballLiveV2Cache,
        now,
      );
      footballLiveV2FetchedAt = now;
      if (footballTodayV2Cache !== null) {
        footballTodayV2Cache = footballLiveV2Cache;
        footballTodayV2FetchedAt = now;
      }
      break;
    case "basketball":
      captureDeltas(incoming, "basketball");
      basketballLiveV2Cache = mergeIncomingPreferFastScore(
        sport,
        incoming,
        basketballLiveV2Cache,
        now,
      );
      basketballLiveV2FetchedAt = now;
      if (basketballTodayV2Cache !== null) {
        basketballTodayV2Cache = basketballLiveV2Cache;
        basketballTodayV2FetchedAt = now;
      }
      break;
    case "hockey":
      captureDeltas(incoming, "hockey");
      hockeyLiveV2Cache = mergeIncomingPreferFastScore(
        sport,
        incoming,
        hockeyLiveV2Cache,
        now,
      );
      hockeyLiveV2FetchedAt = now;
      if (hockeyTodayV2Cache !== null) {
        hockeyTodayV2Cache = hockeyLiveV2Cache;
        hockeyTodayV2FetchedAt = now;
      }
      break;
    case "baseball":
      captureDeltas(incoming, "baseball");
      baseballLiveV2Cache = mergeIncomingPreferFastScore(
        sport,
        incoming,
        baseballLiveV2Cache,
        now,
      );
      baseballLiveV2FetchedAt = now;
      if (baseballTodayV2Cache !== null) {
        baseballTodayV2Cache = baseballLiveV2Cache;
        baseballTodayV2FetchedAt = now;
      }
      break;
    case "tennis":
      captureDeltas(incoming, "tennis");
      tennisLiveV2Cache = mergeIncomingPreferFastScore(
        sport,
        incoming,
        tennisLiveV2Cache,
        now,
      );
      tennisLiveV2FetchedAt = now;
      break;
  }

  if (deltas.length > 0) {
    broadcastBatchDelta(deltas);
  }
}

function mergeSingleV2Event(sport: SportKey, ev: SAPIV2Event): void {
  const now = Date.now();
  let cache: SAPIV2Event[] | null = null;
  switch (sport) {
    case "football":
      cache = footballLiveV2Cache;
      break;
    case "basketball":
      cache = basketballLiveV2Cache;
      break;
    case "hockey":
      cache = hockeyLiveV2Cache;
      break;
    case "baseball":
      cache = baseballLiveV2Cache;
      break;
    case "tennis":
      cache = tennisLiveV2Cache;
      break;
  }
  if (!cache) {
    // No existing snapshot yet — treat as a 1-event array
    applyV2WsMessage(sport, { events: [ev] });
    return;
  }
  const idx = cache.findIndex((e) => e.id === ev.id);
  const updated =
    idx >= 0
      ? [...cache.slice(0, idx), ev, ...cache.slice(idx + 1)]
      : [...cache, ev];
  applyV2WsMessage(sport, { events: updated });

  // Trigger immediate Delta Broadcast for real-time score updates
  const id = liveMatchIdForSportV2(sport, ev.id);
  broadcastMatchDelta(id, {
    homeScore: v2CurrentScore(ev.homeScore),
    awayScore: v2CurrentScore(ev.awayScore),
    status: v2StatusStr(ev.status),
    minute: (ev.status as any)?.minute ?? 0,
  });
}

function connectSportWS(sport: SportKey): void {
  // Don't open duplicate connections
  if (wsConnected.has(sport)) return;

  const key = CONFIG.SPORTSAPI_KEY;
  if (!key || CONFIG.STATPAL_ONLY) return; // no API key or Statpal-only mode

  const url = `wss://${WS_DOMAINS[sport]}/ws?x-api-key=${key}`;

  let ws: WebSocket;
  try {
    ws = new WebSocket(url);
  } catch {
    scheduleReconnect(sport);
    return;
  }

  ws.addEventListener("open", () => {
    wsConnected.add(sport);
    wsRetryDelay.set(sport, 5_000);
    logger.info({ sport, version: "v2" }, "WS connected");
    ws.send(JSON.stringify({ action: "subscribe", channel: "live-scores" }));
  });

  ws.addEventListener("message", (evt) => {
    wsLastMessageAt.set(sport, Date.now());
    try {
      const data: unknown = JSON.parse(
        typeof evt.data === "string" ? evt.data : String(evt.data),
      );
      applyV2WsMessage(sport, data);
      // Removed immediate broadcastLive() — reliance on broadcastMatchDelta for immediate
      // updates and the 1s setInterval for full state snapshots.
    } catch {
      // non-JSON heartbeat / ping — ignore
    }
  });

  ws.addEventListener("close", () => {
    wsConnected.delete(sport);
    wsLastMessageAt.delete(sport);
    scheduleReconnect(sport);
  });

  ws.addEventListener("error", (err) => {
    // error always precedes close; let the close handler reconnect
    wsConnected.delete(sport);
    wsLastMessageAt.delete(sport);
    logger.error({ sport, version: "v2", err }, "WS error");
  });
}

function scheduleReconnect(sport: SportKey): void {
  if (wsTimers.has(sport)) return; // already scheduled
  const prev = wsRetryDelay.get(sport) ?? 5_000;
  const delay = Math.min(prev, 60_000);
  const jitter = Math.floor(Math.random() * 2_000);
  const next = delay + jitter;
  wsRetryDelay.set(sport, Math.min(delay * 2, 60_000));
  const t = setTimeout(() => {
    wsTimers.delete(sport);
    connectSportWS(sport);
  }, next);
  wsTimers.set(sport, t);
}

/** Call once at server startup to open WS connections for all sports. */
export function initSportWebSockets(): void {
  for (const sport of Object.keys(WS_DOMAINS) as SportKey[]) {
    connectSportWS(sport);
  }
}

// ─── V1 WebSocket — 1-2s score-only updates ────────────────────────────────
// V1 gives faster score deltas (1-2s vs 2-5s on V2). We use it exclusively
// for patching homeScore/awayScore/status/minute into the V2 in-memory cache.
// All other data (odds, stats, etc.) stays with V2.

const V1_WS_DOMAINS: Record<SportKey, string> = {
  football: "v1.football.sportsapipro.com",
  basketball: "v1.basketball.sportsapipro.com",
  hockey: "v1.hockey.sportsapipro.com",
  baseball: "v1.baseball.sportsapipro.com",
  tennis: "v1.tennis.sportsapipro.com",
};

const v1WsConnected = new Set<SportKey>();
const v1WsTimers = new Map<SportKey, ReturnType<typeof setTimeout>>();
const v1WsRetryDelay = new Map<SportKey, number>(); // ms, doubles on each failure (cap 60s)

type V1ScoreEvent = {
  id?: number | string; // V1 may send string IDs for some sports
  homeScore?: number | { current?: number };
  awayScore?: number | { current?: number };
  status?: string | { description?: string };
  minute?: number;
};

function v1ScoreNum(
  s: number | { current?: number } | undefined,
): number | undefined {
  if (s === undefined || s === null) return undefined;
  return typeof s === "number" ? s : s.current;
}

function v1StatusStr(
  s: string | { description?: string } | undefined,
): string | undefined {
  if (!s) return undefined;
  return typeof s === "string" ? s : s.description;
}

/** Patch a single V1 score delta into the existing V2 cache for the sport. */
function applyV1ScorePatch(sport: SportKey, ev: V1ScoreEvent): void {
  if (!ev.id) return;

  const now = Date.now();
  v1PatchedAt.set(v1PatchKey(sport, ev.id), now);

  if (sport === "tennis") {
    const hs = v1ScoreNum(ev.homeScore);
    const as = v1ScoreNum(ev.awayScore);
    const st = v1StatusStr(ev.status);
    const mn = ev.minute;
    tennisV1WsScore.set(String(ev.id), {
      home: hs,
      away: as,
      status: st,
      minute: mn,
      patchedAt: now,
    });

    const delta: Partial<LiveMatchState> = {};
    if (hs !== undefined) delta.homeScore = hs;
    if (as !== undefined) delta.awayScore = as;
    if (st !== undefined) delta.status = st;
    if (mn !== undefined) delta.minute = mn;
    if (Object.keys(delta).length > 0) {
      broadcastMatchDelta(liveMatchIdForSportV2("tennis", ev.id), delta);
    }
  }

  let cache: SAPIV2Event[] | null = null;
  switch (sport) {
    case "football":
      cache = footballLiveV2Cache;
      break;
    case "basketball":
      cache = basketballLiveV2Cache;
      break;
    case "hockey":
      cache = hockeyLiveV2Cache;
      break;
    case "baseball":
      cache = baseballLiveV2Cache;
      break;
    case "tennis":
      cache = tennisLiveV2Cache;
      break;
  }
  if (!cache) return; // no V2 snapshot yet — ignore until V2 provides context

  // Use string comparison — V1 may send string IDs while V2 stores numbers
  const idx = cache.findIndex((e) => String(e.id) === String(ev.id));
  if (idx < 0) return; // match not in current V2 cache — skip

  const existing = cache[idx]!;
  const homeScore = v1ScoreNum(ev.homeScore);
  const awayScore = v1ScoreNum(ev.awayScore);
  const status = v1StatusStr(ev.status);

  // Build a shallow-patched copy — only overwrite score-related fields
  const patched: SAPIV2Event = {
    ...existing,
    ...(homeScore !== undefined ? { homeScore } : {}),
    ...(awayScore !== undefined ? { awayScore } : {}),
    ...(status !== undefined ? { status } : {}),
    ...(ev.minute !== undefined ? { roundInfo: { round: ev.minute } } : {}),
  };

  const updated = [...cache.slice(0, idx), patched, ...cache.slice(idx + 1)];
  applyV2WsMessage(sport, { events: updated });

  // Trigger immediate Delta Broadcast for sub-second score-only updates (V1 source)
  broadcastMatchDelta(liveMatchIdForSportV2(sport, ev.id), {
    homeScore:
      homeScore ??
      (typeof existing.homeScore === "number" ? existing.homeScore : 0),
    awayScore:
      awayScore ??
      (typeof existing.awayScore === "number" ? existing.awayScore : 0),
    status: status,
    minute: ev.minute,
  });
}

/** Parse a raw V1 WS message and dispatch score patches. */
function applyV1WsMessage(sport: SportKey, raw: unknown): void {
  if (!raw || typeof raw !== "object") return;
  const msg = raw as Record<string, unknown>;

  if (Array.isArray(msg["events"])) {
    for (const ev of msg["events"] as V1ScoreEvent[])
      applyV1ScorePatch(sport, ev);
  } else if (msg["event"] && typeof msg["event"] === "object") {
    applyV1ScorePatch(sport, msg["event"] as V1ScoreEvent);
  } else if (Array.isArray(msg["data"])) {
    for (const ev of msg["data"] as V1ScoreEvent[])
      applyV1ScorePatch(sport, ev);
  } else if ((msg as V1ScoreEvent).id !== undefined) {
    // Bare event object
    applyV1ScorePatch(sport, msg as V1ScoreEvent);
  }
}

function connectV1SportWS(sport: SportKey): void {
  if (v1WsConnected.has(sport)) return;

  const key = CONFIG.SPORTSAPI_KEY;
  if (!key || CONFIG.STATPAL_ONLY) return; // no API key or Statpal-only mode

  const url = `wss://${V1_WS_DOMAINS[sport]}/ws?x-api-key=${key}`;
  let ws: WebSocket;
  try {
    ws = new WebSocket(url);
  } catch {
    scheduleV1Reconnect(sport);
    return;
  }

  ws.addEventListener("open", () => {
    v1WsConnected.add(sport);
    v1WsRetryDelay.set(sport, 5_000); // reset backoff on success
    logger.info({ sport, version: "v1" }, "V1 WS connected");
    try {
      ws.send(JSON.stringify({ action: "subscribe", channel: "live-scores" }));
    } catch {
      /* ignore */
    }
  });

  ws.addEventListener("message", (evt) => {
    wsLastMessageAt.set(sport, Date.now());
    try {
      const data: unknown = JSON.parse(
        typeof evt.data === "string" ? evt.data : String(evt.data),
      );
      applyV1WsMessage(sport, data);
    } catch {
      // non-JSON heartbeat — ignore
    }
  });

  ws.addEventListener("close", () => {
    v1WsConnected.delete(sport);
    wsLastMessageAt.delete(sport);
    const delay = v1WsRetryDelay.get(sport) ?? 5_000;
    logger.warn(
      { sport, version: "v1", retryMs: delay },
      "V1 WS closed — scheduling reconnect",
    );
    scheduleV1Reconnect(sport, delay);
  });

  ws.addEventListener("error", () => {
    // error always precedes close — close handler does the reconnect
    v1WsConnected.delete(sport);
    wsLastMessageAt.delete(sport);
  });
}

function scheduleV1Reconnect(sport: SportKey, delayMs = 5_000): void {
  if (v1WsTimers.has(sport)) return;
  // Exponential backoff: double each failure, cap at 15s (was 60s — shorter gap means
  // faster recovery when V1 WS drops, reducing fallback to V2-only latency)
  const nextDelay = Math.min(delayMs * 2, 15_000);
  v1WsRetryDelay.set(sport, nextDelay);
  const t = setTimeout(() => {
    v1WsTimers.delete(sport);
    connectV1SportWS(sport);
  }, delayMs);
  v1WsTimers.set(sport, t);
}

/** Call once at startup to open V1 WebSocket connections for fastest score updates. */
export function initV1SportWebSockets(): void {
  for (const sport of Object.keys(V1_WS_DOMAINS) as SportKey[]) {
    connectV1SportWS(sport);
  }
}

export async function primeSportLiveCaches(): Promise<void> {
  if (!CONFIG.SPORTSAPI_KEY || CONFIG.STATPAL_ONLY) return;
  await Promise.all([
    getFootballLiveV2().catch(() => []),
    getBasketballLiveV2().catch(() => []),
    getHockeyLiveV2().catch(() => []),
    getBaseballLiveV2().catch(() => []),
    getTennisTodayV2().catch(() => []),
  ]);
}

// ─── V2 /api/schedule/:date — multi-day upcoming events ──────────────────────

// Per-(sport,date) cache — schedule data for future days changes rarely (30min TTL)
type ScheduleV2Entry = { events: SAPIV2Event[]; fetchedAt: number };
const scheduleV2Cache = new Map<string, ScheduleV2Entry>();
const SCHEDULE_V2_TTL = 30 * 60_000;

/** Fetch all events scheduled for `date` (YYYY-MM-DD) from the given sport. */
async function getScheduleV2(
  sport: SportKey,
  date: string,
): Promise<SAPIV2Event[]> {
  const cacheKey = `${sport}:${date}`;
  const cached = scheduleV2Cache.get(cacheKey);
  if (cached && Date.now() - cached.fetchedAt < SCHEDULE_V2_TTL)
    return cached.events;
  const domain = WS_DOMAINS[sport]; // "v2.football.sportsapipro.com" etc.
  const todayStr = new Date().toISOString().slice(0, 10);
  try {
    const resp = await fetch(`https://${domain}/api/schedule/${date}`, {
      signal: AbortSignal.timeout(9000),
      headers: sapiHeaders(),
    });
    if (!resp.ok) {
      // Fallback to /api/today when schedule endpoint fails, but only for today's date
      if (date === todayStr) {
        const todayResp = await fetch(`https://${domain}/api/today`, {
          signal: AbortSignal.timeout(6000),
          headers: sapiHeaders(),
        }).catch(() => null);
        if (todayResp?.ok) {
          const todayData = (await todayResp.json()) as {
            success?: boolean;
            data?: { events?: SAPIV2Event[] };
            events?: SAPIV2Event[];
          };
          const todayEvents =
            todayData.data?.events ?? (todayData as any).events ?? [];
          if (todayEvents.length > 0) {
            scheduleV2Cache.set(cacheKey, {
              events: todayEvents,
              fetchedAt: Date.now(),
            });
            return todayEvents;
          }
        }
      }
      return cached?.events ?? [];
    }
    const data = (await resp.json()) as {
      success?: boolean;
      data?: { events?: SAPIV2Event[] };
    };
    // Only cache non-empty successful responses
    if (data.success === false) return cached?.events ?? [];
    const events = data.data?.events ?? [];
    if (events.length > 0)
      scheduleV2Cache.set(cacheKey, { events, fetchedAt: Date.now() });
    return events.length > 0 ? events : (cached?.events ?? []);
  } catch {
    return cached?.events ?? [];
  }
}

/**
 * Returns upcoming (not-yet-started) events across the next `days` calendar days
 * for the given sport, sorted by startTimestamp ascending.
 * Filters out events with status.type === "finished" and startTimestamp <= now.
 */
async function getUpcomingEventsV2(
  sport: SportKey,
  days = 7,
  graceSec = 5 * 60,
): Promise<SAPIV2Event[]> {
  const dates: string[] = [];
  const nowMs = Date.now();
  for (let i = 0; i < days; i++) {
    const d = new Date(nowMs + i * 86_400_000);
    dates.push(d.toISOString().slice(0, 10));
  }
  const allDays = await Promise.all(
    dates.map((dt) =>
      getScheduleV2(sport, dt).catch(() => [] as SAPIV2Event[]),
    ),
  );
  const nowSec = nowMs / 1000;
  return allDays
    .flat()
    .filter((ev) => {
      if (!ev.startTimestamp || ev.startTimestamp < nowSec - graceSec)
        return false;
      // Exclude already-finished events that the schedule may still list
      const st = ev.status;
      if (!st) return true;
      const statusType = typeof st === "object" ? (st.type ?? "") : "";
      const statusStr = typeof st === "string" ? st.toLowerCase() : "";
      // Exclude live/inprogress events — they belong in the live feed only
      if (
        statusType === "inprogress" ||
        statusStr === "inprogress" ||
        statusStr === "live" ||
        statusStr === "in progress"
      )
        return false;
      if (typeof st === "object" && statusType === "finished") return false;
      return true;
    })
    .sort((a, b) => (a.startTimestamp ?? 0) - (b.startTimestamp ?? 0));
}

type ExtraV2Sport = "boxing" | "cricket" | "handball";

const EXTRA_V2_BASE_URL: Record<ExtraV2Sport, string> = {
  boxing: "https://api.sportsapipro.com/v2/boxing",
  cricket: "https://api.sportsapipro.com/v2/cricket",
  handball: "https://api.sportsapipro.com/v2/handball",
};

const EXTRA_V2_ID_PREFIX: Record<ExtraV2Sport, string> = {
  boxing: "boxing-v2",
  cricket: "cricket-v2",
  handball: "handball-v2",
};

const EXTRA_V2_LABEL: Record<ExtraV2Sport, string> = {
  boxing: "Boxing",
  cricket: "Cricket",
  handball: "Handball",
};

type F1StatpalRace = {
  date?: string;
  time?: string;
  city?: string;
  track?: string;
  status?: string;
  results?: {
    driver?: Array<{
      name?: string;
      pos?: string;
      time?: string;
    }>;
  } | null;
};

type F1StatpalTournament = {
  id?: string;
  name?: string;
  race?: F1StatpalRace | null;
};

function extractV2EventsPayload(raw: unknown): SAPIV2Event[] {
  const data = raw as
    | {
        events?: SAPIV2Event[];
        data?: { events?: SAPIV2Event[] } | SAPIV2Event[];
      }
    | null
    | undefined;
  const nested = data?.data;
  return (
    data?.events ??
    (Array.isArray(nested)
      ? nested
      : ((nested as { events?: SAPIV2Event[] } | undefined)?.events ?? []))
  );
}

function normalizeProviderStatus(status: string | undefined): string {
  return String(status ?? "")
    .trim()
    .toLowerCase();
}

function isFinishedProviderStatus(status: string | undefined): boolean {
  const s = normalizeProviderStatus(status);
  if (!s) return false;
  return (
    s === "finished" ||
    s === "ended" ||
    s === "ft" ||
    s === "full time" ||
    s === "not started" ||
    s === "canceled" ||
    s === "cancelled" ||
    s === "postponed"
  );
}

function isLiveProviderStatus(status: string | undefined): boolean {
  const s = normalizeProviderStatus(status);
  if (!s) return true;
  return !isFinishedProviderStatus(status);
}

const extraV2ScheduleCache = new Map<string, ScheduleV2Entry>();
const EXTRA_V2_LIVE_TTL = 3000;
const extraV2LiveCache = new Map<
  ExtraV2Sport,
  { events: SAPIV2Event[]; fetchedAt: number }
>();

async function getExtraV2Schedule(
  sport: ExtraV2Sport,
  date: string,
): Promise<SAPIV2Event[]> {
  const cacheKey = `${sport}:${date}`;
  const cached = extraV2ScheduleCache.get(cacheKey);
  if (cached && Date.now() - cached.fetchedAt < SCHEDULE_V2_TTL) {
    return cached.events;
  }
  try {
    const resp = await fetch(`${EXTRA_V2_BASE_URL[sport]}/schedule/${date}`, {
      signal: AbortSignal.timeout(9000),
      headers: sapiHeaders(),
    });
    if (!resp.ok) return cached?.events ?? [];
    const events = extractV2EventsPayload(await resp.json());
    if (events.length > 0) {
      extraV2ScheduleCache.set(cacheKey, { events, fetchedAt: Date.now() });
    }
    return events.length > 0 ? events : (cached?.events ?? []);
  } catch {
    return cached?.events ?? [];
  }
}

async function getExtraUpcomingEventsV2(
  sport: ExtraV2Sport,
  days = 7,
  graceSec = 5 * 60,
): Promise<SAPIV2Event[]> {
  const dates: string[] = [];
  const nowMs = Date.now();
  for (let i = 0; i < days; i++) {
    const d = new Date(nowMs + i * 86_400_000);
    dates.push(d.toISOString().slice(0, 10));
  }
  const allDays = await Promise.all(
    dates.map((dt) => getExtraV2Schedule(sport, dt).catch(() => [] as SAPIV2Event[])),
  );
  const nowSec = nowMs / 1000;
  return allDays
    .flat()
    .filter((ev) => {
      if (!ev.startTimestamp || ev.startTimestamp < nowSec - graceSec) return false;
      const status = v2StatusStr(ev.status);
      if (!status) return true;
      const s = normalizeProviderStatus(status);
      if (s === "live" || s === "in progress" || s === "inprogress") return false;
      if (s === "finished" || s === "ended") return false;
      return true;
    })
    .sort((a, b) => (a.startTimestamp ?? 0) - (b.startTimestamp ?? 0));
}

async function getExtraLiveEventsV2(sport: ExtraV2Sport): Promise<SAPIV2Event[]> {
  const cached = extraV2LiveCache.get(sport);
  if (cached && Date.now() - cached.fetchedAt < EXTRA_V2_LIVE_TTL) {
    return cached.events;
  }
  try {
    const resp = await fetch(`${EXTRA_V2_BASE_URL[sport]}/live`, {
      signal: AbortSignal.timeout(5000),
      headers: sapiHeaders(),
    });
    if (!resp.ok) return cached?.events ?? [];
    const events = extractV2EventsPayload(await resp.json());
    extraV2LiveCache.set(sport, { events, fetchedAt: Date.now() });
    return events;
  } catch {
    return cached?.events ?? [];
  }
}

function buildExtraUpcomingV2(sport: ExtraV2Sport, events: SAPIV2Event[]): UpcomingMatch[] {
  const seen = new Set<string>();
  const results: UpcomingMatch[] = [];
  for (const ev of events) {
    const home = v2TeamName(ev.homeTeam);
    const away = v2TeamName(ev.awayTeam);
    if (home === "Unknown" || away === "Unknown") continue;
    const key = `${home}|${away}|${v2TournName(ev.tournament)}`;
    if (seen.has(key)) continue;
    seen.add(key);
    const { date, time } = v2EventDateTime(ev);
    const country = v2TournCountry(ev);
    results.push({
      id: `${EXTRA_V2_ID_PREFIX[sport]}-${ev.id}`,
      home,
      away,
      league: v2TournName(ev.tournament) || EXTRA_V2_LABEL[sport],
      country,
      time,
      date,
      sport,
      hasRealOdds: false,
      odds: makeOddsFromTeams(home, away),
      markets: makeAdvancedMarketsFromTeams(home, away),
      leagueId: ev.tournamentId ? String(ev.tournamentId) : undefined,
      homeTeamId: ev.homeTeamId != null ? String(ev.homeTeamId) : undefined,
      awayTeamId: ev.awayTeamId != null ? String(ev.awayTeamId) : undefined,
    });
  }
  return results;
}

function buildExtraLiveV2(sport: ExtraV2Sport, events: SAPIV2Event[]): LiveMatchState[] {
  const result: LiveMatchState[] = [];
  const now = Date.now();
  const currentIds = new Set<string>();
  for (const ev of events) {
    const status = v2StatusStr(ev.status);
    if (!isLiveProviderStatus(status)) continue;
    if (ev.startTimestamp !== undefined && ev.startTimestamp - now / 1000 > 30) continue;
    const home = v2TeamName(ev.homeTeam);
    const away = v2TeamName(ev.awayTeam);
    if (home === "Unknown" || away === "Unknown") continue;
    const id = `${EXTRA_V2_ID_PREFIX[sport]}-${ev.id}`;
    currentIds.add(id);
    const state: LiveMatchState = {
      id,
      home,
      away,
      league: v2TournName(ev.tournament) || EXTRA_V2_LABEL[sport],
      country: v2TournCountry(ev),
      sport,
      homeScore: v2CurrentScore(ev.homeScore),
      awayScore: v2CurrentScore(ev.awayScore),
      minute: 0,
      status: status || "LIVE",
      hasRealOdds: false,
      odds: makeOddsFromTeams(home, away),
      markets: makeAdvancedMarketsFromTeams(home, away),
      events: [],
      date: v2EventDateTime(ev).date,
      time: v2EventDateTime(ev).time,
      homeTeamId: ev.homeTeamId != null ? String(ev.homeTeamId) : undefined,
      awayTeamId: ev.awayTeamId != null ? String(ev.awayTeamId) : undefined,
      _firstSeenAt: liveMatchState.get(id)?._firstSeenAt ?? now,
    };
    liveMatchState.set(id, state);
    result.push(state);
  }
  for (const [id, state] of liveMatchState.entries()) {
    if (!id.startsWith(`${EXTRA_V2_ID_PREFIX[sport]}-`)) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (!currentIds.has(id) || tooOld) {
      liveMatchState.delete(id);
    }
  }
  return result;
}

const F1_SCHEDULE_TTL_MS = 30 * 60_000;
const F1_LIVE_TTL_MS = 15_000;
let f1UpcomingCache: { matches: UpcomingMatch[]; fetchedAt: number } | null = null;
let f1LiveCache: { matches: LiveMatchState[]; fetchedAt: number } | null = null;

function statpalTournamentList<T>(
  raw: T | T[] | null | undefined,
): T[] {
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [raw];
}

function buildFormula1UpcomingFromTournaments(
  tournaments: F1StatpalTournament[],
): UpcomingMatch[] {
  return tournaments
    .map((tournament) => {
      const race = tournament.race;
      if (!race?.date || !race?.time || !tournament.id || !tournament.name) return null;
      const home = tournament.name;
      const away = race.city || race.track || "Race";
      return {
        id: `formula1-statpal-${tournament.id}`,
        home,
        away,
        league: "Fórmula 1",
        country: race.city || "",
        time: race.time,
        date: race.date,
        sport: "formula1",
        hasRealOdds: false,
        odds: makeOddsFromTeams(home, away),
        markets: makeAdvancedMarketsFromTeams(home, away),
      } satisfies UpcomingMatch;
    })
    .filter((match): match is UpcomingMatch => !!match);
}

function buildFormula1LiveFromTournaments(
  tournaments: F1StatpalTournament[],
): LiveMatchState[] {
  const out: LiveMatchState[] = [];
  const now = Date.now();
  const currentIds = new Set<string>();
  for (const tournament of tournaments) {
    const race = tournament.race;
    if (!race || !tournament.id || !tournament.name) continue;
    const status = String(race.status ?? "").trim();
    const normalized = normalizeProviderStatus(status);
    if (!normalized || normalized === "not started" || normalized === "finished") continue;
    const drivers = race.results?.driver ?? [];
    const leader = drivers[0]?.name?.trim() || tournament.name;
    const chaser = drivers[1]?.name?.trim() || race.track || "Race";
    const id = `formula1-statpal-${tournament.id}`;
    currentIds.add(id);
    const state: LiveMatchState = {
      id,
      home: leader,
      away: chaser,
      league: tournament.name,
      country: race.city || "",
      sport: "formula1",
      homeScore: Number.parseInt(drivers[0]?.pos ?? "1", 10) || 1,
      awayScore: Number.parseInt(drivers[1]?.pos ?? "2", 10) || 2,
      minute: 0,
      status,
      hasRealOdds: false,
      odds: makeOddsFromTeams(leader, chaser),
      markets: makeAdvancedMarketsFromTeams(leader, chaser),
      events: [],
      date: race.date,
      time: race.time,
      _firstSeenAt: liveMatchState.get(id)?._firstSeenAt ?? now,
    };
    liveMatchState.set(id, state);
    out.push(state);
  }
  for (const [id, state] of liveMatchState.entries()) {
    if (!id.startsWith("formula1-statpal-")) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (!currentIds.has(id) || tooOld) {
      liveMatchState.delete(id);
    }
  }
  return out;
}

async function getFormula1Upcoming(): Promise<UpcomingMatch[]> {
  const now = Date.now();
  if (f1UpcomingCache && now - f1UpcomingCache.fetchedAt < F1_SCHEDULE_TTL_MS) {
    return f1UpcomingCache.matches;
  }
  if (!CONFIG.STATPAL_API_KEY) return f1UpcomingCache?.matches ?? [];
  try {
    const resp = await fetch(buildStatpalUrl("/v1/f1/schedule"), {
      signal: AbortSignal.timeout(8000),
      headers: statpalHeaders(),
    });
    if (!resp.ok) return f1UpcomingCache?.matches ?? [];
    const payload = (await resp.json()) as {
      fixtures?: { tournament?: F1StatpalTournament | F1StatpalTournament[] };
    };
    const matches = buildFormula1UpcomingFromTournaments(
      statpalTournamentList(payload.fixtures?.tournament),
    );
    f1UpcomingCache = { matches, fetchedAt: now };
    return matches;
  } catch {
    return f1UpcomingCache?.matches ?? [];
  }
}

async function getFormula1Live(): Promise<LiveMatchState[]> {
  const now = Date.now();
  if (f1LiveCache && now - f1LiveCache.fetchedAt < F1_LIVE_TTL_MS) {
    return f1LiveCache.matches;
  }
  if (!CONFIG.STATPAL_API_KEY) return f1LiveCache?.matches ?? [];
  try {
    const resp = await fetch(buildStatpalUrl("/v1/f1/livescores"), {
      signal: AbortSignal.timeout(5000),
      headers: statpalHeaders(),
    });
    if (!resp.ok) return f1LiveCache?.matches ?? [];
    const payload = (await resp.json()) as {
      livescore?: { tournament?: F1StatpalTournament | F1StatpalTournament[] };
    };
    const matches = buildFormula1LiveFromTournaments(
      statpalTournamentList(payload.livescore?.tournament),
    );
    f1LiveCache = { matches, fetchedAt: now };
    return matches;
  } catch {
    return f1LiveCache?.matches ?? [];
  }
}

/**
 * Like getUpcomingEventsV2 but filtered to the primary competition for this sport:
 * NBA (basketball), NHL (hockey), MLB (baseball), ATP/WTA main draw (tennis).
 * Also deduplicates by event ID (same event may appear in multiple days' schedules).
 */
async function getUpcomingLeagueEventsV2(
  sport: SportKey,
  days = 7,
): Promise<SAPIV2Event[]> {
  const events = await getUpcomingEventsV2(sport, days);
  const seen = new Set<number>();
  const filtered: SAPIV2Event[] = [];
  for (const ev of events) {
    if (seen.has(ev.id)) continue;
    seen.add(ev.id);
    if (
      sport !== "football" &&
      !isMainLeagueEventRaw(sport, ev as unknown as Record<string, unknown>)
    )
      continue;
    filtered.push(ev);
  }
  return filtered;
}

// ─── V2 Pre-Match Odds ─────────────────────────────────────────────────────────

type V2RawMarket = {
  marketName: string;
  marketGroup: string;
  choices: Array<{ name: string; fractionalValue: string }>;
};

type V2PreMatchOdds = {
  home: number;
  draw: number;
  away: number;
  bttsYes?: number;
  bttsNo?: number;
  over25?: number;
  under25?: number;
  firstSetHome?: number;
  firstSetAway?: number;
  score1st?: Array<{ label: string; odds: number }>;
  score2nd?: Array<{ label: string; odds: number }>;
  score3rd?: Array<{ label: string; odds: number }>;
};

function fractionalToDecimal(frac: string): number {
  const parts = frac.split("/");
  if (parts.length !== 2) return 0;
  const num = parseFloat(parts[0]!);
  const den = parseFloat(parts[1]!);
  if (!den || isNaN(num) || isNaN(den)) return 0;
  return Math.round((num / den + 1) * 100) / 100;
}

function normalizeOddsMarketText(value: string): string {
  return String(value ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function parseTennisSetOrdinal(value: string): number | null {
  const normalized = normalizeOddsMarketText(value);
  const numeric = normalized.match(/(?:^|\b)set\s*(\d)(?:\b|[^0-9])/);
  if (numeric) return Number(numeric[1]);
  if (
    normalized.includes("first set") ||
    normalized.includes("1st set") ||
    normalized.includes("set one")
  )
    return 1;
  if (
    normalized.includes("second set") ||
    normalized.includes("2nd set") ||
    normalized.includes("set two")
  )
    return 2;
  if (
    normalized.includes("third set") ||
    normalized.includes("3rd set") ||
    normalized.includes("set three")
  )
    return 3;
  return null;
}

function canonicalTennisSetScoreOrder(
  entries: Array<{ label: string; odds: number }>,
): Array<{ label: string; odds: number }> {
  const order = new Map([
    ["6-0", 0],
    ["6-1", 1],
    ["6-2", 2],
    ["6-3", 3],
    ["6-4", 4],
    ["7-5", 5],
    ["7-6", 6],
    ["0-6", 7],
    ["1-6", 8],
    ["2-6", 9],
    ["3-6", 10],
    ["4-6", 11],
    ["5-7", 12],
    ["6-7", 13],
  ]);
  return [...entries].sort(
    (a, b) => (order.get(a.label) ?? 999) - (order.get(b.label) ?? 999),
  );
}

function parseTennisSetCorrectScoreChoices(
  choices: Array<{ name: string; fractionalValue: string }>,
): Array<{ label: string; odds: number }> {
  const out: Array<{ label: string; odds: number }> = [];
  for (const choice of choices) {
    const score = String(choice?.name ?? "").replace(/\s+/g, "");
    if (!/^\d-\d$/.test(score)) continue;
    const [homeGames, awayGames] = score.split("-").map(Number);
    const maxGames = Math.max(homeGames, awayGames);
    const minGames = Math.min(homeGames, awayGames);
    const valid =
      (maxGames === 6 && minGames <= 4) ||
      (homeGames === 7 && awayGames === 5) ||
      (homeGames === 7 && awayGames === 6) ||
      (awayGames === 7 && homeGames === 5) ||
      (awayGames === 7 && homeGames === 6);
    if (!valid) continue;
    const odds = fractionalToDecimal(choice.fractionalValue);
    if (!(odds > 1.001)) continue;
    out.push({
      label: `${homeGames}-${awayGames}`,
      odds: clampTennisSetCorrectScoreOdd(odds),
    });
  }
  return canonicalTennisSetScoreOrder(out);
}

function parseV2PreMatchOdds(markets: V2RawMarket[]): V2PreMatchOdds | null {
  let home = 0,
    draw = 0,
    away = 0;
  let bttsYes = 0,
    bttsNo = 0,
    over25 = 0,
    under25 = 0;
  let firstSetHome = 0,
    firstSetAway = 0;
  let score1st: Array<{ label: string; odds: number }> = [];
  let score2nd: Array<{ label: string; odds: number }> = [];
  let score3rd: Array<{ label: string; odds: number }> = [];

  for (const mkt of markets) {
    const grp = mkt.marketGroup ?? "";
    const name = mkt.marketName ?? "";
    const choices = mkt.choices ?? [];
    const combinedText = `${grp} ${name}`;
    const normalizedText = normalizeOddsMarketText(combinedText);

    if (grp === "1X2" && name === "Full time") {
      for (const c of choices) {
        const v = fractionalToDecimal(c.fractionalValue);
        if (c.name === "1") home = v;
        else if (c.name === "X") draw = v;
        else if (c.name === "2") away = v;
      }
    }
    if (grp === "Home/Away" && name === "Full time") {
      for (const c of choices) {
        const v = fractionalToDecimal(c.fractionalValue);
        if (c.name === "1") home = v;
        else if (c.name === "2") away = v;
      }
    }
    if (name === "Both teams to score") {
      for (const c of choices) {
        if (c.name === "Yes") bttsYes = fractionalToDecimal(c.fractionalValue);
        else if (c.name === "No")
          bttsNo = fractionalToDecimal(c.fractionalValue);
      }
    }
    if (name.includes("2.5")) {
      for (const c of choices) {
        const v = fractionalToDecimal(c.fractionalValue);
        if (c.name?.startsWith("Over")) over25 = v;
        else if (c.name?.startsWith("Under")) under25 = v;
      }
    }
    if (name === "First set winner") {
      for (const c of choices) {
        const v = fractionalToDecimal(c.fractionalValue);
        if (c.name === "1") firstSetHome = v;
        else if (c.name === "2") firstSetAway = v;
      }
    }

    const looksLikeSetCorrectScore =
      (normalizedText.includes("correct score") ||
        normalizedText.includes("exact score") ||
        normalizedText.includes("set score")) &&
      normalizedText.includes("set");
    if (looksLikeSetCorrectScore) {
      const parsedChoices = parseTennisSetCorrectScoreChoices(choices);
      if (parsedChoices.length > 0) {
        const setNum = parseTennisSetOrdinal(combinedText);
        if (setNum === 1) score1st = parsedChoices;
        else if (setNum === 2) score2nd = parsedChoices;
        else if (setNum === 3) score3rd = parsedChoices;
      }
    }
  }

  const hasAny =
    home > 0 ||
    draw > 0 ||
    away > 0 ||
    bttsYes > 0 ||
    bttsNo > 0 ||
    over25 > 0 ||
    under25 > 0 ||
    firstSetHome > 0 ||
    firstSetAway > 0 ||
    score1st.length > 0 ||
    score2nd.length > 0 ||
    score3rd.length > 0;
  if (!hasAny) return null;
  return {
    home,
    draw,
    away,
    bttsYes,
    bttsNo,
    over25,
    under25,
    firstSetHome,
    firstSetAway,
    ...(score1st.length > 0 ? { score1st } : {}),
    ...(score2nd.length > 0 ? { score2nd } : {}),
    ...(score3rd.length > 0 ? { score3rd } : {}),
  };
}

type PreMatchOddsEntry = { odds: V2PreMatchOdds; fetchedAt: number };
const preMatchOddsV2Cache = new Map<string, PreMatchOddsEntry>();
const PRE_MATCH_ODDS_TTL = 15 * 60_000;

async function getPreMatchOddsV2(
  sport: SportKey,
  matchId: number,
): Promise<V2PreMatchOdds | null> {
  const key = `${sport}:${matchId}`;
  const cached = preMatchOddsV2Cache.get(key);
  if (cached && Date.now() - cached.fetchedAt < PRE_MATCH_ODDS_TTL)
    return cached.odds;
  const domain = WS_DOMAINS[sport];
  try {
    const resp = await fetch(
      `https://${domain}/api/match/${matchId}/odds/pre-match`,
      {
        signal: AbortSignal.timeout(5000),
        headers: sapiHeaders(),
      },
    );
    if (!resp.ok) return null;
    const data = (await resp.json()) as {
      success?: boolean;
      data?: { markets?: V2RawMarket[] };
    };
    if (!data.success || !data.data?.markets?.length) return null;
    const parsed = parseV2PreMatchOdds(data.data.markets);
    if (parsed)
      preMatchOddsV2Cache.set(key, { odds: parsed, fetchedAt: Date.now() });
    return parsed;
  } catch {
    return null;
  }
}

// ─── League Filters ────────────────────────────────────────────────────────────

/** Returns true for youth leagues (U15–U21, U23) or blocked tournaments that should be hidden. */
function isBlockedLeague(name: string): boolean {
  const n = name.toLowerCase();
  if (/\bu(1[5-9]|2[013])\b/.test(n)) return true;
  if (/\bunder[- ]?(1[5-9]|2[013])\b/.test(n)) return true;
  if (
    /\bjuniors?\b|\byouth\b/.test(n) &&
    !/women|feminine|feminino|frauen|femenin/i.test(n)
  )
    return true;
  // Specific blocked preseason / youth tournaments
  if (n.includes("trofeo dossena")) return true;
  if (n.includes("int.p")) return true;
  return false;
}

/** Returns true for women's football leagues (kept but flagged for frontend). */
function isWomensLeague(name: string): boolean {
  return /women|feminine|féminin|feminino|frauen|femenin|damall|nwsl|wsl/i.test(
    name,
  );
}

