/**
 * Scan all V2 sports "today" feeds and register any finished events into
 * finishedMatchResults. Called by the settlement worker every 60 s so that
 * bets on basketball/hockey/baseball/tennis/football are settled correctly
 * even after a server restart (when the live-eviction path is cold).
 *
 * Match-ID prefix map (must match the IDs used when placing bets):
 *   football   → football-v2-{ev.id}
 *   basketball → bball-v2-{ev.id}
 *   hockey     → hockey-v2-{ev.id}
 *   baseball   → baseball-v2-{ev.id}  AND  mlb-v2-{ev.id}
 *   tennis     → tennis-v2-{ev.id}
 */
export async function scanV2AllSportsForFinished(): Promise<void> {
  try {
    const now = Date.now();

    const [footR, bballR, hockR, baseR, tennR] = await Promise.allSettled([
      getFootballTodayV2(),
      getBasketballTodayV2(),
      getHockeyTodayV2(),
      getBaseballTodayV2(),
      getTennisTodayV2(),
    ]);

    type SportBundle = {
      prefix: string[];
      events: SAPIV2Event[];
      isFootball?: boolean;
    };
    const bundles: SportBundle[] = [
      {
        prefix: ["football-v2"],
        events: footR.status === "fulfilled" ? footR.value : [],
        isFootball: true,
      },
      {
        prefix: ["bball-v2"],
        events: bballR.status === "fulfilled" ? bballR.value : [],
      },
      {
        prefix: ["hockey-v2"],
        events: hockR.status === "fulfilled" ? hockR.value : [],
      },
      {
        prefix: ["baseball-v2", "mlb-v2"],
        events: baseR.status === "fulfilled" ? baseR.value : [],
      },
      {
        prefix: ["tennis-v2"],
        events: tennR.status === "fulfilled" ? tennR.value : [],
      },
    ];

    for (const { prefix, events, isFootball } of bundles) {
      const sport: SportKey = isFootball
        ? "football"
        : prefix.includes("bball-v2")
          ? "basketball"
          : prefix.includes("hockey-v2")
            ? "hockey"
            : prefix.includes("tennis-v2")
              ? "tennis"
              : "baseball";
      for (const ev of events) {
        const st = ev.status as Record<string, unknown> | null | undefined;
        const stType =
          typeof st?.["type"] === "string"
            ? (st["type"] as string).toLowerCase()
            : "";
        const code = v2StatusCode(ev);
        const isFinished =
          stType === "finished" ||
          code === 100 ||
          (typeof st?.["short"] === "string" &&
            SAPI_FINISHED_STATUSES.has(st["short"]));
        if (!isFinished) continue;

        const hS =
          typeof ev.homeScore === "object" && ev.homeScore !== null
            ? (ev.homeScore as SAPIV2ScoreObj)
            : null;
        const aS =
          typeof ev.awayScore === "object" && ev.awayScore !== null
            ? (ev.awayScore as SAPIV2ScoreObj)
            : null;
        const home = hS?.current ?? v2CurrentScore(ev.homeScore) ?? 0;
        const away = aS?.current ?? v2CurrentScore(ev.awayScore) ?? 0;

        // For football extract HT from period1 score; other sports leave undefined
        const htHome = isFootball
          ? typeof hS?.["period1"] === "number"
            ? (hS["period1"] as number)
            : undefined
          : undefined;
        const htAway = isFootball
          ? typeof aS?.["period1"] === "number"
            ? (aS["period1"] as number)
            : undefined
          : undefined;

        const record = {
          home,
          away,
          htHome,
          htAway,
          homeTeam: v2TeamName(ev.homeTeam),
          awayTeam: v2TeamName(ev.awayTeam),
          extras: buildFinishedResultExtrasFromV2Event(sport, ev, hS, aS),
          finishedAt: now,
        };

        for (const p of prefix) {
          const id = `${p}-${ev.id}`;
          if (!finishedMatchResults.has(id))
            finishedMatchResults.set(id, record);
          await enqueueMatchSettlement({
            matchId: id,
            jobId: buildMatchSettlementJobId({
              matchId: id,
              home: record.home,
              away: record.away,
              htHome: record.htHome,
              htAway: record.htAway,
            }),
          });
          try {
            if (db) {
              await db
                .insert(matchResultsTable)
                .values({
                  matchId: id,
                  sport,
                  home: record.home,
                  away: record.away,
                  htHome: record.htHome ?? null,
                  htAway: record.htAway ?? null,
                  homeTeam: record.homeTeam,
                  awayTeam: record.awayTeam,
                  cornersTotal: null,
                  cardsTotal: null,
                  firstGoal: null,
                  extras: record.extras ?? null,
                  finishedAt: new Date(record.finishedAt),
                  updatedAt: new Date(),
                })
                .onConflictDoUpdate({
                  target: matchResultsTable.matchId,
                  set: {
                    home: record.home,
                    away: record.away,
                    htHome: record.htHome ?? null,
                    htAway: record.htAway ?? null,
                    homeTeam: record.homeTeam,
                    awayTeam: record.awayTeam,
                    extras: record.extras ?? null,
                    finishedAt: new Date(record.finishedAt),
                    updatedAt: new Date(),
                  },
                });
            }
          } catch {}
        }
      }
    }

    _pruneFinishedResults();
  } catch (err) {
    logger.error({ err }, "scanV2AllSportsForFinished failed");
  }
}

// Shared helper: convert a SAPIV2Event startTimestamp to date/time strings (Europe/Lisbon)
function v2EventDateTime(ev: SAPIV2Event): { date: string; time: string } {
  const ts = ev.startTimestamp;
  if (!ts) return { date: "", time: "" };
  const d = new Date(ts * 1000);
  // Use "en-US" for predictable formatToParts field names (avoids pt-PT locale quirks
  // in some Node environments where hour/minute keys may differ).
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: "Europe/Lisbon",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  }).formatToParts(d);
  const p: Record<string, string> = {};
  for (const part of parts) p[part.type] = part.value;
  // hour12:false may give "24" at midnight in some environments
  const hh = p["hour"] === "24" ? "00" : (p["hour"] ?? "00");
  const mm = p["minute"] ?? "00";
  return {
    date: `${p["day"] ?? "01"}.${p["month"] ?? "01"}.${p["year"] ?? "2025"}`,
    time: `${hh}:${mm}`,
  };
}

// ─── V2 Tournament/Season ID Cache ────────────────────────────────────────────
const v2TournIdCache = new Map<
  string,
  { tid: number; sid: number; fetchedAt: number }
>();
const V2_TOURN_ID_TTL = 30 * 60_000;

/** Resolves the dominant tournament+season IDs for a sport from V2 live or schedule. */
async function getV2TournamentIds(
  sport: SportKey,
): Promise<{ tid: number; sid: number } | null> {
  const cached = v2TournIdCache.get(sport);
  if (cached && Date.now() - cached.fetchedAt < V2_TOURN_ID_TTL) return cached;
  const domain = WS_DOMAINS[sport];

  const extractIds = (
    events: unknown[],
  ): { tid: number; sid: number } | null => {
    const countMap = new Map<string, { tid: number; sid: number; n: number }>();
    for (const ev of events) {
      const e = ev as Record<string, unknown>;
      // Only count events that belong to the primary league for this sport
      if (!isMainLeagueEventRaw(sport, e)) continue;
      const tourn = e["tournament"] as Record<string, unknown> | undefined;
      const uniq = tourn?.["uniqueTournament"] as
        | Record<string, unknown>
        | undefined;
      const tid = Number(
        e["tournamentId"] ?? uniq?.["id"] ?? tourn?.["id"] ?? 0,
      );
      const season = e["season"] as Record<string, unknown> | undefined;
      const sid = Number(e["seasonId"] ?? season?.["id"] ?? 0);
      if (!tid || !sid) continue;
      const key = `${tid}:${sid}`;
      const ex = countMap.get(key);
      if (ex) ex.n++;
      else countMap.set(key, { tid, sid, n: 1 });
    }
    let best: { tid: number; sid: number } | null = null;
    let bestN = 0;
    for (const entry of countMap.values()) {
      if (entry.n > bestN) {
        bestN = entry.n;
        best = { tid: entry.tid, sid: entry.sid };
      }
    }
    return best;
  };

  // Try V2 live first (flat event structure)
  try {
    const r = await fetch(`https://${domain}/api/live`, {
      signal: AbortSignal.timeout(7000),
      headers: sapiHeaders(),
    });
    if (r.ok) {
      const d = (await r.json()) as Record<string, unknown>;
      const evts = (d["events"] ??
        (d["data"] as Record<string, unknown>)?.["events"] ??
        []) as unknown[];
      const ids = extractIds(evts);
      if (ids) {
        v2TournIdCache.set(sport, { ...ids, fetchedAt: Date.now() });
        return ids;
      }
    }
  } catch {}

  // Fall back to today's schedule (nested data.events structure)
  const todayStr = new Date().toISOString().slice(0, 10);
  const scheduleEvts = await getScheduleV2(sport, todayStr).catch(
    () => [] as SAPIV2Event[],
  );
  const ids2 = extractIds(scheduleEvts as unknown[]);
  if (ids2) {
    v2TournIdCache.set(sport, { ...ids2, fetchedAt: Date.now() });
    return ids2;
  }
  return cached ?? null;
}

// ─── V2 Events/Last Cache ──────────────────────────────────────────────────────
const v2EventsLastMap = new Map<
  string,
  { events: unknown[]; fetchedAt: number }
>();
const V2_EVENTS_LAST_TTL = 5 * 60_000;

async function getV2EventsLast(sport: SportKey, n = 30): Promise<unknown[]> {
  const ids = await getV2TournamentIds(sport);
  if (!ids) return [];
  const cacheKey = `${sport}:${ids.tid}:${ids.sid}:${n}`;
  const cached = v2EventsLastMap.get(cacheKey);
  if (cached && Date.now() - cached.fetchedAt < V2_EVENTS_LAST_TTL)
    return cached.events;
  const domain = WS_DOMAINS[sport];
  try {
    const resp = await fetch(
      `https://${domain}/api/tournament/${ids.tid}/season/${ids.sid}/events/last/${n}`,
      { signal: AbortSignal.timeout(9000), headers: sapiHeaders() },
    );
    if (!resp.ok) return cached?.events ?? [];
    const d = (await resp.json()) as Record<string, unknown>;
    const events = ((d["data"] as Record<string, unknown>)?.["events"] ??
      []) as unknown[];
    v2EventsLastMap.set(cacheKey, { events, fetchedAt: Date.now() });
    return events;
  } catch {
    return cached?.events ?? [];
  }
}

// ─── V2 Standings Rows ─────────────────────────────────────────────────────────
type V2StandingRow = {
  position: number;
  team: { id: number; name: string; nameCode: string };
  matches: number;
  wins: number;
  losses: number;
  draws?: number;
  points?: number;
  percentage?: number;
  gamesBehind?: number;
  streak?: number;
  normaltimeLosses?: number;
  overtimeLosses?: number;
  scoresFor?: number;
  scoresAgainst?: number;
  scoreDiffFormatted?: string;
};

const v2StandingsRowCache = new Map<
  string,
  { rows: V2StandingRow[]; fetchedAt: number }
>();
const V2_STANDINGS_ROWS_TTL = 30 * 60_000;

async function getV2StandingRows(sport: SportKey): Promise<V2StandingRow[]> {
  const ids = await getV2TournamentIds(sport);
  if (!ids) return [];
  const cacheKey = `${sport}:${ids.tid}:${ids.sid}`;
  const cached = v2StandingsRowCache.get(cacheKey);
  if (cached && Date.now() - cached.fetchedAt < V2_STANDINGS_ROWS_TTL)
    return cached.rows;
  const domain = WS_DOMAINS[sport];
  try {
    const resp = await fetch(
      `https://${domain}/api/tournament/${ids.tid}/season/${ids.sid}/standings`,
      { signal: AbortSignal.timeout(9000), headers: sapiHeaders() },
    );
    if (!resp.ok) return cached?.rows ?? [];
    const d = (await resp.json()) as Record<string, unknown>;
    const standings = ((d["data"] as Record<string, unknown>)?.["standings"] ??
      []) as Array<{ type: string; rows?: V2StandingRow[] }>;
    const total = standings.find((s) => s.type === "total") ?? standings[0];
    const rows = (total?.rows ?? []) as V2StandingRow[];
    v2StandingsRowCache.set(cacheKey, { rows, fetchedAt: Date.now() });
    return rows;
  } catch {
    return cached?.rows ?? [];
  }
}

const TENNIS_LIVE_STATUSES = new Set([
  "Set 1",
  "Set 2",
  "Set 3",
  "Set 4",
  "Set 5",
]);

function buildTennisLiveMatches(
  tournaments: TennisTournament[],
  statsMap: Map<string, [TennisStatData, TennisStatData]>,
): LiveMatchState[] {
  const result: LiveMatchState[] = [];
  const parsePt = (gs: string): number | string => {
    if (!gs || gs === "0") return 0;
    if (gs === "15" || gs === "30" || gs === "40") return parseInt(gs);
    if (gs === "AD") return "AD";
    return 0;
  };

  // Sort by tournament priority: Grand Slams → Masters → ATP 500 → ATP 250 → Challenger → ITF
  const sorted = [...tournaments].sort(
    (a, b) => tennisLeaguePriority(a.name) - tennisLeaguePriority(b.name),
  );

  for (const t of sorted) {
    const matches = Array.isArray(t.match) ? t.match : t.match ? [t.match] : [];
    for (const m of matches) {
      if (!m) continue;

      const now = Date.now();
      const id = `tennis-live-${m.id}`;
      const existing = liveMatchState.get(id);

      // Skip any match not explicitly live according to Statpal.
      // Tennis courts run late (previous match still in progress) — never
      // infer "in progress" from time alone; only trust real API statuses.
      if (!TENNIS_LIVE_STATUSES.has(m.status)) continue;
      const players = Array.isArray(m.player) ? m.player : [m.player];
      if (players.length < 2) continue;
      const p0 = players[0]!;
      const p1 = players[1]!;
      // Skip doubles (player name contains "/")
      if (p0.name.includes("/") || p0.dp1) continue;

      // Build sets array (all sets incl in-progress)
      const sets: Array<[number, number]> = [];
      for (const sf of ["s1", "s2", "s3", "s4", "s5"] as const) {
        const h = p0[sf];
        const a = p1[sf];
        if (h !== "" && a !== "")
          sets.push([parseFloat(h) || 0, parseFloat(a) || 0]);
      }

      const homeScore = parseInt(p0.totalscore) || 0;
      const awayScore = parseInt(p1.totalscore) || 0;
      const setNum = parseInt(m.status.split(" ")[1]!) || 1;

      // Current game points
      const hGs = parsePt(p0.game_score);
      const aGs = parsePt(p1.game_score);
      let hPt: number | string, aPt: number | string;
      if (hGs === 40 && aGs === 40) {
        hPt = "D";
        aPt = "D";
      } else if (hGs === "AD") {
        hPt = "AD";
        aPt = 40;
      } else if (aGs === "AD") {
        hPt = 40;
        aPt = "AD";
      } else {
        hPt = hGs;
        aPt = aGs;
      }

      // Serving advantage: server has a slight edge in live tennis pricing.
      const isServeTrue = (v: unknown): boolean => {
        const s = String(v ?? "")
          .trim()
          .toLowerCase();
        return s === "true" || s === "1" || s === "yes";
      };
      const getServeVal = (p: any): unknown =>
        p?.serve ??
        p?.serving ??
        p?.server ??
        p?.isServing ??
        p?.service ??
        p?.srv;
      const serveFromMatch = (() => {
        const raw =
          (m as any)?.serve ?? (m as any)?.server ?? (m as any)?.serving;
        const s = String(raw ?? "")
          .trim()
          .toLowerCase();
        if (s === "1" || s === "home") return [true, false] as const;
        if (s === "2" || s === "away") return [false, true] as const;
        return null;
      })();
      const p0Serving = serveFromMatch
        ? serveFromMatch[0]
        : isServeTrue(getServeVal(p0));
      const p1Serving = serveFromMatch
        ? serveFromMatch[1]
        : isServeTrue(getServeVal(p1));

      // Use real pre-match odds from cache (populated by getTennisOdds) as base.
      // Fall back to a balanced model only if we have no cached data yet.
      const baseOdds = makeTennisBaseOdds(p0.name, p1.name);
      const currentPoints: [number | string, number | string] = [hPt, aPt];
      const serving: [boolean, boolean] = [p0Serving, p1Serving];
      const liveOddsState = computeTennisLiveOdds(
        baseOdds,
        sets,
        homeScore,
        awayScore,
        currentPoints,
        serving,
      );
      const liveOdds = liveOddsState.odds;

      const liveHomeP =
        liveOdds.home > 0 && liveOdds.away > 0
          ? 1 / liveOdds.home / (1 / liveOdds.home + 1 / liveOdds.away)
          : 0.5;

      // Placar Exato do Set — stable score-template model from set-win probability
      const curSetH = sets.length > 0 ? (sets[sets.length - 1]?.[0] ?? 0) : 0;
      const curSetA = sets.length > 0 ? (sets[sets.length - 1]?.[1] ?? 0) : 0;
      const currentSetHomeWinProb = Math.min(
        0.97,
        Math.max(
          0.03,
          0.5 + (liveHomeP - 0.5) * 0.55 + (curSetH - curSetA) * 0.055,
        ),
      );
      const pGameHomeWin = estimateTennisLiveGameWinProb(
        liveHomeP,
        currentPoints,
        serving,
      );
      const completedSetMomentum = getTennisCompletedSetMomentum(
        sets,
        homeScore + awayScore,
      );
      const homeSetScoreMomentum = Math.max(0, completedSetMomentum);
      const awaySetScoreMomentum = Math.max(0, -completedSetMomentum);
      const setExactScore = computeSetExactScoreOdds(
        curSetH,
        curSetA,
        currentSetHomeWinProb,
        0.22,
        pGameHomeWin,
        homeSetScoreMomentum,
        awaySetScoreMomentum,
      );

      // ── Per-set winner markets: numDoneSets = sets fully won by either side ─
      const numDoneSets = homeScore + awayScore;
      const liveTennisExtras = computeLiveTennisExtras(
        liveHomeP,
        sets,
        homeScore,
        awayScore,
        setNum,
        currentPoints,
        serving,
      );

      // Completed set markets are permanently settled. Future set markets stay
      // locked until their respective set actually starts.
      const SETTLED = now + 30 * 24 * 60 * 60 * 1000;
      const settledSusp: Record<string, number> = {};
      const phaseHoldSusp: Record<string, number> = {};
      if (numDoneSets >= 1) settledSusp["firstSet"] = SETTLED;
      if (numDoneSets >= 2) settledSusp["set2"] = SETTLED;
      if (setNum < 2) phaseHoldSusp["set2"] = SETTLED;
      if (setNum < 3) phaseHoldSusp["set3"] = SETTLED;

      const suspPts: [number | string, number | string] = [
        hPt === "D" ? "40" : hPt,
        aPt === "D" ? "40" : aPt,
      ];

      const prevPoints = existing?._liveExtra?.currentPoints;
      const prevSets = existing?._liveExtra?.sets;
      const lastTennisUpdate = existing?._oddsUpdatedAt ?? 0;
      const isDifferentPollCycle = now - lastTennisUpdate > 1500;
      const pointPlayed =
        isDifferentPollCycle &&
        prevPoints !== undefined &&
        (JSON.stringify(prevPoints) !== JSON.stringify(currentPoints) ||
          JSON.stringify(prevSets) !== JSON.stringify(sets));

      let marketSuspension: Record<string, number> | undefined =
        existing?.marketSuspension
          ? Object.fromEntries(
              Object.entries(existing.marketSuspension).filter(([key, ts]) => {
                if (ts <= now) return false;
                if (
                  (key === "set2" || key === "set3") &&
                  ts > now + 60 * 60 * 1000 &&
                  settledSusp[key] === undefined &&
                  phaseHoldSusp[key] === undefined
                ) {
                  return false;
                }
                return true;
              }),
            )
          : undefined;

      if (
        Object.keys(settledSusp).length > 0 ||
        Object.keys(phaseHoldSusp).length > 0
      ) {
        marketSuspension = {
          ...(marketSuspension ?? {}),
          ...settledSusp,
          ...phaseHoldSusp,
        };
      }

      let suspensionReason = existing?._suspensionReason;

      if (pointPlayed) {
        const suspMs = tennisSuspensionMs(suspPts, sets, homeScore, awayScore);
        if (suspMs > 0) {
          const pointSusp = Object.fromEntries(
            TENNIS_SUSP_KEYS.map((k) => [k, now + suspMs]),
          );
          marketSuspension = {
            ...(marketSuspension ?? {}),
            ...pointSusp,
            ...settledSusp,
            ...phaseHoldSusp,
          };
          suspensionReason = "PONTO EM JOGO";
        }
      } else if (
        marketSuspension &&
        Object.keys(marketSuspension).length === 0
      ) {
        marketSuspension = undefined;
        suspensionReason = undefined;
      } else if (!pointPlayed && suspensionReason === "PONTO EM JOGO") {
        const active = marketSuspension
          ? Object.entries(marketSuspension).filter(
              ([k, ts]) => ts > now && settledSusp[k] === undefined,
            )
          : [];
        suspensionReason = active.length > 0 ? suspensionReason : undefined;
      }

      // Only tennis-relevant markets — no football goals/corners/cards
      const tennisOnlyMarkets = {
        doubleChance: { homeOrDraw: 0, awayOrDraw: 0, homeOrAway: 0 },
        bothTeamsScore: { yes: 0, no: 0 },
        totalGoals: {
          over05: 0,
          under05: 0,
          over15: 0,
          under15: 0,
          over25: 0,
          under25: 0,
          over35: 0,
          under35: 0,
          over45: 0,
          under45: 0,
          over55: 0,
          under55: 0,
          over65: 0,
          under65: 0,
        },
        handicap: {
          homeMinusOne: 0,
          awayPlusOne: 0,
          homeMinusOneHalf: 0,
          awayPlusOneHalf: 0,
        },
        halfTime: { home: 0, draw: 0, away: 0 },
        firstGoal: { home: 0, noGoal: 0, away: 0 },
        tennisExtra: { ...liveTennisExtras, setExactScore },
      } as unknown as AdvancedMarkets;

      result.push({
        id,
        home: p0.name,
        away: p1.name,
        league: t.name,
        country: "tennis",
        sport: "tennis",
        homeScore,
        awayScore,
        minute: setNum,
        status: m.status,
        hasRealOdds: liveOddsState.hasRealOdds,
        odds: liveOdds,
        markets: tennisOnlyMarkets,
        events: [],
        marketSuspension:
          marketSuspension && Object.keys(marketSuspension).length > 0
            ? marketSuspension
            : undefined,
        _suspensionReason: suspensionReason,
        _oddsUpdatedAt: now,
        _liveExtra: {
          sets,
          currentPoints,
          serving,
          tennisStats: statsMap.get(m.id),
        },
      });
    }
  }
  return result;
}

function buildVolleyballLiveMatches(
  tournaments: VolleyTournament[],
): LiveMatchState[] {
  const VSET_LIVE = new Set(["Set 1", "Set 2", "Set 3", "Set 4", "Set 5"]);
  const result: LiveMatchState[] = [];

  // Sort by league priority: SuperLega / Superliga / PlusLiga → medium leagues
  const sorted = [...tournaments].sort(
    (a, b) =>
      volleyballLeaguePriority(a.league) - volleyballLeaguePriority(b.league),
  );

  // Today's date in DD.MM.YYYY for filtering non-live matches
  const now = new Date();
  const todayStr = `${String(now.getDate()).padStart(2, "0")}.${String(now.getMonth() + 1).padStart(2, "0")}.${now.getFullYear()}`;

  for (const t of sorted) {
    const matches = Array.isArray(t.match) ? t.match : t.match ? [t.match] : [];
    for (const m of matches) {
      if (!m) continue;
      const home = m.home;
      const away = m.away;
      if (!home?.name || !away?.name) continue;

      // Statpal sometimes sends numeric status codes (e.g. "43") when a set is in progress
      const isNumericStatus = /^\d+$/.test(String(m.status ?? ""));
      const isLive = VSET_LIVE.has(m.status) || isNumericStatus;
      const isNotStarted = m.status === "Not Started";
      const isFinished = m.status === "Finished";

      if (isFinished) continue; // never show finished games in live section
      if (!isLive && !isNotStarted) continue;
      // Non-live: only today's fixtures
      if (isNotStarted && m.date !== todayStr) continue;
      // Only show Not Started games within 90 min — avoids showing afternoon games in the morning
      const minsUntilStart = isNotStarted
        ? matchStartsInMinutes(m.date ?? "", m.time ?? "")
        : 0;
      if (isNotStarted && minsUntilStart > 90) continue;

      // If Statpal still reports "Not Started" but the scheduled time has already passed,
      // treat as in-progress (API lag) so the match shows as live rather than upcoming.
      const apiLagging = isNotStarted && minsUntilStart < 0;

      const homeScore = parseInt(home.totalscore) || 0;
      const awayScore = parseInt(away.totalscore) || 0;

      const vollSets: Array<[number, number]> = [];
      let ptH = 0,
        ptA = 0;
      const sfs = ["s1", "s2", "s3", "s4", "s5"] as const;

      if (isLive) {
        // Build completed sets and current-set points
        const setNum = parseInt(m.status.split(" ")[1]!) || 1;
        for (let i = 0; i < sfs.length; i++) {
          const h = home[sfs[i]!];
          const a = away[sfs[i]!];
          if (!h || !a) break;
          if (i < setNum - 1)
            vollSets.push([parseInt(h) || 0, parseInt(a) || 0]);
          else {
            ptH = parseInt(h) || 0;
            ptA = parseInt(a) || 0;
          }
        }
      } else if (isFinished) {
        // All sets completed — include every scored set
        for (const sf of sfs) {
          const h = home[sf];
          const a = away[sf];
          if (!h || !a) break;
          vollSets.push([parseInt(h) || 0, parseInt(a) || 0]);
        }
      }

      // For numeric status (e.g. "43"), infer set number from total sets won
      const setNumFromScore =
        parseInt(home.totalscore || "0") + parseInt(away.totalscore || "0") + 1;
      const setNum = isLive
        ? isNumericStatus
          ? setNumFromScore
          : parseInt(m.status.split(" ")[1]!) || 1
        : apiLagging
          ? 1
          : 0;
      const statusLabel = isNotStarted
        ? apiLagging
          ? "Em Jogo"
          : `Hoje ${m.time}`
        : isFinished
          ? "Encerrado"
          : isNumericStatus
            ? `Set ${setNumFromScore}`
            : m.status;
      const baseOdds = makeOddsFromTeams(home.name, away.name);

      result.push({
        id: `volley-live-${m.id}`,
        home: home.name,
        away: away.name,
        league: t.league,
        country: t.country,
        sport: "volleyball",
        homeScore,
        awayScore,
        minute: setNum,
        status: statusLabel,
        hasRealOdds: !isFinished,
        odds: isFinished
          ? { home: 0, draw: 0, away: 0 }
          : { home: baseOdds.home, draw: 0, away: baseOdds.away },
        markets: makeAdvancedMarketsFromTeams(home.name, away.name),
        events: [],
        _liveExtra: {
          vollSets,
          ...(isLive ? { currentPts: [ptH, ptA] as [number, number] } : {}),
        },
      });
    }
  }
  return result;
}

// ─── ET / Penalty market helpers ────────────────────────────────────────────────

function makeETMarketsFromScore(
  etHome: number,
  etAway: number,
  totalHome: number,
  totalAway: number,
): NonNullable<AdvancedMarkets["etExtra"]> {
  const marg = 0.07;
  const price = (p: number) =>
    mr(mc((1 / Math.max(0.01, p)) * (1 + marg), 1.01, 200));

  // ET period result (1X2 — draw in ET means match goes to penalties)
  const etDiff = etHome - etAway;
  let pH: number, pD: number, pA: number;
  if (etDiff === 0) {
    pH = 0.37;
    pD = 0.28;
    pA = 0.35;
  } else if (etDiff === 1) {
    pH = 0.72;
    pD = 0.18;
    pA = 0.1;
  } else if (etDiff === -1) {
    pH = 0.1;
    pD = 0.18;
    pA = 0.72;
  } else if (etDiff >= 2) {
    pH = 0.92;
    pD = 0.05;
    pA = 0.03;
  } else {
    pH = 0.03;
    pD = 0.05;
    pA = 0.92;
  }

  // Tie winner — who advances from the knockout (penalty shootout is 50/50 if ET ends level)
  const totalDiff = totalHome - totalAway;
  let pTH: number, pTA: number;
  if (totalDiff >= 3) {
    pTH = 0.98;
    pTA = 0.02;
  } else if (totalDiff === 2) {
    pTH = 0.95;
    pTA = 0.05;
  } else if (totalDiff === 1) {
    pTH = pH + pD * 0.5;
    pTA = pA + pD * 0.5;
  } else if (totalDiff === 0) {
    pTH = pH + pD * 0.5;
    pTA = pA + pD * 0.5;
  } else if (totalDiff === -1) {
    pTH = pA + pD * 0.5;
    pTA = pH + pD * 0.5;
  } else if (totalDiff === -2) {
    pTH = 0.05;
    pTA = 0.95;
  } else {
    pTH = 0.02;
    pTA = 0.98;
  }
  // Normalise
  const tSum = pTH + pTA;
  pTH /= tSum;
  pTA /= tSum;

  // Next goal scorer — trailing team is more desperate, slight advantage
  let pNG_H: number, pNG_A: number;
  if (totalDiff > 0) {
    pNG_H = 0.45;
    pNG_A = 0.55;
  } // away trailing → more desperate
  else if (totalDiff < 0) {
    pNG_H = 0.55;
    pNG_A = 0.45;
  } // home trailing → more desperate
  else {
    pNG_H = 0.5;
    pNG_A = 0.5;
  }

  // Total goals (Poisson model for remaining ET time)
  const totalGoalsET = etHome + etAway;
  const λ = Math.max(0.05, 0.65 - totalGoalsET * 0.22);
  const p0 = Math.exp(-λ);
  const p1 = λ * p0;
  const p2 = ((λ * λ) / 2) * p0;
  const pO05 = Math.max(0.02, 1 - p0);
  const pO15 = Math.max(0.01, 1 - p0 - p1);
  const pO25 = Math.max(0.005, 1 - p0 - p1 - p2);

  return {
    tieWinner: { home: price(pTH), away: price(pTA) },
    etResult: { home: price(pH), draw: price(pD), away: price(pA) },
    totalGoals: {
      o05: price(pO05),
      u05: price(1 - pO05),
      o15: price(pO15),
      u15: price(1 - pO15),
      o25: price(pO25),
      u25: price(1 - pO25),
    },
    nextGoal: { home: price(pNG_H), away: price(pNG_A) },
  };
}

function makePenMarketsFromScore(
  penHome: number,
  penAway: number,
): NonNullable<AdvancedMarkets["penExtra"]> {
  const marg = 0.07;
  const price = (p: number) =>
    mr(mc((1 / Math.max(0.01, p)) * (1 + marg), 1.01, 50));

  const diff = penHome - penAway;
  let pHome: number, pAway: number;
  if (diff === 0) {
    pHome = 0.5;
    pAway = 0.5;
  } else if (diff === 1) {
    pHome = 0.68;
    pAway = 0.32;
  } else if (diff === -1) {
    pHome = 0.32;
    pAway = 0.68;
  } else if (diff >= 2) {
    pHome = 0.88;
    pAway = 0.12;
  } else {
    pHome = 0.12;
    pAway = 0.88;
  }

  return { winner: { home: price(pHome), away: price(pAway) } };
}

// ─── Match builders ────────────────────────────────────────────────────────────

// Max time a football match may stay in live: 210 min (90 + 30 ET + 15 pen shoot + buffer)
const MATCH_MAX_LIVE_MS = 210 * 60 * 1000;
// Max time a match may sit in "HT" status: 22 min (real HT is ≤15 min)
const HT_MAX_DURATION_MS = 22 * 60 * 1000;
// Additional FINISHED statuses Statpal may return when slow to update
const SAPI_FINISHED_STATUSES = new Set([
  "FT",
  "AET",
  "AP",
  "Pen",
  "Full Time",
  "After ET",
  "After Pens",
  "Finished",
  "Ended",
  "Abandoned",
  "Postponed",
  "Cancelled",
  "Susp",
  "Delayed",
  "Interrupted",
  "Cancl.",
  "Abd",
  "Postp.",
  "Susp.",
]);

async function buildLiveMatches(): Promise<LiveMatchState[]> {
  const [leagues, odds] = await Promise.all([getLiveLeagues(), getOddsMap()]);

  const sorted = [...leagues]
    .sort(
      (a, b) =>
        leaguePriority(a.name, a.country) - leaguePriority(b.name, b.country),
    )
    .filter((l) => leaguePriority(l.name, l.country) < 100);

  // ── Garbage-collect liveMatchState for IDs no longer in the Statpal response ──
  const currentMatchIds = new Set<string>();
  for (const league of sorted) {
    const ms: SAPIMatchV2[] = Array.isArray(league.match)
      ? league.match
      : [league.match];
    for (const m of ms) currentMatchIds.add(m.main_id);
  }
  for (const id of liveMatchState.keys()) {
    const state = liveMatchState.get(id);
    if (!state) continue;
    if (state.sport !== "football") continue;
    if (id.startsWith("football-v2-")) continue;
    if (currentMatchIds.has(id)) {
      if (state._missingSinceAt) {
        liveMatchState.set(id, { ...state, _missingSinceAt: undefined });
      }
      continue;
    }
    const missingSince = state._missingSinceAt ?? Date.now();
    if (!state._missingSinceAt) {
      liveMatchState.set(id, { ...state, _missingSinceAt: missingSince });
      continue;
    }
    if (Date.now() - missingSince > getFootballLiveDisappearGraceMs(state)) {
      await finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
    }
  }

  const now = Date.now();
  let count = 0;
  const result: LiveMatchState[] = [];

  for (const league of sorted) {
    if (count >= 30) break;
    const matches: SAPIMatchV2[] = Array.isArray(league.match)
      ? league.match
      : [league.match];

    for (const m of matches) {
      if (count >= 30) break;

      const existing = liveMatchState.get(m.main_id);

      // ── Guard 0: explicitly finished statuses Statpal is slow to remove ───────
      if (SAPI_FINISHED_STATUSES.has(m.status)) {
        if (existing) {
          await finalizeStaleLiveMatch({
            ...existing,
            homeScore:
              m.home.goals === "?"
                ? existing.homeScore
                : parseInt(m.home.goals) || existing.homeScore,
            awayScore:
              m.away.goals === "?"
                ? existing.awayScore
                : parseInt(m.away.goals) || existing.awayScore,
            status: m.status,
          });
          liveMatchState.delete(m.main_id);
        }
        continue;
      }

      const isLiveMinute = /^\d{1,3}$/.test(m.status);
      const isHT = m.status === "HT";
      const isET = m.status === "ET";
      if (!isLiveMinute && !isHT && !isET) continue;

      // ── Guard 0b: frozen feed detection ─────────────────────────────────────
      // If Statpal's own updated_ts hasn't moved in >15min, the feed is frozen.
      // In that case, drop any match whose scheduled kickoff + 130 min has passed
      // (it's almost certainly over even if Statpal still shows it as in-progress).
      if (liveFeedUpdatedTs > 0) {
        const feedAgeMs = now - liveFeedUpdatedTs * 1000;
        const FROZEN_THRESHOLD_MS = 15 * 60 * 1000; // 15 minutes
        if (feedAgeMs > FROZEN_THRESHOLD_MS && m.date && m.time) {
          // Parse "DD.MM.YYYY" + "HH:MM" into UTC ms
          const [d, mo, y] = m.date.split(".").map(Number);
          const [h, mi] = m.time.split(":").map(Number);
          if (!isNaN(d) && !isNaN(h)) {
            const kickoffMs = Date.UTC(y, mo - 1, d, h, mi);
            const MAX_MATCH_DURATION_MS = 130 * 60 * 1000; // 130 min (90 + ET + buffer)
            if (now - kickoffMs > MAX_MATCH_DURATION_MS) {
              if (existing) {
                await finalizeStaleLiveMatch({
                  ...existing,
                  status: m.status,
                });
                liveMatchState.delete(m.main_id);
              }
              continue; // match is over
            }
          }
        }
      }

      // ── Guard 1: discard match that has been live longer than MATCH_MAX_LIVE_MS ─
      const firstSeenAt = existing?._firstSeenAt ?? now;
      if (now - firstSeenAt > MATCH_MAX_LIVE_MS) {
        if (existing) await finalizeStaleLiveMatch(existing);
        liveMatchState.delete(m.main_id);
        continue;
      }

      // ── Guard 2: discard match stuck in "HT" for more than HT_MAX_DURATION_MS ──
      // Reset htStartedAt when match leaves HT (progresses to 2nd half)
      const htStartedAt = isHT
        ? (existing?._htStartedAt ??
          (existing?.status === "HT" ? existing._htStartedAt : now))
        : undefined;
      if (
        isHT &&
        htStartedAt !== undefined &&
        now - htStartedAt > HT_MAX_DURATION_MS
      ) {
        if (existing) await finalizeStaleLiveMatch(existing);
        liveMatchState.delete(m.main_id);
        continue;
      }

      const homeScore = m.home.goals === "?" ? 0 : parseInt(m.home.goals) || 0;
      const awayScore = m.away.goals === "?" ? 0 : parseInt(m.away.goals) || 0;
      const injMinute = parseInt(m.inj_minute) || 0;
      const injTime = parseInt(m.inj_time) || 0;
      const minuteBase = isHT ? 45 : isET ? 105 : parseInt(m.status) || 1;
      const minuteRaw =
        injMinute > 0
          ? Math.min(130, Math.max(1, injMinute + Math.max(0, injTime)))
          : minuteBase;
      const minute = existing
        ? Math.max(existing.minute, minuteRaw)
        : minuteRaw;
      const gameStatus = isHT
        ? "HT"
        : isET
          ? "ET"
          : parseInt(m.status) > 45
            ? "2nd half"
            : "1st half";

      // Stable odds: once assigned, keep unless score changes significantly
      let matchOdds: { home: number; draw: number; away: number };
      let matchMarkets: AdvancedMarkets;
      let matchMarketSuspension: Record<string, number> | undefined;
      let matchSuspensionReason: string | undefined;

      let hasRealOdds = true; // Always show odds — use model when real unavailable

      if (
        existing &&
        existing.homeScore === homeScore &&
        existing.awayScore === awayScore
      ) {
        // Score unchanged — background drift timer handles market updates every 1–2s.
        // Here we update minute, clean up expired suspensions, and re-filter settled markets.
        const now = Date.now();
        if (existing.marketSuspension) {
          const active = Object.fromEntries(
            Object.entries(existing.marketSuspension).filter(
              ([, ts]) => ts > now,
            ),
          );
          matchMarketSuspension =
            Object.keys(active).length > 0 ? active : undefined;
        }
        // Clear suspension reason if no active suspensions left
        if (!matchMarketSuspension) {
          matchSuspensionReason = undefined;
        }

        // Re-apply filterLiveMarkets so settled lines (BTTS, Over/Under) stay zeroed
        // even if drift or initialization left them non-zero.
        const safeMarkets = filterLiveMarkets(
          existing.markets,
          homeScore,
          awayScore,
          gameStatus,
        );
        const safeBase = filterLiveMarkets(
          existing._baseMarkets ?? existing.markets,
          homeScore,
          awayScore,
          gameStatus,
        );

        // Collect red cards from events even when score hasn't changed
        const rawEvents = m.events?.event
          ? Array.isArray(m.events.event)
            ? m.events.event
            : [m.events.event]
          : [];
        const rcHome = countRedCards(
          rawEvents.map((e) => ({ type: e.type ?? "", team: e.team ?? "" })),
          "home",
        );
        const rcAway = countRedCards(
          rawEvents.map((e) => ({ type: e.type ?? "", team: e.team ?? "" })),
          "away",
        );

        const updatedState = {
          ...existing,
          minute,
          date: m.date,
          time: m.time,
          markets: safeMarkets,
          _baseMarkets: safeBase,
          marketSuspension: matchMarketSuspension,
          _suspensionReason: matchMarketSuspension
            ? matchSuspensionReason ?? existing._suspensionReason
            : undefined,
          _firstSeenAt: firstSeenAt,
          _htStartedAt: isHT ? htStartedAt : undefined,
          redCardsHome: rcHome > 0 ? rcHome : undefined,
          redCardsAway: rcAway > 0 ? rcAway : undefined,
        };
        // Inject ET/pen markets if match is in extra time / penalties (always refresh in ET)
        {
          const inETU = isET || minute > 90;
          let mkt = updatedState.markets;
          if (inETU) {
            const etH = m.et && m.et.home_goals != null ? m.et.home_goals : 0;
            const etA = m.et && m.et.away_goals != null ? m.et.away_goals : 0;
            mkt = {
              ...mkt,
              etExtra: makeETMarketsFromScore(etH, etA, homeScore, awayScore),
            };
          }
          if (m.penalties && !mkt.penExtra) {
            mkt = {
              ...mkt,
              penExtra: makePenMarketsFromScore(
                m.penalties.home_pen,
                m.penalties.away_pen,
              ),
            };
          }
          if (mkt !== updatedState.markets)
            (updatedState as LiveMatchState).markets = mkt;
        }
        // VAR/penalty/card detection in score-unchanged ticks (V1 path)
        // Without this, VAR events are only caught when score changes.
        // Also check match status string for VAR keywords (V1 API may not use event types)
        const v1StatusStr = String(m.status ?? "").toLowerCase();
        const v1IsVARStatus =
          v1StatusStr.includes("var") ||
          v1StatusStr.includes("video review") ||
          v1StatusStr.includes("under review") ||
          v1StatusStr.includes("referee review") ||
          v1StatusStr.includes("review") ||
          v1StatusStr.includes("revision");
        if (!matchMarketSuspension && v1IsVARStatus) {
          const now2 = Date.now();
          matchMarketSuspension = Object.fromEntries(
            FOOTBALL_SUSP_KEYS.map((k) => [k, now2 + footballSuspensionDelayMs("var", k)]),
          ) as Record<string, number>;
          matchSuspensionReason = "REVISÃO AO VAR";
          (updatedState as LiveMatchState).marketSuspension = matchMarketSuspension;
          (updatedState as LiveMatchState)._suspensionReason = matchSuspensionReason;
        }
        if (!matchMarketSuspension && m.events?.event) {
          const rawEvts = Array.isArray(m.events.event)
            ? m.events.event
            : [m.events.event];
          const recentMin = Math.max(1, minute - 2);
          const V1_SUSP_TOKENS = [
            "penalty", "var", "bigchance", "big_chance", "suspension", "expelled",
            "video", "review", "offsidecheck",
          ];
          const V1_SUSP_LABELS: Record<string, string> = {
            penalty: "PENÁLTI",
            var: "REVISÃO AO VAR",
            bigchance: "GRANDE CHANCE",
            big_chance: "GRANDE CHANCE",
            suspension: "SUSPENSO",
            expelled: "SUSPENSO",
          };
          const dangerEv = rawEvts.find((e: unknown) => {
            const ev = e as Record<string, unknown>;
            const t = String(ev["type"] ?? "").toLowerCase().replace(/[\s_-]/g, "");
            const evMin = Number(ev["minute"] ?? 0);
            if (evMin < recentMin) return false;
            return V1_SUSP_TOKENS.some((tok) => t.includes(tok.replace("_", "")));
          });
          if (dangerEv) {
            const now2 = Date.now();
            const evType = String(
              (dangerEv as Record<string, unknown>)["type"] ?? "",
            ).toLowerCase().replace(/[\s_-]/g, "");
            const rk = Object.keys(V1_SUSP_LABELS).find((k) =>
              evType.includes(k),
            );
            const reason = rk ? V1_SUSP_LABELS[rk]! : "SUSPENSO";
            matchMarketSuspension = Object.fromEntries(
              FOOTBALL_SUSP_KEYS.map((k) => [
                k,
                now2 + footballSuspensionDelayMs("var", k),
              ]),
            ) as Record<string, number>;
            (updatedState as LiveMatchState).marketSuspension =
              matchMarketSuspension;
            (updatedState as LiveMatchState)._suspensionReason = reason;
          }
        }
        liveMatchState.set(m.main_id, updatedState as LiveMatchState);
        result.push({
          ...(updatedState as LiveMatchState),
          events: existing.events,
        });
        count++;
        continue;
      } else {
        // Score changed or first seen — build base odds from pre-match model/real data
        // Detect goal: score increased vs previous state
        const isGoal =
          existing != null &&
          (homeScore > existing.homeScore || awayScore > existing.awayScore);
        if (isGoal) {
          const now = Date.now();
          matchMarketSuspension = Object.fromEntries(
            FOOTBALL_SUSP_KEYS.map((k) => [
              k,
              now + footballSuspensionDelayMs("goal", k),
            ]),
          ) as Record<string, number>;
          matchSuspensionReason = "GOLO!";
        }
        const resolved = resolveOdds(m, odds);
        matchMarkets = resolved.markets;
        hasRealOdds = true;

        // Collect red cards from events (before they are parsed below)
        const rawEvents = m.events?.event
          ? Array.isArray(m.events.event)
            ? m.events.event
            : [m.events.event]
          : [];
        const rcHome = countRedCards(
          rawEvents.map((e) => ({ type: e.type ?? "", team: e.team ?? "" })),
          "home",
        );
        const rcAway = countRedCards(
          rawEvents.map((e) => ({ type: e.type ?? "", team: e.team ?? "" })),
          "away",
        );

        // Use sportsbook probability engine when score or game state changed
        matchOdds = calculateLive1x2({
          minute,
          homeGoals: homeScore,
          awayGoals: awayScore,
          redCardsHome: rcHome,
          redCardsAway: rcAway,
          baseHome: resolved.odds.home,
          baseDraw: resolved.odds.draw,
          baseAway: resolved.odds.away,
        });

        // Filter markets for live score (remove impossible/settled lines)
        matchMarkets = filterLiveMarkets(
          matchMarkets,
          homeScore,
          awayScore,
          gameStatus,
        );

        // Recalculate total goals using live-adjusted lambda (remaining time + current score)
        matchMarkets = {
          ...matchMarkets,
          totalGoals: recalcLiveTotalGoals(
            m.home.name,
            m.away.name,
            homeScore + awayScore,
            minute,
            m.status,
            matchMarkets.totalGoals,
          ),
          ...(matchMarkets.teamGoals
            ? {
                teamGoals: recalcLiveTeamGoals(
                  m.home.name,
                  m.away.name,
                  homeScore,
                  awayScore,
                  minute,
                  m.status,
                  matchMarkets.teamGoals,
                ),
              }
            : {}),
          bothTeamsScore:
            recalcLiveBothTeamsScore(
              m.home.name,
              m.away.name,
              homeScore,
              awayScore,
              minute,
              m.status,
              matchMarkets.bothTeamsScore,
            ) ?? matchMarkets.bothTeamsScore,
        };

        // Recalculate halfTime / secondHalf immediately on score change (Poisson-based)
        {
          const htScoreNow: [number, number] | null = m.ht
            ? [m.ht.home_goals, m.ht.away_goals]
            : null;
          if (matchMarkets.halfTime) {
            matchMarkets = {
              ...matchMarkets,
              halfTime: recalcLiveHalfTime(
                m.home.name,
                m.away.name,
                homeScore,
                awayScore,
                minute,
                m.status,
                matchMarkets.halfTime,
              ),
            };
          }
          if (matchMarkets.secondHalf) {
            matchMarkets = {
              ...matchMarkets,
              secondHalf: recalcLiveSecondHalf(
                m.home.name,
                m.away.name,
                homeScore,
                awayScore,
                htScoreNow,
                minute,
                m.status,
                matchMarkets.secondHalf,
              ),
            };
          }

          // ── HT/FT: zero out impossible outcomes when HT result is known ──────
          // At HT break: homeScore/awayScore ARE the halftime scores.
          // In 2nd half: use htScoreNow (from m.ht) to recover HT score.
          if (matchMarkets.htft) {
            const isAtHT = m.status === "HT";
            const isIn2nd = !isAtHT && minute > 45;
            let htH: number | null = null;
            let htA: number | null = null;
            if (isAtHT) {
              htH = homeScore;
              htA = awayScore;
            } else if (isIn2nd && htScoreNow) {
              [htH, htA] = htScoreNow;
            }

            if (htH !== null && htA !== null) {
              const htR = htH > htA ? "h" : htH < htA ? "a" : "d";
              const hf = matchMarkets.htft;
              // Extract the 3 surviving implied probs and re-normalize
              const raw3: [number, number, number] =
                htR === "h"
                  ? [hf.hh, hf.hd, hf.ha]
                  : htR === "d"
                    ? [hf.dh, hf.dd, hf.da]
                    : [hf.ah, hf.ad, hf.aa];
              const ps = raw3.map((o) => (o > 1 ? 1 / o : 0));
              const sum3 = ps.reduce((a, b) => a + b, 0);
              if (sum3 > 1e-9) {
                const normed = ps.map((p) => mc(p / sum3, 0.01, 0.99));
                const [o1, o2, o3] = probsToDecimalOdds(normed, 1.1);
                if (o1 !== undefined && o2 !== undefined && o3 !== undefined) {
                  const nh = {
                    hh: 0,
                    hd: 0,
                    ha: 0,
                    dh: 0,
                    dd: 0,
                    da: 0,
                    ah: 0,
                    ad: 0,
                    aa: 0,
                  };
                  if (htR === "h") {
                    nh.hh = o1;
                    nh.hd = o2;
                    nh.ha = o3;
                  } else if (htR === "d") {
                    nh.dh = o1;
                    nh.dd = o2;
                    nh.da = o3;
                  } else {
                    nh.ah = o1;
                    nh.ad = o2;
                    nh.aa = o3;
                  }
                  matchMarkets = { ...matchMarkets, htft: nh };
                }
              }
            }
          }
        }

        // Recalculate Double Chance and Draw No Bet from the ACTUAL live 1X2 odds.
        // The base model computes these from internal ELO probs which diverge from the
        // live 1X2 after score changes (e.g. Home=1.06 but DC homeOrDraw shows 2.89).
        {
          const inv = (o: number) => (o > 1 ? 1 / o : 0);
          const pH = inv(matchOdds.home);
          const pD = inv(matchOdds.draw);
          const pA = inv(matchOdds.away);
          const sum = pH + pD + pA;
          if (sum > 0 && matchOdds.draw > 0) {
            const nH = pH / sum,
              nD = pD / sum,
              nA = pA / sum;
            const dc = (p: number) =>
              mr(mc(1 / Math.max(1e-9, p * 1.04), 1.01, 100));
            matchMarkets = {
              ...matchMarkets,
              doubleChance: {
                homeOrDraw: dc(nH + nD),
                awayOrDraw: dc(nA + nD),
                homeOrAway: dc(nH + nA),
              },
              drawNoBet: matchMarkets.drawNoBet
                ? {
                    home: mr(
                      mc(
                        1 /
                          Math.max(1e-9, (nH / Math.max(1e-9, nH + nA)) * 1.04),
                        1.01,
                        100,
                      ),
                    ),
                    away: mr(
                      mc(
                        1 /
                          Math.max(1e-9, (nA / Math.max(1e-9, nH + nA)) * 1.04),
                        1.01,
                        100,
                      ),
                    ),
                  }
                : undefined,
            };
          }
        }
      }

      const events: LiveMatchState["events"] = [];
      if (m.events?.event) {
        const evArr = Array.isArray(m.events.event)
          ? m.events.event
          : [m.events.event];
        for (const ev of evArr) {
          events.push({
            type: ev.type,
            team: ev.team,
            minute: parseInt(ev.minute) || 0,
            player: ev.player || "",
          });
        }
      }
      // Red card counts derived from the fully-parsed events (available in both branches)
      const stateRcHome = countRedCards(events, "home");
      const stateRcAway = countRedCards(events, "away");

      // ── Live-recalculate new football markets from remaining expected goals ──
      if (!isET && !m.penalties && minute < 90) {
        const remFrac = Math.max(0.01, (90 - Math.min(minute, 89)) / 90);
        const pH0 = 0.95 / Math.max(1.01, matchOdds.home);
        const pA0 = 0.95 / Math.max(1.01, matchOdds.away);
        const pD0 = Math.max(0.02, 1 - pH0 - pA0);
        const totL = 2.6;
        const hStr = pH0 + pD0 * 0.45;
        const aStr = pA0 + pD0 * 0.45;
        const muH =
          totL *
          (hStr / Math.max(1e-9, hStr + aStr)) *
          1.08 *
          remFrac *
          Math.max(0.4, 1 - 0.12 * stateRcHome + 0.04 * stateRcAway);
        const muA =
          totL *
          (aStr / Math.max(1e-9, hStr + aStr)) *
          0.92 *
          remFrac *
          Math.max(0.4, 1 - 0.12 * stateRcAway + 0.04 * stateRcHome);
        const pHomeWin = pH0 / Math.max(1e-9, pH0 + pD0 + pA0);
        const pAwayWin = pA0 / Math.max(1e-9, pH0 + pD0 + pA0);
        const homeScore =
          m.home.goals === "?" ? 0 : parseInt(m.home.goals) || 0;
        const awayScore =
          m.away.goals === "?" ? 0 : parseInt(m.away.goals) || 0;
        const scored = homeScore + awayScore;
        // Win to Nil & Clean Sheet — zeroed when opponent has already scored
        const pWTNH =
          awayScore === 0 ? mc(pHomeWin * Math.exp(-muA), 0.01, 0.85) : 0;
        const pWTNA =
          homeScore === 0 ? mc(pAwayWin * Math.exp(-muH), 0.01, 0.85) : 0;
        const pCSH = awayScore === 0 ? mc(Math.exp(-muA), 0.01, 0.99) : 0;
        const pCSA = homeScore === 0 ? mc(Math.exp(-muH), 0.01, 0.99) : 0;
        const wtnHLive = pWTNH > 0 ? mr(mc(1 / (pWTNH * 0.935), 1.01, 50)) : 0;
        const wtnALive = pWTNA > 0 ? mr(mc(1 / (pWTNA * 0.935), 1.01, 50)) : 0;
        const csHLive = pCSH > 0 ? mr(mc(1 / (pCSH * 0.935), 1.01, 20)) : 0;
        const csALive = pCSA > 0 ? mr(mc(1 / (pCSA * 0.935), 1.01, 20)) : 0;
        // Odd/Even: parity of goals already scored + remaining
        const muRem = muH + muA;
        const pmfRem = poissonPmf(muRem, 10);
        let pOddFin = 0,
          pEvenFin = 0;
        for (let k = 0; k <= 10; k++) {
          if ((scored + k) % 2 === 0) pEvenFin += pmfRem[k]!;
          else pOddFin += pmfRem[k]!;
        }
        const [oeOddL, oeEvenL] = probsToDecimalOdds(
          [mc(pOddFin, 0.2, 0.8), mc(pEvenFin, 0.2, 0.8)],
          1.06,
        );
        // Exact Goals: accumulate remaining distribution into buckets
        const egBuckets: Record<string, number> = {};
        for (let add = 0; add <= 10; add++) {
          const tot = scored + add;
          const key = tot >= 5 ? "g5plus" : `g${tot}`;
          egBuckets[key] = (egBuckets[key] ?? 0) + (pmfRem[add] ?? 0);
        }
        const egBucketTotal = Object.values(egBuckets).reduce(
          (a, b) => a + b,
          0,
        );
        const egLiveOdds =
          egBucketTotal > 0
            ? Object.fromEntries(
                Object.entries(egBuckets).map(([k, p]) => [
                  k,
                  Math.max(
                    1.01,
                    +(1 / ((p / egBucketTotal) * 0.87)).toFixed(2),
                  ),
                ]),
              )
            : {};
        // Team Goals O/U live: P(team scores ≥ threshold more goals | still have remaining time)
        const tgLive = (
          score: number,
          threshold: number,
          mu: number,
        ): [number, number] => {
          if (score >= threshold) return [0, 0]; // already settled — won the Over
          const need = threshold - score;
          const pOver = mc(1 - poissonCdf(mu, need - 1), 0.02, 0.98);
          const r = probsToDecimalOdds([pOver, 1 - pOver], 1.065);
          return [r[0]!, r[1]!];
        };
        const [ho05, hu05] = tgLive(homeScore, 1, muH);
        const [ho15, hu15] = tgLive(homeScore, 2, muH);
        const [ho25, hu25] = tgLive(homeScore, 3, muH);
        const [ao05, au05] = tgLive(awayScore, 1, muA);
        const [ao15, au15] = tgLive(awayScore, 2, muA);
        const [ao25, au25] = tgLive(awayScore, 3, muA);

        matchMarkets = {
          ...matchMarkets,
          winToNil: { home: wtnHLive, away: wtnALive },
          cleanSheet: { home: csHLive, away: csALive },
          ...(oeOddL && oeEvenL
            ? { goalOddEven: { odd: oeOddL, even: oeEvenL } }
            : {}),
          ...(Object.keys(egLiveOdds).length > 0
            ? {
                exactGoals: {
                  g0: egLiveOdds["g0"] ?? 0,
                  g1: egLiveOdds["g1"] ?? 0,
                  g2: egLiveOdds["g2"] ?? 0,
                  g3: egLiveOdds["g3"] ?? 0,
                  g4: egLiveOdds["g4"] ?? 0,
                  g5plus: egLiveOdds["g5plus"] ?? 0,
                },
              }
            : {}),
          teamGoals: {
            homeOver05: ho05,
            homeUnder05: hu05,
            homeOver15: ho15,
            homeUnder15: hu15,
            homeOver25: ho25,
            homeUnder25: hu25,
            awayOver05: ao05,
            awayUnder05: au05,
            awayOver15: ao15,
            awayUnder15: au15,
            awayOver25: ao25,
            awayUnder25: au25,
          },
        };
      }

      // ── Remove 1st-half markets after half-time ─────────────────────────────
      // These markets are settled at half-time and must not show in the 2nd half.
      const in2ndHalf = !isHT && !isET && !m.penalties && minute > 45;
      const isAtHT = isHT;
      if (isAtHT || in2ndHalf) {
        matchMarkets = {
          ...matchMarkets,
          htCorrectScore: undefined, // 1T correct score — settled
          halfTime: { home: 0, draw: 0, away: 0 }, // 1T result — settled (zeros hide in UI)
          btts1H: undefined, // Both teams score in 1T — settled
          firstGoal: { home: 0, noGoal: 0, away: 0 }, // First goalscorer — settled (zeros hide in UI)
        };
      }

      // Live-recalculate h2CorrectScore during 2nd half from remaining λ
      if (!isHT && !isET && !m.penalties && minute > 45 && minute < 90) {
        const rem2HFrac = Math.max(0.01, (90 - Math.min(minute, 89)) / 45);
        const pH0b = 0.95 / Math.max(1.01, matchOdds.home);
        const pA0b = 0.95 / Math.max(1.01, matchOdds.away);
        const pD0b = Math.max(0.02, 1 - pH0b - pA0b);
        const hStrB = pH0b + pD0b * 0.45;
        const aStrB = pA0b + pD0b * 0.45;
        const mu2HH =
          2.6 *
          (hStrB / Math.max(1e-9, hStrB + aStrB)) *
          1.08 *
          rem2HFrac *
          Math.max(0.4, 1 - 0.12 * stateRcHome + 0.04 * stateRcAway);
        const mu2HA =
          2.6 *
          (aStrB / Math.max(1e-9, hStrB + aStrB)) *
          0.92 *
          rem2HFrac *
          Math.max(0.4, 1 - 0.12 * stateRcAway + 0.04 * stateRcHome);
        // Infer 2H score from events (goals scored after minute 45 come from 2H)
        const htGoalsH = events.filter(
          (e) =>
            e.team === "home" &&
            e.type.toLowerCase().includes("goal") &&
            e.minute <= 45,
        ).length;
        const htGoalsA = events.filter(
          (e) =>
            e.team === "away" &&
            e.type.toLowerCase().includes("goal") &&
            e.minute <= 45,
        ).length;
        const home2H = Math.max(0, homeScore - htGoalsH);
        const away2H = Math.max(0, awayScore - htGoalsA);
        const pmf2HH = poissonPmf(mu2HH, 7);
        const pmf2HA = poissonPmf(mu2HA, 7);
        const h2CSM: Record<string, number> = {};
        let h2CSOtherL = 0;
        for (let i = 0; i <= 7; i++) {
          for (let j = 0; j <= 7; j++) {
            const tot_i = home2H + i,
              tot_j = away2H + j;
            const p = (pmf2HH[i] ?? 0) * (pmf2HA[j] ?? 0);
            if (tot_i > 4 || tot_j > 4) {
              h2CSOtherL += p;
              continue;
            }
            h2CSM[`${tot_i}-${tot_j}`] = (h2CSM[`${tot_i}-${tot_j}`] ?? 0) + p;
          }
        }
        const h2CSArr = Object.entries(h2CSM).sort((a, b) => b[1] - a[1]);
        const h2CSTotL = h2CSArr.reduce((s, [, p]) => s + p, 0) + h2CSOtherL;
        if (h2CSTotL > 0) {
          const h2CSO = probsToDecimalOdds(
            h2CSArr.map(([, p]) => mc(p / h2CSTotL, 0.005, 0.7)),
            1.14,
          );
          const h2CSnew: Record<string, number> = {};
          h2CSArr.forEach(([score], idx) => {
            h2CSnew[score] = h2CSO[idx]!;
          });
          h2CSnew["Outro"] = mr(
            mc(
              1 / mc(h2CSOtherL / Math.max(1e-9, h2CSTotL) / 1.14, 0.005, 0.6),
              1.01,
              500,
            ),
          );
          matchMarkets = { ...matchMarkets, h2CorrectScore: h2CSnew };
        }
      }

      // VAR review / penalty / big-chance detection → suspend all markets
      // Triggered on dangerous events in the most recent 2 minutes of play
      const VAR_DANGER_TOKENS = [
        "penalty",
        "var",
        "missed",
        "bigchance",
        "big_chance",
        "suspension",
        "expelled",
      ];
      const VAR_REASON_MAP: Record<string, string> = {
        penalty: "PENÁLTI",
        var: "REVISÃO AO VAR",
        bigchance: "GRANDE CHANCE",
        big_chance: "GRANDE CHANCE",
        missed: "GRANDE CHANCE",
        suspension: "SUSPENSO",
        expelled: "SUSPENSO",
      };
      const recentThreshold = Math.max(1, minute - 2);
      const isGoalEvent =
        existing != null &&
        (homeScore > (existing.homeScore ?? -1) ||
          awayScore > (existing.awayScore ?? -1));
      // Search for a danger event in recent play.
      // On a goal tick we still allow VAR/penalty through — but suppress bigchance/missed
      // because those make no sense when a goal was actually scored.
      const dangerEvent = events.find((e) => {
        const t = e.type.toLowerCase().replace(/[\s_-]/g, "");
        if (e.minute < recentThreshold) return false;
        if (
          !VAR_DANGER_TOKENS.some((token) => t.includes(token.replace("_", "")))
        )
          return false;
        if (isGoalEvent && !t.includes("var") && !t.includes("penalty"))
          return false;
        return true;
      });
      if (dangerEvent) {
        const now = Date.now();
        const evType = dangerEvent.type.toLowerCase().replace(/[\s_-]/g, "");
        const reasonKey = Object.keys(VAR_REASON_MAP).find((k: string) =>
          evType.includes(k),
        );
        const reason = reasonKey ? VAR_REASON_MAP[reasonKey] : "SUSPENSO";
        const isHighPriority =
          reason.includes("VAR") || reason.includes("PENÁL");
        if (!matchMarketSuspension) {
          // No active suspension yet — set full timers
          matchMarketSuspension = Object.fromEntries(
            FOOTBALL_SUSP_KEYS.map((k) => [
              k,
              now + footballSuspensionDelayMs("var", k),
            ]),
          ) as Record<string, number>;
          matchSuspensionReason = reason;
        } else if (isHighPriority) {
          // VAR/penalty always overrides existing label (e.g. "GOLO!" → "REVISÃO AO VAR")
          // Do NOT reset suspension timers — keep the existing (longer) goal timers
          matchSuspensionReason = reason;
        }
      }

      // Inject ET markets when in extra time (minute > 90 or isET status)
      if (isET || minute > 90) {
        const etH = m.et && m.et.home_goals != null ? m.et.home_goals : 0;
        const etA = m.et && m.et.away_goals != null ? m.et.away_goals : 0;
        matchMarkets = {
          ...matchMarkets,
          etExtra: makeETMarketsFromScore(etH, etA, homeScore, awayScore),
        };
      }
      // Inject penalty markets when shootout is underway
      if (m.penalties) {
        matchMarkets = {
          ...matchMarkets,
          penExtra: makePenMarketsFromScore(
            m.penalties.home_pen,
            m.penalties.away_pen,
          ),
        };
      }

      const footballExtra: LiveMatchState["_liveExtra"] = {};
      if (m.ht) footballExtra.htScore = [m.ht.home_goals, m.ht.away_goals];
      if (m.et) footballExtra.etScore = [m.et.home_goals, m.et.away_goals];
      if (m.penalties)
        footballExtra.penScore = [m.penalties.home_pen, m.penalties.away_pen];
      
      // Fetch live stats (corners, cards, possession, shots, etc.) and add to _liveExtra
      try {
        const extras = await fetchFootballExtras(Number(m.main_id));
        if (extras) {
          const setIfDef = <K extends keyof typeof footballExtra>(
            key: K, val: typeof footballExtra[K]
          ) => { if (val !== undefined) (footballExtra as any)[key] = val; };
          setIfDef("cornersTotal", extras.cornersTotal);
          setIfDef("cardsTotal", extras.cardsTotal);
          setIfDef("possessionHome", extras.possessionHome);
          setIfDef("possessionAway", extras.possessionAway);
          setIfDef("shotsTotalHome", extras.shotsTotalHome);
          setIfDef("shotsTotalAway", extras.shotsTotalAway);
          setIfDef("shotsOnTargetHome", extras.shotsOnTargetHome);
          setIfDef("shotsOnTargetAway", extras.shotsOnTargetAway);
          setIfDef("foulsHome", extras.foulsHome);
          setIfDef("foulsAway", extras.foulsAway);
          setIfDef("yellowCardsHome", extras.yellowCardsHome);
          setIfDef("yellowCardsAway", extras.yellowCardsAway);
          setIfDef("redCardsHomeCount", extras.redCardsHomeCount);
          setIfDef("redCardsAwayCount", extras.redCardsAwayCount);
          setIfDef("offsidesHome", extras.offsidesHome);
          setIfDef("offsidesAway", extras.offsidesAway);
          setIfDef("savesHome", extras.savesHome);
          setIfDef("savesAway", extras.savesAway);
          setIfDef("dangerousAttacksHome", extras.dangerousAttacksHome);
          setIfDef("dangerousAttacksAway", extras.dangerousAttacksAway);
          setIfDef("attacksHome", extras.attacksHome);
          setIfDef("attacksAway", extras.attacksAway);
          setIfDef("xgHome", extras.xgHome);
          setIfDef("xgAway", extras.xgAway);
          setIfDef("throwInsHome", extras.throwInsHome);
          setIfDef("throwInsAway", extras.throwInsAway);
          setIfDef("crossesHome", extras.crossesHome);
          setIfDef("crossesAway", extras.crossesAway);
          setIfDef("passesHome", extras.passesHome);
          setIfDef("passesAway", extras.passesAway);
          setIfDef("passAccuracyHome", extras.passAccuracyHome);
          setIfDef("passAccuracyAway", extras.passAccuracyAway);
        }
      } catch {
        // Ignore errors fetching stats
      }

      const state: LiveMatchState = {
        id: m.main_id,
        home: m.home.name,
        away: m.away.name,
        homeTeamId: m.home.id ? String(m.home.id) : undefined,
        awayTeamId: m.away.id ? String(m.away.id) : undefined,
        league: normalizeLeagueName(league.name, league.country),
        country: league.country,
        sport: "football",
        homeScore,
        awayScore,
        minute,
        status: m.status,
        hasRealOdds,
        odds: matchOdds,
        markets: matchMarkets,
        events,
        marketSuspension: matchMarketSuspension,
        _suspensionReason: matchSuspensionReason,
        _baseOdds: matchOdds,
        _baseMarkets: matchMarkets,
        _oddsUpdatedAt: Date.now(),
        _driftPhase: 0,
        _liveExtra:
          Object.keys(footballExtra).length > 0 ? footballExtra : undefined,
        _firstSeenAt: firstSeenAt,
        _htStartedAt: isHT ? htStartedAt : undefined,
        redCardsHome: stateRcHome > 0 ? stateRcHome : undefined,
        redCardsAway: stateRcAway > 0 ? stateRcAway : undefined,
        date: m.date,
        time: m.time,
        leagueId: league.id,
      };

      liveMatchState.set(m.main_id, state);
      result.push(state);
      count++;
    }
  }

  return result;
}

async function buildUpcomingMatches(): Promise<UpcomingMatch[]> {
  const events = await getUpcomingEventsV2("football", 3);
  if (events.length === 0) return buildFootballUpcomingV1();
  // Capture ground-truth scheduled kickoff for every fixture seen here, before
  // any league/team filtering — this is our only trustworthy source, since it
  // comes from the schedule feed rather than the live feed's self-reported time.
  for (const ev of events) {
    if (ev.startTimestamp) footballScheduledKickoffSec.set(ev.id, ev.startTimestamp);
  }
  const seen = new Set<string>();
  const primary: SAPIV2Event[] = [];
  const fallback: SAPIV2Event[] = [];

  for (const ev of events) {
    const home = v2TeamName(ev.homeTeam);
    const away = v2TeamName(ev.awayTeam);
    if (home === "Unknown" || away === "Unknown") continue;
    const countryRaw = v2TournCountry(ev);
    const countryKey = normalizeCountryKey(countryRaw);
    const leagueRaw = countryKey
      ? `${countryKey}: ${v2TournName(ev.tournament)}`
      : v2TournName(ev.tournament);
    const leagueName = normalizeLeagueName(leagueRaw, countryKey);
    if (isBlockedLeague(`${leagueName} ${home} ${away}`)) continue;
    const key = `${home}|${away}`;
    if (seen.has(key)) continue;
    seen.add(key);
    if (footballLeagueAllowedStrict(countryRaw, leagueName)) primary.push(ev);
    else if (!isLeagueUniversallyBlocked(`${leagueName} ${home} ${away}`))
      fallback.push(ev);
    if (primary.length >= 80) break;
  }
  const filtered = (primary.length > 0 ? primary : fallback).slice(
    0,
    primary.length > 0 ? 80 : 3,
  );

  const oddsResults: Array<V2PreMatchOdds | null> = new Array(
    filtered.length,
  ).fill(null);
  const maxOddsLookups = Math.min(filtered.length, 30);
  const batchSize = 10;
  for (let i = 0; i < maxOddsLookups; i += batchSize) {
    const slice = filtered.slice(i, i + batchSize);
    const out = await Promise.all(
      slice.map((ev) => getPreMatchOddsV2("football", ev.id).catch(() => null)),
    );
    for (let j = 0; j < out.length; j++) oddsResults[i + j] = out[j] ?? null;
  }

  // ── Statpal league-level prematch odds (DC, BTTS, O/U, HT, DNB) ──────────
  // Fetch by league in parallel — one request covers all matches in that league.
  const leagueIds = [
    ...new Set(
      filtered
        .map((ev) => (ev.tournamentId ? String(ev.tournamentId) : null))
        .filter((id): id is string => id != null),
    ),
  ];
  const statpalLeagueOdds = new Map<string, FootballOddsEntry[]>();
  await Promise.all(
    leagueIds.map(async (leagueId) => {
      try {
        const { odds } = await getFootballLeagueOdds(leagueId);
        statpalLeagueOdds.set(leagueId, odds);
      } catch {
        /* skip leagues where prematch odds are unavailable */
      }
    }),
  );

  /** Normalise a team name for fuzzy matching across providers. */
  const normTeam = (s: string) =>
    String(s ?? "")
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9 ]/g, "")
      .replace(/\s+/g, " ")
      .trim();

  const results: UpcomingMatch[] = [];
  for (let i = 0; i < filtered.length; i++) {
    const ev = filtered[i]!;
    const home = v2TeamName(ev.homeTeam);
    const away = v2TeamName(ev.awayTeam);
    const countryRaw = v2TournCountry(ev);
    const countryKey = normalizeCountryKey(countryRaw);
    const leagueRaw = countryKey
      ? `${countryKey}: ${v2TournName(ev.tournament)}`
      : v2TournName(ev.tournament);
    const leagueName = normalizeLeagueName(leagueRaw, countryKey);
    const { date, time } = v2EventDateTime(ev);
    const realOdds = oddsResults[i] ?? null;
    const isWomens = isWomensLeague(v2TournName(ev.tournament));

    let odds: { home: number; draw: number; away: number };
    let markets: AdvancedMarkets;
    let hasRealOdds: boolean;

    const baseOdds = makeOddsFromTeams(home, away);
    const baseMarkets = makeAdvancedMarketsFromTeams(home, away);
    markets = {
      ...baseMarkets,
      ...(realOdds?.bttsYes
        ? {
            bothTeamsScore: { yes: realOdds.bttsYes, no: realOdds.bttsNo ?? 0 },
          }
        : {}),
      ...(realOdds?.over25
        ? {
            totalGoals: {
              ...baseMarkets.totalGoals,
              over25: realOdds.over25,
              under25: realOdds.under25 ?? 0,
            },
          }
        : {}),
    };
    const hasFull1x2 = !!(
      realOdds &&
      realOdds.home > 0 &&
      realOdds.draw > 0 &&
      realOdds.away > 0
    );
    odds = hasFull1x2
      ? { home: realOdds!.home, draw: realOdds!.draw, away: realOdds!.away }
      : baseOdds;
    hasRealOdds = hasFull1x2;

    // ── Enrich with Statpal league prematch odds ───────────────────────────
    // Supplements the per-match SportsAPI odds with Double Chance, BTTS,
    // Over/Under lines, Half Time, Draw No Bet, and Asian Handicap from the
    // Statpal prematch feed.  Also provides 1x2 as a fallback.
    const leagueIdStr = ev.tournamentId ? String(ev.tournamentId) : null;
    if (leagueIdStr) {
      const leagueEntries = statpalLeagueOdds.get(leagueIdStr) ?? [];
      const normHome = normTeam(home);
      const normAway = normTeam(away);
      const statpalMatch = leagueEntries.find(
        (e) =>
          normTeam(e.homeTeam.name) === normHome ||
          normTeam(e.awayTeam.name) === normAway ||
          (normTeam(e.homeTeam.name).includes(normHome.split(" ")[0]!) &&
            normTeam(e.awayTeam.name).includes(normAway.split(" ")[0]!)),
      );
      if (statpalMatch) {
        // 1x2 fallback when SportsAPI didn't supply it
        if (
          !hasRealOdds &&
          statpalMatch.homeOdds > 0 &&
          statpalMatch.drawOdds > 0 &&
          statpalMatch.awayOdds > 0
        ) {
          odds = {
            home: statpalMatch.homeOdds,
            draw: statpalMatch.drawOdds,
            away: statpalMatch.awayOdds,
          };
          hasRealOdds = true;
        }
        // Merge enriched markets — Statpal data wins when no existing value
        if (statpalMatch.markets) {
          const sm = statpalMatch.markets;
          if (sm.doubleChance?.homeOrDraw && !markets.doubleChance?.homeOrDraw)
            markets = { ...markets, doubleChance: sm.doubleChance };
          if (sm.bothTeamsScore?.yes && !markets.bothTeamsScore?.yes)
            markets = { ...markets, bothTeamsScore: sm.bothTeamsScore };
          if (sm.halfTime?.home && !markets.halfTime?.home)
            markets = { ...markets, halfTime: sm.halfTime };
          if (sm.drawNoBet?.home && !markets.drawNoBet?.home)
            markets = { ...markets, drawNoBet: sm.drawNoBet };
          if (sm.asianHandicap?.home && !markets.asianHandicap?.home)
            markets = { ...markets, asianHandicap: sm.asianHandicap };
          if (sm.firstGoal?.home && !markets.firstGoal?.home)
            markets = { ...markets, firstGoal: sm.firstGoal };
          // Merge O/U lines individually — Statpal may fill lines SportsAPI missed
          if (sm.totalGoals) {
            const tg = markets.totalGoals;
            markets = {
              ...markets,
              totalGoals: {
                ...tg,
                ...(sm.totalGoals.over05 && !tg.over05
                  ? { over05: sm.totalGoals.over05, under05: sm.totalGoals.under05 }
                  : {}),
                ...(sm.totalGoals.over15 && !tg.over15
                  ? { over15: sm.totalGoals.over15, under15: sm.totalGoals.under15 }
                  : {}),
                ...(sm.totalGoals.over25 && !tg.over25
                  ? { over25: sm.totalGoals.over25, under25: sm.totalGoals.under25 }
                  : {}),
                ...(sm.totalGoals.over35 && !tg.over35
                  ? { over35: sm.totalGoals.over35, under35: sm.totalGoals.under35 }
                  : {}),
                ...(sm.totalGoals.over45 && !tg.over45
                  ? { over45: sm.totalGoals.over45, under45: sm.totalGoals.under45 }
                  : {}),
              },
            };
          }
        }
      }
    }

    results.push({
      id: `fb-v2-${ev.id}`,
      home,
      away,
      homeTeamId: ev.homeTeamId != null ? String(ev.homeTeamId) : undefined,
      awayTeamId: ev.awayTeamId != null ? String(ev.awayTeamId) : undefined,
      league: leagueName,
      country: countryRaw,
      time,
      date,
      sport: "football",
      hasRealOdds,
      odds,
      markets,
      isWomens,
      leagueId: ev.tournamentId ? String(ev.tournamentId) : undefined,
    });
  }

  return results;
}

/**
 * Returns true if the match's scheduled date+time is already in the past.
 * Handles both DD.MM.YYYY and YYYY-MM-DD date formats.
 * A match is considered past as soon as its scheduled minute begins.
 */
function isMatchTimePast(dateStr: string, timeStr: string): boolean {
  if (!dateStr || !timeStr) return false;
  try {
    let isoDate: string;
    if (/^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
      const [dd, mm, yyyy] = dateStr.split(".");
      isoDate = `${yyyy}-${mm}-${dd}`;
    } else if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
      isoDate = dateStr;
    } else {
      return false;
    }
    // timeStr is Europe/Lisbon local time — convert to UTC before comparing
    const offsetH = lisbonOffsetHours();
    const [hStr, mStr] = timeStr.split(":");
    const hUtc = (parseInt(hStr!) - offsetH + 24) % 24;
    const scheduledMs = new Date(
      `${isoDate}T${String(hUtc).padStart(2, "0")}:${mStr}:00Z`,
    ).getTime();
    return Date.now() >= scheduledMs;
  } catch {
    return false;
  }
}

/**
 * Returns minutes until match starts (negative = already started).
 * `displayTimeStr` is UTC+1 (Portugal) — already addOneHour'd from raw Statpal UTC.
 */
function matchStartsInMinutes(dateStr: string, displayTimeStr: string): number {
  try {
    let isoDate: string;
    if (/^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
      const [dd, mm, yyyy] = dateStr.split(".");
      isoDate = `${yyyy}-${mm}-${dd}`;
    } else if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
      isoDate = dateStr;
    } else {
      return Infinity;
    }
    if (!/^\d{2}:\d{2}$/.test(displayTimeStr)) return Infinity;
    // displayTimeStr is Europe/Lisbon local time — convert to UTC dynamically
    const offsetH = lisbonOffsetHours();
    const [hStr, mStr] = displayTimeStr.split(":");
    const hUtc = (parseInt(hStr!) - offsetH + 24) % 24;
    const matchMs = new Date(
      `${isoDate}T${String(hUtc).padStart(2, "0")}:${mStr}:00Z`,
    ).getTime();
    return (matchMs - Date.now()) / 60000;
  } catch {
    return Infinity;
  }
}

/** Adds 1 hour to a "HH:MM" string (UTC → Portugal UTC+1). Wraps at midnight. */
function addOneHour(timeStr: string): string {
  if (!/^\d{2}:\d{2}$/.test(timeStr)) return timeStr;
  const [hStr, mStr] = timeStr.split(":");
  const h = (parseInt(hStr!) + 1) % 24;
  return `${String(h).padStart(2, "0")}:${mStr}`;
}

/**
 * Like addOneHour but also rolls the date forward when time crosses midnight
 * (e.g. 23:00 UTC → 00:00 PT on the next calendar day).
 * Returns spread-compatible { date, time } so callers can do: ...shiftHour(d, t)
 */
function shiftHour(
  dateStr: string,
  timeStr: string,
): { date: string; time: string } {
  if (!/^\d{2}:\d{2}$/.test(timeStr)) return { date: dateStr, time: timeStr };
  const [hStr, mStr] = timeStr.split(":");
  const h = parseInt(hStr!);
  const newH = (h + 1) % 24;
  const newTime = `${String(newH).padStart(2, "0")}:${mStr}`;
  if (h !== 23) return { date: dateStr, time: newTime };
  // Midnight rollover — advance date by 1 calendar day
  if (/^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
    const [dd, mm, yyyy] = dateStr.split(".");
    const d = new Date(parseInt(yyyy!), parseInt(mm!) - 1, parseInt(dd!));
    d.setDate(d.getDate() + 1);
    const nd = `${String(d.getDate()).padStart(2, "0")}.${String(d.getMonth() + 1).padStart(2, "0")}.${d.getFullYear()}`;
    return { date: nd, time: newTime };
  }
  return { date: dateStr, time: newTime };
}

// Pre-match tennis odds cache: keyed by sorted-surname pair so live matches
// can use the last known real odds even after status changes to "Set 1" etc.
const _tennisPreMatchOdds = new Map<string, { home: number; away: number }>();
const _tennisPreMatchSetScoreOdds = new Map<
  string,
  {
    score1st?: Array<{ label: string; odds: number }>;
    score2nd?: Array<{ label: string; odds: number }>;
    score3rd?: Array<{ label: string; odds: number }>;
  }
>();
function _tennisPairKey(n0: string, n1: string): string {
  const sur = (n: string) =>
    n
      .replace(/^([A-Z]\.\s*)+/, "")
      .trim()
      .toLowerCase();
  return [sur(n0), sur(n1)].sort().join("|");
}

/**
 * Returns base 1x2 odds for a tennis match.
 * Priority: real pre-match bookmaker odds from cache → neutral 1.85/1.85.
 * 1.85/1.85 (≈50/50 with ~8% margin) is far more accurate than applying the
 * soccer Poisson model to player name hashes, which produces arbitrary prices.
 */
function makeTennisBaseOdds(
  home: string,
  away: string,
): { home: number; draw: number; away: number } {
  const key = _tennisPairKey(home, away);
  const cached = _tennisPreMatchOdds.get(key);
  if (cached && cached.home > 1.01 && cached.away > 1.01) {
    return { home: cached.home, draw: 0, away: cached.away };
  }
  // Neutral tennis odds — better than a soccer Poisson model on player name hashes
  return { home: 1.85, draw: 0, away: 1.85 };
}

// ─── Live odds cache: real bookmaker live odds fetched per-match ───────────────
// Keyed by tennis match ID (number). Keep the TTL short enough for live tennis
// so the UI does not sit on stale prices for half a minute or more.
//   GET {SAPI_V2_TENNIS}/match/:id/odds  →  market "Full time" isLive:true
// Populated by refreshTennisLiveOdds() (fire-and-forget, called from buildTennisLiveV2).
const _tennisLiveOddsCache = new Map<
  number,
  { home: number; away: number; at: number }
>();
const _tennisLiveOddsInFlight = new Map<number, Promise<void>>();
const TENNIS_LIVE_ODDS_TTL = 2_500;

/** Convert fractional odd string (e.g. "7/2") to decimal (e.g. 4.50). */
function parseFractionalOdd(frac: string): number {
  const [n, d] = frac.split("/").map(Number);
  if (!d || isNaN(n) || isNaN(d)) return 0;
  return +(1 + n / d).toFixed(2);
}

/** Fire-and-forget: fetch live bookmaker odds for each match ID and store in cache. */
function refreshTennisLiveOdds(matchIds: number[]): void {
  const now = Date.now();
  const toFetch = [...new Set(matchIds)].filter((id) => {
    const cached = _tennisLiveOddsCache.get(id);
    if (cached && now - cached.at <= TENNIS_LIVE_ODDS_TTL) return false;
    return !_tennisLiveOddsInFlight.has(id);
  });
  if (toFetch.length === 0) return;
  for (const id of toFetch) {
    const request = (async () => {
      try {
        const res = await fetch(`${SAPI_V2_TENNIS}/match/${id}/odds`, {
          headers: sapiHeaders(),
          signal: AbortSignal.timeout(6_000),
        });
        if (!res.ok) return;
        const j = (await res.json()) as {
          data?: {
            markets?: Array<{
              marketName?: string;
              marketId?: number;
              isLive?: boolean;
              choices?: Array<{ name?: string; fractionalValue?: string }>;
            }>;
          };
        };
        const markets = j.data?.markets ?? [];
        // Pick the live Full time (match winner) market
        const ft = markets.find(
          (m) =>
            (m.marketName === "Full time" || m.marketId === 1) &&
            m.isLive === true,
        );
        if (!ft) return;
        const homeChoice = (ft.choices ?? []).find((c) => c.name === "1");
        const awayChoice = (ft.choices ?? []).find((c) => c.name === "2");
        if (!homeChoice?.fractionalValue || !awayChoice?.fractionalValue)
          return;
        const home = parseFractionalOdd(homeChoice.fractionalValue);
        const away = parseFractionalOdd(awayChoice.fractionalValue);
        if (home <= 1 || away <= 1) return; // sanity — 1/1 or worse is a data error
        _tennisLiveOddsCache.set(id, { home, away, at: Date.now() });
      } catch {
        /* ignore */
      } finally {
        _tennisLiveOddsInFlight.delete(id);
      }
    })();
    _tennisLiveOddsInFlight.set(id, request);
  }
}

const _tennisServingCache = new Map<
  number,
  { serving: [boolean, boolean]; at: number }
>();
const _tennisServingInFlight = new Map<number, Promise<void>>();
const TENNIS_SERVING_TTL = 1_500;
type TennisLiveDetailSnapshot = {
  status: string;
  statusCode?: number;
  sets: Array<[number, number]>;
  currentPoints?: [number | string, number | string];
  serving?: [boolean, boolean];
  fetchedAt: number;
};
const _tennisLiveDetailCache = new Map<number, TennisLiveDetailSnapshot>();
const _tennisLiveDetailInFlight = new Map<
  number,
  Promise<TennisLiveDetailSnapshot | null>
>();

function parseTennisPointValue(
  p: string | undefined,
): number | string | undefined {
  if (p === undefined) return undefined;
  if (p === "AD" || p === "D") return p;
  const n = parseInt(p, 10);
  return Number.isNaN(n) ? p : n;
}

function tennisSetLabel(n: number): string {
  if (n === 1) return "1st set";
  if (n === 2) return "2nd set";
  if (n === 3) return "3rd set";
  return `Set ${n}`;
}

function tennisDisplayStatus(
  status: string,
  statusCode: number | undefined,
  sets: Array<[number, number]>,
): string {
  const raw = String(status ?? "").trim();
  if (raw && raw.toLowerCase() !== "in progress") return raw;
  if (typeof statusCode === "number" && statusCode >= 13)
    return tennisSetLabel(statusCode - 12);
  return tennisSetLabel(Math.max(1, sets.length || 1));
}

async function getTennisMatchDetailV2(
  id: number,
): Promise<TennisLiveDetailSnapshot | null> {
  const now = Date.now();
  const cached = _tennisLiveDetailCache.get(id);
  if (cached && now - cached.fetchedAt <= TENNIS_SERVING_TTL) return cached;
  const inflight = _tennisLiveDetailInFlight.get(id);
  if (inflight) return inflight;
  const p = (async () => {
    const toBool = (v: unknown): boolean | null => {
      if (v === true || v === false) return v;
      if (v == null) return null;
      const s = String(v).trim().toLowerCase();
      if (s === "true" || s === "1" || s === "yes" || s === "y") return true;
      if (s === "false" || s === "0" || s === "no" || s === "n") return false;
      return null;
    };
    try {
      const res = await fetch(`${SAPI_V2_TENNIS}/match/${id}`, {
        headers: sapiHeaders(),
        signal: AbortSignal.timeout(6_000),
      });
      if (!res.ok) return null;
      const j = await res.json();
      const ev =
        j?.event ??
        j?.data?.event ??
        j?.data?.match?.event ??
        j?.data?.data?.event ??
        null;
      if (!ev) return null;
      const hS =
        typeof ev.homeScore === "object" && ev.homeScore !== null
          ? (ev.homeScore as SAPIV2ScoreObj)
          : null;
      const aS =
        typeof ev.awayScore === "object" && ev.awayScore !== null
          ? (ev.awayScore as SAPIV2ScoreObj)
          : null;
      const sets: Array<[number, number]> = [];
      if (hS && aS) {
        (
          ["period1", "period2", "period3", "period4", "period5"] as Array<
            keyof SAPIV2ScoreObj
          >
        ).forEach((p) => {
          const h = hS[p] as number | undefined;
          const a = aS[p] as number | undefined;
          if (h !== undefined && a !== undefined) sets.push([h, a]);
        });
      }
      const points =
        hS?.point !== undefined && aS?.point !== undefined
          ? ([
              parseTennisPointValue(hS.point),
              parseTennisPointValue(aS.point),
            ] as [number | string, number | string])
          : undefined;
      const h = ev.homeTeam ?? ev.home ?? ev.homeCompetitor ?? null;
      const a = ev.awayTeam ?? ev.away ?? ev.awayCompetitor ?? null;
      const hs = toBool(h?.serving ?? h?.serve ?? h?.isServing ?? h?.service);
      const as = toBool(a?.serving ?? a?.serve ?? a?.isServing ?? a?.service);
      const serving =
        hs === null && as === null
          ? undefined
          : ([hs === true, as === true] as [boolean, boolean]);
      const statusCode =
        typeof ev.status === "object" && ev.status?.code !== undefined
          ? ev.status.code
          : ev.statusCode;
      const status = tennisDisplayStatus(
        v2StatusStr(ev.status),
        statusCode,
        sets,
      );
      const snap: TennisLiveDetailSnapshot = {
        status,
        statusCode,
        sets,
        currentPoints: points,
        serving,
        fetchedAt: Date.now(),
      };
      _tennisLiveDetailCache.set(id, snap);
      if (serving) _tennisServingCache.set(id, { serving, at: snap.fetchedAt });
      return snap;
    } catch {
      return null;
    } finally {
      _tennisLiveDetailInFlight.delete(id);
    }
  })();
  _tennisLiveDetailInFlight.set(id, p);
  return p;
}

function refreshTennisServing(matchIds: number[]): void {
  const now = Date.now();
  const toFetch = matchIds.filter((id) => {
    const cached = _tennisServingCache.get(id);
    if (cached && now - cached.at <= TENNIS_SERVING_TTL) return false;
    if (_tennisServingInFlight.has(id)) return false;
    return true;
  });
  if (toFetch.length === 0) return;

  for (const id of toFetch) {
    const p = (async () => {
      try {
        await getTennisMatchDetailV2(id);
      } catch {}
    })().finally(() => {
      _tennisServingInFlight.delete(id);
    });
    _tennisServingInFlight.set(id, p);
  }
}

export { buildLiveMatches, buildUpcomingMatches, getUpcomingAll };

// ─── SportsAPI Pro V2 Live Build Functions ────────────────────────────────────

function normalizeLiveStatus(value: string | undefined): string {
  return String(value ?? "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function isFootballV2FinishedStatus(statusStr: string): boolean {
  const s = normalizeLiveStatus(statusStr);
  if (!s) return false;
  return (
    s === "ft" ||
    s === "aet" ||
    s === "ap" ||
    s.includes("finished") ||
    s.includes("ended") ||
    s.includes("after extra time") ||
    s.includes("after penalties") ||
    s.includes("postpon") ||
    s.includes("cancel") ||
    s.includes("abandon") ||
    s.includes("awarded")
  );
}

function isFootballV2LiveStatus(
  statusStr: string,
  statusCode?: number,
): boolean {
  const s = normalizeLiveStatus(statusStr);
  if (isFootballV2FinishedStatus(statusStr)) return false;
  if (typeof statusCode === "number") {
    if (statusCode >= 100) return false;
    if (statusCode > 0) return true;
  }
  if (!s) return false;
  return (
    s === "ht" ||
    s.includes("halftime") ||
    s.includes("1st half") ||
    s.includes("first half") ||
    s.includes("2nd half") ||
    s.includes("second half") ||
    s.includes("half time") ||
    s.includes("extra time") ||
    s.includes("1st extra time") ||
    s.includes("2nd extra time") ||
    s.includes("penalt") ||
    s.includes("break time") ||
    s.includes("pause") ||
    s.includes("var") ||
    s.includes("review") ||
    s.includes("in progress") ||
    s.includes("live") ||
    s.includes("playing")
  );
}

// Tracks the last time a match's minute+score changed.
// If both are frozen for > 20 min the match is a zombie and gets evicted.
const _v2StuckTracker = new Map<
  string,
  { minute: number; score: string; since: number }
>();
const FIRST_HALF_CLOCK_CAP_MIN = 59;
const SECOND_HALF_CLOCK_CAP_MIN = 109;

async function buildFootballLiveV2(
  events: SAPIV2Event[],
): Promise<LiveMatchState[]> {
  const now = Date.now();
  const clockSkewSec = (() => {
    // Default: 30 s — only allow a match into the live feed up to 30 seconds
    // before its scheduled kickoff (tolerates minor API clock drift). The old
    // default of 180 s (3 min) caused Statpal's pre-game fixtures (reported as
    // "1st half 0'" before kickoff) to appear in the live section with a
    // running clock up to 3 minutes early.
    const v = Number(process.env.FOOTBALL_CLOCK_SKEW_SEC ?? "30");
    if (!Number.isFinite(v)) return 30;
    return Math.min(600, Math.max(0, Math.trunc(v)));
  })();
  // Keep the ground-truth kickoff map fresh before evaluating any "too early"
  // guard below — getDailyLeagues() is internally cached, so this is a no-op
  // fetch-wise on most calls.
  await refreshFootballGroundTruthKickoffs();

  const result: LiveMatchState[] = [];
  const currentIds = new Set<string>();
  const providerPresentIds = new Set<string>();

  const pool = async <T>(
    items: T[],
    limit: number,
    fn: (item: T) => Promise<void>,
  ): Promise<void> => {
    let i = 0;
    const workers = Array.from({ length: Math.max(1, limit) }).map(async () => {
      while (i < items.length) {
        const cur = items[i++]!;
        await fn(cur);
      }
    });
    await Promise.all(workers);
  };

  const metaById = new Map<
    number,
    { countryRaw: string; countryKey: string; leagueName: string; prio: number }
  >();
  const primary: Array<{
    ev: SAPIV2Event;
    prio: number;
    fromUpcoming: boolean;
  }> = [];
  const fallback: Array<{
    ev: SAPIV2Event;
    prio: number;
    fromUpcoming: boolean;
  }> = [];

  for (const ev of events) {
    const statusStr = v2StatusStr(ev.status);
    const statusCode = v2StatusCode(ev);
    if (isFootballV2FinishedStatus(statusStr)) continue;
    if (!isFootballV2LiveStatus(statusStr, statusCode)) continue;
    // Prefer the ground-truth kickoff captured from the pre-match schedule feed
    // over the live feed's own self-reported startTimestamp: some providers
    // report a fixture's date/time as already-past in lockstep with a fake
    // early "live"/0' status, which would otherwise defeat this guard entirely.
    const groundTruthStart = footballScheduledKickoffSec.get(ev.id);
    const effectiveStart = groundTruthStart ?? ev.startTimestamp;
    const evAgeSeconds = effectiveStart
      ? Date.now() / 1000 - effectiveStart
      : 0;
    if (evAgeSeconds > 2.5 * 3600) continue;
    // Guard against providers (Statpal in particular) reporting not-yet-started
    // fixtures as "live" with a fake 0' status. If the scheduled kickoff is
    // still in the future beyond the allowed clock-skew window, it hasn't
    // actually started — do not show it in the live feed.
    if (effectiveStart && -evAgeSeconds > clockSkewSec) continue;
    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    if (homeTeam === "Unknown" || awayTeam === "Unknown") continue;

    const countryRaw = v2TournCountry(ev);
    const countryKey = normalizeCountryKey(countryRaw);
    const leagueRaw = countryKey
      ? `${countryKey}: ${v2TournName(ev.tournament)}`
      : v2TournName(ev.tournament);
    const leagueName = normalizeLeagueName(leagueRaw, countryKey);
    if (isBlockedLeague(`${leagueName} ${homeTeam} ${awayTeam}`)) continue;

    const key = `${countryKey}: ${leagueName}`.toLowerCase();
    const prio = leaguePriority(key, countryKey);
    const isPriorityLeague = isCatalogPriorityLeague(prio);
    const fromUpcoming = hasRecentUpcomingFootballEligibility(ev.id);
    metaById.set(ev.id, { countryRaw, countryKey, leagueName, prio });
    // Gate: block a match appearing for the first time if it's already more than
    // 20 minutes old. Prevents games from suddenly entering the live section
    // already mid-game (e.g. at 60'). fromUpcoming matches bypass this because
    // they were pre-announced as upcoming. Cold-start grace period (first 5 min
    // after process boot) also bypasses this gate so that a fresh deploy (e.g.
    // on Railway) immediately surfaces all currently-live matches rather than
    // waiting up to 20 minutes for them to appear.
    const isColdStart = Date.now() - SERVER_BOOT_AT < COLD_START_GRACE_MS;
    // oddsLiveKnownIds: IDs confirmed live via /v2/soccer/odds/live — bookmakers only
    // price live odds on matches in progress, so these bypass the "never seen + >20min"
    // gate that exists to block Statpal pre-match fixtures faking a live status.
    const isConfirmedOddsLive = oddsLiveKnownIds.has(ev.id);
    if (
      !liveMatchState.has(`football-v2-${ev.id}`) &&
      evAgeSeconds > 20 * 60 &&
      !fromUpcoming &&
      !isColdStart &&
      !isConfirmedOddsLive
    )
      continue;

    if (footballLeagueAllowedStrict(countryRaw, leagueName))
      primary.push({ ev, prio, fromUpcoming });
    else if (
      !isLeagueUniversallyBlocked(`${leagueName} ${homeTeam} ${awayTeam}`)
    )
      fallback.push({ ev, prio: prio === 999 ? 500 : prio, fromUpcoming });
    providerPresentIds.add(`football-v2-${ev.id}`);
  }

  primary.sort((a, b) => a.prio - b.prio);
  fallback.sort((a, b) => a.prio - b.prio);

  const source = primary.length > 0 ? primary : fallback;
  const baseCap = primary.length > 0 ? 40 : 8;
  const chosen: SAPIV2Event[] = [];
  const chosenIds = new Set<number>();
  for (const entry of source) {
    if (chosenIds.has(entry.ev.id)) continue;
    if (!entry.fromUpcoming && chosen.length >= baseCap) continue;
    chosen.push(entry.ev);
    chosenIds.add(entry.ev.id);
  }

  for (const entry of source) {
    if (chosen.length >= 70) break;
    if (chosenIds.has(entry.ev.id)) continue;
    if (!liveMatchState.has(`football-v2-${entry.ev.id}`)) continue;
    chosen.push(entry.ev);
    chosenIds.add(entry.ev.id);
  }

  const prefetchRedCards = new Map<number, V2RedCards>();

  const firstSeenMatchIds = chosen
    .filter((ev) => !liveMatchState.has(`football-v2-${ev.id}`))
    .map((ev) => ev.id);

  // Fire-and-forget background pre-fetcher for newly seen matches
  if (firstSeenMatchIds.length > 0) {
    (async () => {
      for (const id of firstSeenMatchIds) {
        getFootballV2RedCards(id).catch(() => {});
      }
    })().catch(() => {});
  }

  for (const ev of chosen) {
    const statusStr = v2StatusStr(ev.status);

    const id = `football-v2-${ev.id}`;
    currentIds.add(id);

    // Skip matches the server already saw finish — API sometimes re-reports
    // completed matches as "live" in a later poll (zombie feed).
    if (finishedMatchResults.has(id)) continue;

    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    const homeScore = v2CurrentScore(ev.homeScore);
    const awayScore = v2CurrentScore(ev.awayScore);
    const meta = metaById.get(ev.id);
    const league =
      meta?.leagueName ?? normalizeLeagueName(v2TournName(ev.tournament), "");
    const { date, time } = v2EventDateTime(ev);
    const rc = v2FootballRedCardsCache.get(ev.id) ?? {
      home: 0,
      away: 0,
      fetchedAt: 0,
    };
    const rcHome = rc.home ?? 0;
    const rcAway = rc.away ?? 0;

    // Block youth matches: check league name AND team names (e.g. "Pergolettese U19")
    if (isBlockedLeague(`${league} ${homeTeam} ${awayTeam}`)) continue;

    const existing = liveMatchState.get(id);
    const isHT = statusStr === "HT";
    const isPen = statusStr === "Penalties";
    const isET =
      !isPen && (statusStr.includes("extra") || statusStr === "Extra Time");
    const isBreak = statusStr === "Break Time" || statusStr === "Pause";
    const existingStatus = String(existing?.status ?? "");
    let resolvedKickoffSec: number | undefined =
      existing?._liveExtra?.kickoffSec;
    let elapsedClockMinutes: number | null = null;
    let inferredSecondHalf = false;
    let minute: number;
    if (isHT) {
      minute = 45;
    } else if (isPen) {
      minute = 120;
    } else if (isET) {
      minute = 105;
    } else {
      let kickoffSec =
        existing?._liveExtra?.kickoffSec ??
        footballScheduledKickoffSec.get(ev.id) ??
        ev.startTimestamp ??
        0;
      if (!kickoffSec) {
        const { date: sDate, time: sTime } = v2EventDateTime(ev);
        if (sDate && /^\d{2}:\d{2}$/.test(sTime)) {
          try {
            const [dd, mm, yyyy] = sDate.split(".");
            const offsetH = lisbonOffsetHours();
            const [hStr, mStr] = sTime.split(":");
            const hUtc = (parseInt(hStr!) - offsetH + 24) % 24;
            kickoffSec =
              new Date(
                `${yyyy}-${mm}-${dd}T${String(hUtc).padStart(2, "0")}:${mStr}:00Z`,
              ).getTime() / 1000;
          } catch {
            kickoffSec = 0;
          }
        }
      }
      if (kickoffSec > 0) {
        resolvedKickoffSec = kickoffSec;
        const minsFromKickoff = Math.floor(
          (now / 1000 - kickoffSec - clockSkewSec) / 60,
        );
        elapsedClockMinutes = Math.max(0, minsFromKickoff);
        inferredSecondHalf =
          !isHT &&
          !isPen &&
          !isET &&
          !isBreak &&
          (statusStr === "2nd half" ||
            existingStatus === "2nd half" ||
            !!existing?._liveExtra?.secondHalfKickoffSec ||
            minsFromKickoff >= 63);
        if (statusStr === "1st half" && !inferredSecondHalf) {
          // Keep the first-half clock running through stoppage time until the feed
          // explicitly flips to HT, instead of freezing at 49'.
          minute = Math.min(
            FIRST_HALF_CLOCK_CAP_MIN,
            Math.max(0, minsFromKickoff),
          );
        } else if (statusStr === "2nd half" || inferredSecondHalf) {
          const shKickoff = existing?._liveExtra?.secondHalfKickoffSec;
          if (
            typeof shKickoff === "number" &&
            Number.isFinite(shKickoff) &&
            shKickoff > 0
          ) {
            const minsFromSecondHalf = Math.floor(
              (now / 1000 - shKickoff - clockSkewSec) / 60,
            );
            minute = Math.min(
              SECOND_HALF_CLOCK_CAP_MIN,
              Math.max(45, 45 + minsFromSecondHalf),
            );
          } else {
            minute = Math.min(
              SECOND_HALF_CLOCK_CAP_MIN,
              Math.max(45, minsFromKickoff - 15),
            );
          }
        } else {
          minute = Math.min(
            FIRST_HALF_CLOCK_CAP_MIN,
            Math.max(0, minsFromKickoff),
          );
        }
      } else {
        // Last resort: no timestamp available at all — use mid-period defaults
        minute =
          statusStr === "1st half" ? 25 : statusStr === "2nd half" ? 70 : 45;
      }
    }
    const inferredHT =
      isBreak &&
      !existing?._liveExtra?.secondHalfKickoffSec &&
      minute >= 45 &&
      minute <= 55;
    if (inferredHT) minute = 45;
    const newStatus = inferredHT
      ? "HT"
      : isHT
        ? "HT"
        : isPen
          ? "Penalties"
          : isET
            ? "ET"
            : inferredSecondHalf
              ? "2nd half"
              : statusStr;

    if (existing) {
      const diff = existing.minute - minute;
      if (!(diff > 0 && diff <= 8)) {
        minute = Math.max(existing.minute, minute);
      }
    }

    const clockNowSec = Math.floor(now / 1000);
    const clamp = (n: number, lo: number, hi: number) =>
      Math.min(hi, Math.max(lo, n));
    const isFirstHalf = newStatus === "1st half";
    const isSecondHalf = newStatus === "2nd half";
    const shKickoffSec = isSecondHalf
      ? (existing?._liveExtra?.secondHalfKickoffSec ??
        (resolvedKickoffSec &&
        elapsedClockMinutes !== null &&
        elapsedClockMinutes >= 45
          ? Math.floor(now / 1000) - Math.max(0, minute - 45) * 60
          : 0))
      : 0;
    const baseSec = !resolvedKickoffSec
      ? null
      : newStatus === "HT"
        ? 45 * 60
        : isFirstHalf
          ? clamp(
              clockNowSec - resolvedKickoffSec - clockSkewSec,
              0,
              FIRST_HALF_CLOCK_CAP_MIN * 60,
            )
          : isSecondHalf
            ? clamp(
                45 * 60 +
                  (shKickoffSec > 0
                    ? clockNowSec - shKickoffSec - clockSkewSec
                    : Math.max(
                        0,
                        clockNowSec -
                          resolvedKickoffSec -
                          clockSkewSec -
                          15 * 60,
                      )),
                45 * 60,
                SECOND_HALF_CLOCK_CAP_MIN * 60,
              )
            : null;
    // Clock is only running if the game has actually started (baseSec > 0).
    // Previously this was computed before baseSec, which caused pre-kickoff
    // fixtures (status="1st half", baseSec=0 due to clamp) to send
    // clockRunning:true to the frontend, making the client-side timer tick
    // from 00:00 before the match had started.
    const isClockRunning = !!(
      resolvedKickoffSec &&
      (isFirstHalf || isSecondHalf) &&
      baseSec !== null &&
      baseSec > 0
    );
    const secInMin = baseSec === null ? 0 : clamp(baseSec % 60, 0, 59);
    const secStr = String(secInMin).padStart(2, "0");

    const clockStr =
      newStatus === "HT"
        ? undefined
        : isFirstHalf
          ? minute > 45
            ? `45+${minute - 45}'`
            : `${String(Math.max(0, minute)).padStart(2, "0")}:${secStr}`
          : isSecondHalf
            ? minute > 90
              ? `90+${minute - 90}'`
              : `${String(Math.max(45, minute)).padStart(2, "0")}:${secStr}`
            : minute > 0
              ? `${minute}'`
              : undefined;

    // Zombie detector: if minute AND score are identical for too long the feed is frozen.
    // Exclude HT/ET/Penalties where minute naturally stays constant for legitimate breaks.
    if (!isHT && !isPen && !isET) {
      const scoreKey = `${homeScore}-${awayScore}`;
      const stuck = _v2StuckTracker.get(id);
      if (stuck && stuck.minute === minute && stuck.score === scoreKey) {
        if (now - stuck.since > 45 * 60 * 1000) {
          // Mark finished so it doesn't reappear; clean up tracker and skip.
          await finalizeStaleLiveMatch({
            ...(existing ?? {
              id,
              home: homeTeam,
              away: awayTeam,
              league: meta?.leagueName ?? league,
              country: meta?.countryKey ?? "",
              sport: "football",
              homeScore,
              awayScore,
              minute,
              status: newStatus,
              hasRealOdds: false,
              odds: { home: 0, draw: 0, away: 0 },
              markets: {} as AdvancedMarkets,
              events: [],
            }),
            home: homeTeam,
            away: awayTeam,
            homeScore,
            awayScore,
            minute,
            status: newStatus,
          });
          liveMatchState.delete(id);
          _v2StuckTracker.delete(id);
          continue;
        }
      } else {
        _v2StuckTracker.set(id, { minute, score: scoreKey, since: now });
      }
    }

    if (existing) {
      minute = Math.max(existing.minute, minute);
      // Pre-compute VAR status once, used in both scored and non-scored branches
      const rawStatusDesc = v2StatusStr(ev.status).toLowerCase();
      const isVARStatus =
        rawStatusDesc.includes("var") ||
        rawStatusDesc.includes("video review") ||
        rawStatusDesc.includes("awaiting review") ||
        rawStatusDesc.includes("var check") ||
        rawStatusDesc.includes("awaiting var") ||
        rawStatusDesc.includes("video assistant") ||
        rawStatusDesc.includes("under review") ||
        rawStatusDesc.includes("referee review") ||
        rawStatusDesc.includes("review in progress") ||
        rawStatusDesc.includes("checking") ||
        rawStatusDesc.includes("arbitro") ||
        rawStatusDesc.includes("revision");

      const scored =
        homeScore !== existing.homeScore || awayScore !== existing.awayScore;
      const baseOdds = existing._baseOdds ?? {
        home: existing.odds.home,
        draw: existing.odds.draw,
        away: existing.odds.away,
      };
      const newOdds = scored
        ? calculateLive1x2({
            minute,
            homeGoals: homeScore,
            awayGoals: awayScore,
            redCardsHome: rcHome,
            redCardsAway: rcAway,
            baseHome: baseOdds.home,
            baseDraw: baseOdds.draw,
            baseAway: baseOdds.away,
          })
        : existing.odds;

      // Penalty score tracking: when entering "Penalties" phase store the pre-penalty base score.
      // On every subsequent tick compute goals scored in the shootout from the delta.
      const prevBase = existing._liveExtra?.penBaseScore;
      const penBase: [number, number] = isPen
        ? existing.status !== "Penalties"
          ? [homeScore, awayScore] // just transitioned — current score IS the base
          : (prevBase ?? [homeScore, awayScore]) // already in penalties — keep stored base
        : [0, 0];
      const penGoals: [number, number] = isPen
        ? [
            Math.max(0, homeScore - penBase[0]),
            Math.max(0, awayScore - penBase[1]),
          ]
        : [0, 0];
      const penLiveExtra: LiveMatchState["_liveExtra"] = isPen
        ? {
            ...(existing._liveExtra ?? {}),
            penBaseScore: penBase,
            penScore: penGoals,
          }
        : existing._liveExtra;
      const shKickoffSec =
        newStatus === "2nd half"
          ? existing.status !== "2nd half"
            ? Math.floor(now / 1000) - Math.max(0, minute - 45) * 60
            : (existing._liveExtra?.secondHalfKickoffSec ??
              Math.floor(now / 1000) - Math.max(0, minute - 45) * 60)
          : existing._liveExtra?.secondHalfKickoffSec;
      const liveExtra = {
        ...(penLiveExtra ?? {}),
        ...(shKickoffSec ? { secondHalfKickoffSec: shKickoffSec } : {}),
        kickoffSec: resolvedKickoffSec,
        ...(baseSec !== null
          ? { clockSec: baseSec, clockAtMs: now, clockRunning: isClockRunning }
          : {}),
        clockStr,
      };

      // Helper: patch penExtra with real penalty odds into markets
      const withPen = (mkts: typeof existing.markets) =>
        isPen
          ? {
              ...mkts,
              penExtra: makePenMarketsFromScore(penGoals[0], penGoals[1]),
            }
          : mkts;

      if (scored) {
        // Goal detected — filter settled markets, set goal suspension.
        // If the API is simultaneously reporting a VAR review (e.g. goal under review),
        // override the label immediately so the frontend shows "REVISÃO AO VAR".
        const filteredMarkets = withPen(
          filterLiveMarkets(existing.markets, homeScore, awayScore, newStatus),
        );
        const filteredBase = withPen(
          filterLiveMarkets(
            existing._baseMarkets ?? existing.markets,
            homeScore,
            awayScore,
            newStatus,
          ),
        );
        const susp = Object.fromEntries(
          FOOTBALL_SUSP_KEYS.map((k) => [
            k,
            now + footballSuspensionDelayMs("goal", k),
          ]),
        ) as Record<string, number>;
        const updated: LiveMatchState = {
          ...existing,
          country: meta?.countryRaw ?? existing.country,
          homeScore,
          awayScore,
          minute,
          status: newStatus,
          odds: newOdds,
          markets: filteredMarkets,
          _baseOdds: baseOdds,
          _baseMarkets: filteredBase,
          marketSuspension: susp,
          _suspensionReason: isVARStatus ? "REVISÃO AO VAR" : "GOLO!",
          _liveExtra: liveExtra,
          _lastSeenAt: now,
          _missingSinceAt: undefined,
          date,
          time,
          redCardsHome: rcHome > 0 ? rcHome : undefined,
          redCardsAway: rcAway > 0 ? rcAway : undefined,
        };
        liveMatchState.set(id, applyTieredMarketDrift(updated, now));
      } else {
        // Score unchanged — clean up expired suspensions, re-filter for safety
        let susp = existing.marketSuspension;
        if (susp) {
          const active = Object.fromEntries(
            Object.entries(susp).filter(([, ts]) => ts > now),
          );
          susp = Object.keys(active).length > 0 ? active : undefined;
        }
        const filteredMarkets = withPen(
          filterLiveMarkets(existing.markets, homeScore, awayScore, newStatus),
        );
        const filteredBase = withPen(
          filterLiveMarkets(
            existing._baseMarkets ?? existing.markets,
            homeScore,
            awayScore,
            newStatus,
          ),
        );

        // isVARStatus already computed above

        // If VAR is active: ensure suspension is set and override reason label
        if (isVARStatus) {
          if (!susp || Object.keys(susp).length === 0) {
            susp = Object.fromEntries(
              FOOTBALL_SUSP_KEYS.map((k) => [
                k,
                now + footballSuspensionDelayMs("var", k),
              ]),
            ) as Record<string, number>;
          }
          // Always override the reason label with VAR (covers "GOLO!" → "REVISÃO AO VAR")
          const updated: LiveMatchState = {
            ...existing,
            country: meta?.countryRaw ?? existing.country,
            homeScore,
            awayScore,
            minute,
            status: newStatus,
            odds: newOdds,
            markets: filteredMarkets,
            _baseOdds: baseOdds,
            _baseMarkets: filteredBase,
            marketSuspension: susp,
            _suspensionReason: "REVISÃO AO VAR",
            _liveExtra: liveExtra,
            _lastSeenAt: now,
            _missingSinceAt: undefined,
            date,
            time,
            redCardsHome: rcHome > 0 ? rcHome : undefined,
            redCardsAway: rcAway > 0 ? rcAway : undefined,
          };
          liveMatchState.set(id, applyTieredMarketDrift(updated, now));
        } else {
          const updated: LiveMatchState = {
            ...existing,
            country: meta?.countryRaw ?? existing.country,
            homeScore,
            awayScore,
            minute,
            status: newStatus,
            odds: newOdds,
            markets: filteredMarkets,
            _baseOdds: baseOdds,
            _baseMarkets: filteredBase,
            marketSuspension: susp,
            _suspensionReason: susp ? existing._suspensionReason : undefined,
            _liveExtra: liveExtra,
            _lastSeenAt: now,
            _missingSinceAt: undefined,
            date,
            time,
            redCardsHome: rcHome > 0 ? rcHome : undefined,
            redCardsAway: rcAway > 0 ? rcAway : undefined,
          };
          liveMatchState.set(id, applyTieredMarketDrift(updated, now));
        }
      }
      result.push(liveMatchState.get(id)!);
    } else {
      // First seen — build initial state with score-filtered markets
      const baseOdds =
        v2FootballOddsCache.get(String(ev.id)) ??
        getUpcomingPreMatchOdds(homeTeam, awayTeam) ??
        makeOddsFromTeams(homeTeam, awayTeam);
      const liveOdds =
        homeScore === 0 && awayScore === 0
          ? baseOdds
          : calculateLive1x2({
              minute,
              homeGoals: homeScore,
              awayGoals: awayScore,
              redCardsHome: rcHome,
              redCardsAway: rcAway,
              baseHome: baseOdds.home,
              baseDraw: baseOdds.draw,
              baseAway: baseOdds.away,
            });
      const rawMarkets = makeAdvancedMarketsFromTeams(homeTeam, awayTeam);
      const baseMarkets = filterLiveMarkets(
        rawMarkets,
        homeScore,
        awayScore,
        newStatus,
      );
      // First time seen in penalties — store current score as base (0-0 penalties so far)
      const markets = isPen
        ? { ...baseMarkets, penExtra: makePenMarketsFromScore(0, 0) }
        : baseMarkets;
      const shKickoffSec =
        statusStr === "2nd half"
          ? Math.floor(now / 1000) - Math.max(0, minute - 46) * 60
          : undefined;
      const state: LiveMatchState = {
        id,
        home: homeTeam,
        away: awayTeam,
        league,
        country: meta?.countryRaw ?? "",
        sport: "football",
        homeScore,
        awayScore,
        minute,
        status: newStatus,
        hasRealOdds: true,
        odds: liveOdds,
        markets,
        events: [],
        _firstSeenAt: now,
        _lastSeenAt: now,
        date,
        time,
        redCardsHome: rcHome > 0 ? rcHome : undefined,
        redCardsAway: rcAway > 0 ? rcAway : undefined,
        _baseOdds: baseOdds,
        _baseMarkets: markets,
        _oddsUpdatedAt: now,
        _liveExtra: {
          ...(isPen
            ? {
                penBaseScore: [homeScore, awayScore] as [number, number],
                penScore: [0, 0] as [number, number],
              }
            : {}),
          ...(shKickoffSec ? { secondHalfKickoffSec: shKickoffSec } : {}),
          kickoffSec: resolvedKickoffSec,
          ...(baseSec !== null
            ? {
                clockSec: baseSec,
                clockAtMs: now,
                clockRunning: isClockRunning,
              }
            : {}),
          clockStr,
        },
      };
      liveMatchState.set(id, state);
      result.push(state);
    }
  }

  // Garbage collect football matches no longer in the V2 live feed
  // Also evict matches blocked by youth filter or stuck > 4h (frozen feed safety net)
  const MAX_V2_LIVE_MS = 4 * 60 * 60 * 1000; // 4 hours
  const resultIds = new Set(result.map((m) => String(m.id)));
  for (const id of liveMatchState.keys()) {
    if (!id.startsWith("football-v2-")) continue;
    const state = liveMatchState.get(id);
    if (!state) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_V2_LIVE_MS;
    const blockedNow = isBlockedLeague(
      `${state.league} ${state.home} ${state.away}`,
    );
    if (tooOld) {
      await finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
      _v2StuckTracker.delete(id);
      continue;
    }
    if (blockedNow) {
      liveMatchState.delete(id);
      _v2StuckTracker.delete(id);
      continue;
    }
    if (providerPresentIds.has(id)) {
      if (state._missingSinceAt) {
        liveMatchState.set(id, {
          ...state,
          _missingSinceAt: undefined,
          _suspensionReason: undefined,
          _feedWarning: undefined,
        });
      }
      continue;
    }
    const missingSince = state._missingSinceAt ?? now;
    if (!state._missingSinceAt) {
      const updated: LiveMatchState = {
        ...state,
        _missingSinceAt: missingSince,
        _feedWarning: "SINAL INSTÁVEL",
      };
      liveMatchState.set(id, updated);
      if (!resultIds.has(id)) {
        result.push(updated);
        resultIds.add(id);
      }
      continue;
    }
    if (now - missingSince > getFootballLiveDisappearGraceMs(state)) {
      await finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
      _v2StuckTracker.delete(id);
      continue;
    }
    if (!resultIds.has(id)) {
      result.push(state);
      resultIds.add(id);
    }
  }

  return result;
}

const BBALL_SUSP_KEYS = [
  "result",
  "totalGoals",
  "handicap",
  "halfTime",
  "basketballExtra",
] as const;
const HOCKEY_SUSP_KEYS = [
  "result",
  "totalGoals",
  "handicap",
  "halfTime",
  "hockeyExtra",
] as const;
const BASEBALL_SUSP_KEYS = [
  "result",
  "totalGoals",
  "handicap",
  "mlbExtra",
] as const;
const MAX_LIVE_STATE_MS = 4 * 60 * 60 * 1000;

async function buildBasketballLiveV2(
  events: SAPIV2Event[],
): Promise<LiveMatchState[]> {
  const result: LiveMatchState[] = [];
  const now = Date.now();
  const currentIds = new Set<string>();
  const summaries = new Map<number, BasketballIncidentSummarySnapshot | null>();
  await Promise.all(
    events.slice(0, 40).map(async (ev) => {
      const idNum = Number(ev.id);
      if (!Number.isFinite(idNum) || idNum <= 0) return;
      const summary = await getBasketballIncidentSummaryV2(idNum).catch(
        () => null,
      );
      summaries.set(idNum, summary);
    }),
  );
  for (const ev of events) {
    const code = v2StatusCode(ev);
    // code 100 = ended; 0 = not started; undefined = keep
    if (code === 100 || code === 0) continue;
    const statusStr = v2StatusStr(ev.status);
    if (
      statusStr === "Not started" ||
      statusStr === "Ended" ||
      statusStr === "Finished"
    )
      continue;
    // Guard against providers (Statpal in particular) reporting not-yet-started
    // fixtures as "live" with a stale/fake in-progress status code. If the
    // scheduled tip-off is still more than a small clock-skew window in the
    // future, it hasn't actually started — do not show it in the live feed.
    // A fixture that was recently seen in the upcoming list (fromUpcoming) is
    // trusted to bypass a missing startTimestamp; anything else with no
    // startTimestamp at all is treated cautiously and skipped, mirroring the
    // stricter football guard.
    const fromUpcoming = hasRecentUpcomingEligibility("basketball", ev.id);
    if (ev.startTimestamp !== undefined) {
      if (ev.startTimestamp - now / 1000 > 30) continue;
    } else if (!fromUpcoming) {
      continue;
    }
    const evAgeSeconds = ev.startTimestamp
      ? now / 1000 - ev.startTimestamp
      : 0;
    // Block a fixture appearing for the first time if it's already more than
    // 20 minutes old — prevents games from suddenly entering the live section
    // already mid-game. fromUpcoming matches bypass this since they were
    // pre-announced as upcoming.
    if (
      !liveMatchState.has(`bball-v2-${ev.id}`) &&
      evAgeSeconds > 20 * 60 &&
      !fromUpcoming
    )
      continue;

    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    const hS =
      typeof ev.homeScore === "object" && ev.homeScore !== null
        ? (ev.homeScore as SAPIV2ScoreObj)
        : null;
    const aS =
      typeof ev.awayScore === "object" && ev.awayScore !== null
        ? (ev.awayScore as SAPIV2ScoreObj)
        : null;
    const homeScore = hS?.current ?? v2CurrentScore(ev.homeScore);
    const awayScore = aS?.current ?? v2CurrentScore(ev.awayScore);

    const league = v2TournName(ev.tournament);
    const country = v2TournCountry(ev);
    if (!fromUpcoming && !basketballLeagueAllowed(country, league)) continue;

    // Build quarters array from period1..4
    const quarters: Array<[number, number]> = [];
    if (hS && aS) {
      (
        [
          ["period1", "period1"],
          ["period2", "period2"],
          ["period3", "period3"],
          ["period4", "period4"],
        ] as Array<[keyof SAPIV2ScoreObj, keyof SAPIV2ScoreObj]>
      ).forEach(([hp, ap]) => {
        const h = hS[hp] as number | undefined;
        const a = aS[ap] as number | undefined;
        if ((h ?? 0) > 0 || (a ?? 0) > 0) quarters.push([h ?? 0, a ?? 0]);
      });
    }

    // Determine quarter from statusCode (13=Q1, 14=Q2, 15=Q3, 16=Q4, 17=OT, 30=Pause, 31=HT)
    const isHT = code === 31 || statusStr.toLowerCase().includes("half");
    const isPause = code === 30 || statusStr.toLowerCase() === "pause";
    const qNum =
      code === 13
        ? 1
        : code === 14
          ? 2
          : code === 15
            ? 3
            : code === 16
              ? 4
              : code === 17
                ? 5
                : quarters.length > 0
                  ? Math.max(1, quarters.length)
                  : 1;
    const minute = isHT ? 24 : isPause ? (qNum - 1) * 12 : (qNum - 1) * 12 + 6;
    const statusLabel = isHT
      ? "HT"
      : isPause
        ? `Q${Math.min(qNum, 4)}`
        : code === 17
          ? "OT"
          : `Q${Math.min(qNum, 4)}`;

    const odds = makeOddsFromTeams(homeTeam, awayTeam);
    const diff = homeScore - awayScore;
    let liveOdds = { ...odds, draw: 0 };
    if (diff !== 0) {
      // Basketball: each point ~2.5% probability swing; at 20pts lead → ~96% win chance
      const absDiff = Math.abs(diff);
      const winPct = Math.min(0.96, 0.5 + absDiff * 0.025);
      const winnerOdds = Math.max(1.04, +(0.975 / winPct).toFixed(2));
      const loserOdds = Math.min(
        50,
        +(0.975 / Math.max(0.04, 1 - winPct)).toFixed(2),
      );
      liveOdds =
        diff > 0
          ? { home: winnerOdds, draw: 0, away: loserOdds }
          : { home: loserOdds, draw: 0, away: winnerOdds };
    }

    const id = `bball-v2-${ev.id}`;
    currentIds.add(id);
    const incidentSummary = summaries.get(Number(ev.id)) ?? null;

    const prev = liveMatchState.get(id);
    let marketSuspension = prev?.marketSuspension;
    let suspensionReason = prev?._suspensionReason;

    if (marketSuspension) {
      const kept = Object.fromEntries(
        Object.entries(marketSuspension).filter(([, ts]) => ts > now),
      );
      marketSuspension = Object.keys(kept).length ? kept : undefined;
    }
    if (!marketSuspension) suspensionReason = undefined;

    const scoreChanged =
      prev != null &&
      (prev.homeScore !== homeScore || prev.awayScore !== awayScore);
    const statusChanged = prev != null && prev.status !== statusLabel;

    if (scoreChanged) {
      marketSuspension = Object.fromEntries(
        BBALL_SUSP_KEYS.map((k) => [k, now + 5_000]),
      );
      suspensionReason = "CESTA";
    } else if (statusChanged && (isHT || isPause)) {
      marketSuspension = Object.fromEntries(
        BBALL_SUSP_KEYS.map((k) => [k, now + 8_000]),
      );
      suspensionReason = "INTERVALO";
    }

    const state: LiveMatchState = {
      id,
      home: homeTeam,
      away: awayTeam,
      homeTeamId:
        typeof ev.homeTeam === "object" && ev.homeTeam?.id != null
          ? String(ev.homeTeam.id)
          : ev.homeTeamId != null
            ? String(ev.homeTeamId)
            : undefined,
      awayTeamId:
        typeof ev.awayTeam === "object" && ev.awayTeam?.id != null
          ? String(ev.awayTeam.id)
          : ev.awayTeamId != null
            ? String(ev.awayTeamId)
            : undefined,
      league,
      country,
      sport: "basketball",
      homeScore,
      awayScore,
      minute,
      status: statusLabel,
      hasRealOdds: true,
      odds: liveOdds,
      markets: makeBasketballMarketsFromTeams(homeTeam, awayTeam),
      events: (incidentSummary?.scoringEvents ?? []).slice(-12).map((it) => ({
        type: it.isThree ? "3PT" : `PTS${it.points}`,
        team: it.team,
        minute: 0,
        player: "",
      })),
      marketSuspension,
      _suspensionReason: suspensionReason,
      _firstSeenAt: prev?._firstSeenAt ?? now,
      _liveExtra:
        quarters.length > 0 || (incidentSummary?.scoringEvents.length ?? 0) > 0
          ? {
              ...(quarters.length > 0 ? { quarters } : {}),
              ...((incidentSummary?.scoringEvents.length ?? 0) > 0
                ? { basketballScoringEvents: incidentSummary!.scoringEvents }
                : {}),
            }
          : undefined,
    };
    liveMatchState.set(id, state);
    result.push(state);
  }
  for (const [id, state] of liveMatchState.entries()) {
    if (!id.startsWith("bball-v2-")) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (!currentIds.has(id) || tooOld) {
      await finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
    }
  }
  return result;
}

function buildHockeyLiveV2(events: SAPIV2Event[]): LiveMatchState[] {
  const result: LiveMatchState[] = [];
  const now = Date.now();
  const currentIds = new Set<string>();
  for (const ev of events) {
    const code = v2StatusCode(ev);
    if (code === 100 || code === 0) continue;
    const statusStr = v2StatusStr(ev.status);
    if (
      statusStr === "Not started" ||
      statusStr === "Ended" ||
      statusStr === "Finished"
    )
      continue;
    // Guard against providers (Statpal in particular) reporting not-yet-started
    // fixtures as "live" with a stale/fake in-progress status code. If the
    // scheduled puck-drop is still more than a small clock-skew window in the
    // future, it hasn't actually started — do not show it in the live feed.
    // A fixture recently seen in the upcoming list (fromUpcoming) is trusted to
    // bypass a missing startTimestamp; anything else with no startTimestamp at
    // all is treated cautiously and skipped, mirroring the stricter football guard.
    const fromUpcoming = hasRecentUpcomingEligibility("hockey", ev.id);
    if (ev.startTimestamp !== undefined) {
      if (ev.startTimestamp - now / 1000 > 30) continue;
    } else if (!fromUpcoming) {
      continue;
    }
    const evAgeSeconds = ev.startTimestamp
      ? now / 1000 - ev.startTimestamp
      : 0;
    // Block a fixture appearing for the first time if it's already more than
    // 20 minutes old — prevents games from suddenly entering the live section
    // already mid-game. fromUpcoming matches bypass this since they were
    // pre-announced as upcoming.
    if (
      !liveMatchState.has(`hockey-v2-${ev.id}`) &&
      evAgeSeconds > 20 * 60 &&
      !fromUpcoming
    )
      continue;

    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    const hS =
      typeof ev.homeScore === "object" && ev.homeScore !== null
        ? (ev.homeScore as SAPIV2ScoreObj)
        : null;
    const aS =
      typeof ev.awayScore === "object" && ev.awayScore !== null
        ? (ev.awayScore as SAPIV2ScoreObj)
        : null;
    const homeScore = hS?.current ?? v2CurrentScore(ev.homeScore);
    const awayScore = aS?.current ?? v2CurrentScore(ev.awayScore);

    const periods: Array<[number, number]> = [];
    if (hS && aS) {
      (
        ["period1", "period2", "period3", "period4"] as Array<
          keyof SAPIV2ScoreObj
        >
      ).forEach((p) => {
        const h = hS[p] as number | undefined;
        const a = aS[p] as number | undefined;
        if ((h ?? 0) > 0 || (a ?? 0) > 0) periods.push([h ?? 0, a ?? 0]);
      });
    }

    const pNum =
      code === 13
        ? 1
        : code === 14
          ? 2
          : code === 15
            ? 3
            : code === 17
              ? 4
              : periods.length > 0
                ? Math.max(1, periods.length)
                : 1;
    const isPause =
      code === 30 ||
      statusStr.toLowerCase().includes("intermission") ||
      statusStr.toLowerCase().includes("pause");
    const minute = isPause ? (pNum - 1) * 20 : (pNum - 1) * 20 + 10;
    const statusLabel = isPause
      ? `P${Math.min(pNum, 3)} Break`
      : code === 17
        ? "OT"
        : `P${Math.min(pNum, 3)}`;

    const odds = makeOddsFromTeams(homeTeam, awayTeam);
    const diff = homeScore - awayScore;
    let liveOdds = { ...odds, draw: 0 };
    if (diff !== 0) {
      // Hockey: each goal ~17% probability swing; 3+ goal lead → decisive favourite
      const absDiff = Math.abs(diff);
      const winPct = Math.min(0.97, 0.5 + absDiff * 0.17);
      const winnerOdds = Math.max(1.04, +(0.975 / winPct).toFixed(2));
      const loserOdds = Math.min(
        50,
        +(0.975 / Math.max(0.03, 1 - winPct)).toFixed(2),
      );
      liveOdds =
        diff > 0
          ? { home: winnerOdds, draw: 0, away: loserOdds }
          : { home: loserOdds, draw: 0, away: winnerOdds };
    }
    liveOdds.draw = 0;

    const id = `hockey-v2-${ev.id}`;
    currentIds.add(id);

    const prev = liveMatchState.get(id);
    let marketSuspension = prev?.marketSuspension;
    let suspensionReason = prev?._suspensionReason;

    if (marketSuspension) {
      const kept = Object.fromEntries(
        Object.entries(marketSuspension).filter(([, ts]) => ts > now),
      );
      marketSuspension = Object.keys(kept).length ? kept : undefined;
    }
    if (!marketSuspension) suspensionReason = undefined;

    const scoreChanged =
      prev != null &&
      (prev.homeScore !== homeScore || prev.awayScore !== awayScore);
    const statusChanged = prev != null && prev.status !== statusLabel;

    if (scoreChanged) {
      marketSuspension = Object.fromEntries(
        HOCKEY_SUSP_KEYS.map((k) => [k, now + 12_000]),
      );
      suspensionReason = "GOLO";
    } else if (statusChanged && isPause) {
      marketSuspension = Object.fromEntries(
        HOCKEY_SUSP_KEYS.map((k) => [k, now + 10_000]),
      );
      suspensionReason = "INTERVALO";
    } else if (statusChanged && code === 17) {
      marketSuspension = Object.fromEntries(
        HOCKEY_SUSP_KEYS.map((k) => [k, now + 10_000]),
      );
      suspensionReason = "PRORROGAÇÃO";
    }

    const state: LiveMatchState = {
      id,
      home: homeTeam,
      away: awayTeam,
      homeTeamId:
        typeof ev.homeTeam === "object" && ev.homeTeam?.id != null
          ? String(ev.homeTeam.id)
          : ev.homeTeamId != null
            ? String(ev.homeTeamId)
            : undefined,
      awayTeamId:
        typeof ev.awayTeam === "object" && ev.awayTeam?.id != null
          ? String(ev.awayTeam.id)
          : ev.awayTeamId != null
            ? String(ev.awayTeamId)
            : undefined,
      league: v2TournName(ev.tournament),
      country: v2TournCountry(ev),
      sport: "hockey",
      homeScore,
      awayScore,
      minute,
      status: statusLabel,
      hasRealOdds: true,
      odds: liveOdds,
      markets: makeHockeyMarketsFromTeams(homeTeam, awayTeam),
      events: [],
      marketSuspension,
      _suspensionReason: suspensionReason,
      _firstSeenAt: prev?._firstSeenAt ?? now,
      _liveExtra: periods.length > 0 ? { periods } : undefined,
    };
    liveMatchState.set(id, state);
    result.push(state);
  }
  for (const [id, state] of liveMatchState.entries()) {
    if (!id.startsWith("hockey-v2-")) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (!currentIds.has(id) || tooOld) {
      void finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
    }
  }
  return result;
}

function buildBaseballLiveV2(events: SAPIV2Event[]): LiveMatchState[] {
  const result: LiveMatchState[] = [];
  const now = Date.now();
  const currentIds = new Set<string>();
  for (const ev of events) {
    const code = v2StatusCode(ev);
    const statusStr = v2StatusStr(ev.status);
    const statusType =
      typeof ev.status === "object" ? (ev.status as SAPIV2StatusObj).type : "";
    if (code === 100 || statusStr === "Ended" || statusStr === "Finished")
      continue;
    if (
      statusType !== "inprogress" &&
      !statusStr.toLowerCase().includes("inning") &&
      !statusStr.toLowerCase().includes("progress")
    )
      continue;
    // Guard against providers (Statpal in particular) reporting not-yet-started
    // fixtures as "live" with a stale/fake in-progress status. If the
    // scheduled first pitch is still more than a small clock-skew window in
    // the future, it hasn't actually started — do not show it in the live feed.
    // A fixture recently seen in the upcoming list (fromUpcoming) is trusted to
    // bypass a missing startTimestamp; anything else with no startTimestamp at
    // all is treated cautiously and skipped, mirroring the stricter football guard.
    const fromUpcoming = hasRecentUpcomingEligibility("baseball", ev.id);
    if (ev.startTimestamp !== undefined) {
      if (ev.startTimestamp - now / 1000 > 30) continue;
    } else if (!fromUpcoming) {
      continue;
    }
    const evAgeSeconds = ev.startTimestamp
      ? now / 1000 - ev.startTimestamp
      : 0;
    // Block a fixture appearing for the first time if it's already more than
    // 20 minutes old — prevents games from suddenly entering the live section
    // already mid-game. fromUpcoming matches bypass this since they were
    // pre-announced as upcoming.
    if (
      !liveMatchState.has(`baseball-v2-${ev.id}`) &&
      evAgeSeconds > 20 * 60 &&
      !fromUpcoming
    )
      continue;

    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    const hS =
      typeof ev.homeScore === "object" && ev.homeScore !== null
        ? (ev.homeScore as SAPIV2ScoreObj)
        : null;
    const aS =
      typeof ev.awayScore === "object" && ev.awayScore !== null
        ? (ev.awayScore as SAPIV2ScoreObj)
        : null;
    const homeScore = hS?.current ?? v2CurrentScore(ev.homeScore);
    const awayScore = aS?.current ?? v2CurrentScore(ev.awayScore);

    // Extract innings from inning1..inning9
    const innings: Array<[number, number]> = [];
    if (hS?.innings && aS?.innings) {
      for (let i = 1; i <= 12; i++) {
        const hRun = hS.innings[`inning${i}`]?.run;
        const aRun = aS.innings[`inning${i}`]?.run;
        if (
          hRun !== undefined &&
          hRun !== null &&
          aRun !== undefined &&
          aRun !== null
        ) {
          innings.push([hRun, aRun]);
        } else break;
      }
    }

    const league = v2TournName(ev.tournament);
    const odds = makeBaseballBaseOdds(homeTeam, awayTeam);
    const diff = homeScore - awayScore;
    let liveOdds = { ...odds, draw: 0 };
    if (diff !== 0) {
      // Baseball: each run ~14% probability swing; 5+ run lead → decisive favourite
      const absDiff = Math.abs(diff);
      const winPct = Math.min(0.97, 0.5 + absDiff * 0.14);
      const winnerOdds = Math.max(1.04, +(0.975 / winPct).toFixed(2));
      const loserOdds = Math.min(
        50,
        +(0.975 / Math.max(0.03, 1 - winPct)).toFixed(2),
      );
      liveOdds =
        diff > 0
          ? { home: winnerOdds, draw: 0, away: loserOdds }
          : { home: loserOdds, draw: 0, away: winnerOdds };
    }

    const id = `baseball-v2-${ev.id}`;
    currentIds.add(id);

    const prev = liveMatchState.get(id);
    let marketSuspension = prev?.marketSuspension;
    let suspensionReason = prev?._suspensionReason;

    if (marketSuspension) {
      const kept = Object.fromEntries(
        Object.entries(marketSuspension).filter(([, ts]) => ts > now),
      );
      marketSuspension = Object.keys(kept).length ? kept : undefined;
    }
    if (!marketSuspension) suspensionReason = undefined;

    const scoreChanged =
      prev != null &&
      (prev.homeScore !== homeScore || prev.awayScore !== awayScore);
    const prevInningsLen = prev?._liveExtra?.innings?.length ?? 0;
    const inningChanged = prev != null && prevInningsLen !== innings.length;

    if (scoreChanged) {
      marketSuspension = Object.fromEntries(
        BASEBALL_SUSP_KEYS.map((k) => [k, now + 12_000]),
      );
      suspensionReason = "RUN";
    } else if (inningChanged) {
      marketSuspension = Object.fromEntries(
        BASEBALL_SUSP_KEYS.map((k) => [k, now + 10_000]),
      );
      suspensionReason = "TROCA DE INNING";
    }

    const state: LiveMatchState = {
      id,
      home: homeTeam,
      away: awayTeam,
      homeTeamId:
        typeof ev.homeTeam === "object" && ev.homeTeam?.id != null
          ? String(ev.homeTeam.id)
          : ev.homeTeamId != null
            ? String(ev.homeTeamId)
            : undefined,
      awayTeamId:
        typeof ev.awayTeam === "object" && ev.awayTeam?.id != null
          ? String(ev.awayTeam.id)
          : ev.awayTeamId != null
            ? String(ev.awayTeamId)
            : undefined,
      league,
      country: v2TournCountry(ev),
      sport: "baseball",
      homeScore,
      awayScore,
      minute: innings.length,
      status: statusStr,
      hasRealOdds: true,
      odds: liveOdds,
      markets: makeMLBMarketsFromTeams(homeTeam, awayTeam),
      events: [],
      marketSuspension,
      _suspensionReason: suspensionReason,
      _firstSeenAt: prev?._firstSeenAt ?? now,
      _liveExtra: innings.length > 0 ? { innings } : undefined,
    };
    liveMatchState.set(id, state);
    result.push(state);
  }
  for (const [id, state] of liveMatchState.entries()) {
    if (!id.startsWith("baseball-v2-")) continue;
    const tooOld = now - (state._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (!currentIds.has(id) || tooOld) {
      void finalizeStaleLiveMatch(state);
      liveMatchState.delete(id);
    }
  }
  return result;
}

function rememberFinishedTennisState(
  id: string,
  state: LiveMatchState,
  finishedAt: number,
): void {
  finishedMatchResults.set(id, {
    home: state.homeScore,
    away: state.awayScore,
    homeTeam: state.home,
    awayTeam: state.away,
    extras: state._liveExtra?.sets
      ? {
          tennis: {
            sets: state._liveExtra.sets,
            currentPoints: state._liveExtra.currentPoints,
          },
        }
      : undefined,
    finishedAt,
  });
  void persistFinishedMatchRecord(id, "tennis", {
    home: state.homeScore,
    away: state.awayScore,
    status: "finished",
    homeTeam: state.home,
    awayTeam: state.away,
    extras: state._liveExtra?.sets
      ? {
          tennis: {
            sets: state._liveExtra.sets,
            currentPoints: state._liveExtra.currentPoints,
          },
        }
      : undefined,
    finishedAt,
  });
  void enqueueMatchSettlement({
    matchId: id,
    jobId: buildMatchSettlementJobId({
      matchId: id,
      home: state.homeScore,
      away: state.awayScore,
    }),
  });
}

/**
 * Returns the appropriate market suspension duration (ms) for a tennis point.
 * Based on real sportsbook behaviour: longer suspension at high-pressure moments.
 *   - Match point               → 25 s
 *   - Set point + break point   → 18 s
 *   - Set point alone           → 15 s
 *   - Break point (0/15/30-40)  → 12 s
 *   - Deuce / Advantage         → 10 s
 *   - Tie-break point           → 12 s
 *   - Normal point              →  5 s
 */
function tennisSuspensionMs(
  pts: [number | string, number | string],
  sets: Array<[number, number]>,
  homeSets: number,
  awaySets: number,
): number {
  const h = String(pts[0]);
  const a = String(pts[1]);

  // Deuce / Advantage situations
  const isDeuce = h === "40" && a === "40";
  const isAdv = h === "AD" || a === "AD";

  // Break-point: one side has "40" while the other is behind (0/15/30)
  const isBreakPoint =
    (h === "40" && (a === "0" || a === "15" || a === "30")) ||
    (a === "40" && (h === "0" || h === "15" || h === "30"));

  // Tie-break: both players have 6 games in the current set
  const currentSet = sets[sets.length - 1] ?? [0, 0];
  const isTiebreak = currentSet[0] === 6 && currentSet[1] === 6;

  // Set point: one player is at 5 or 6 games and ahead of the other
  // (crude heuristic — good enough for suspension timing)
  const isSetPoint =
    !isTiebreak &&
    ((currentSet[0] >= 5 && currentSet[0] > currentSet[1]) ||
      (currentSet[1] >= 5 && currentSet[1] > currentSet[0]));

  // Match point (best-of-3 assumption): only treat as match point when a player
  // is one set away AND this is effectively a set-point situation.
  const setsNeeded = 2;
  const oneSetAway = homeSets === setsNeeded - 1 || awaySets === setsNeeded - 1;
  const isMatchPoint = oneSetAway && (isSetPoint || isTiebreak);

  if (isMatchPoint && (isBreakPoint || isAdv)) return 25_000;
  if (isMatchPoint) return 20_000;
  if (isSetPoint && isBreakPoint) return 18_000;
  if (isSetPoint) return 15_000;
  if (isBreakPoint) return 12_000;
  if (isTiebreak) return 12_000;
  if (isAdv || isDeuce) return 10_000;
  return 5_000;
}

// Tennis market keys to suspend after each point (flat keys used by frontend)
const TENNIS_SUSP_KEYS = [
  "result",
  "firstSet",
  "set2",
  "set3",
  "exactSets",
  "totalGames",
  "gameHandicap",
  "setHandicap",
  "set1Games",
] as const;

// Grace-period tracker: ms when a tennis match first disappeared from the live feed.
// Prevents transient feed gaps from causing matches to flicker out of the UI.
const _tennisMissingFrom = new Map<string, number>();

function buildTennisLiveV2(events: SAPIV2Event[]): LiveMatchState[] {
  const now = Date.now();
  const result: LiveMatchState[] = [];
  const currentIds = new Set<string>();
  const seenIds = new Set<number>();
  const seenPairs = new Set<string>();
  // Kick off background live-odds refresh for all valid match IDs (fire-and-forget)
  const liveIds = events.map((e) => e.id).filter(Boolean) as number[];
  refreshTennisLiveOdds(liveIds);
  refreshTennisServing(liveIds);
  const nowSec = now / 1000;
  // Sort descending by status code so that when the same match pair appears twice,
  // the more-advanced (higher code = later set) entry is processed first and wins the dedup.
  const sorted = [...events].sort(
    (a, b) => (v2StatusCode(b) ?? 0) - (v2StatusCode(a) ?? 0),
  );
  for (const ev of sorted) {
    // Deduplicate by event ID (API sometimes returns the same event twice)
    if (seenIds.has(ev.id)) continue;
    seenIds.add(ev.id);
    // ATP/WTA/Challenger/WTA-125 + ITF singles; excludes doubles/wheelchair/UTR/juniors
    // isTennisElite also checks player names for " / " (doubles pair indicator)
    if (!isTennisElite(ev)) continue;
    // Only show ATP/WTA/Grand Slam — exclude Challengers, ITF, WTA-125
    const v2LeagueLabel = tennisTournLabel(ev.tournament);
    const isMainTourLabel =
      v2LeagueLabel.startsWith("ATP") ||
      v2LeagueLabel.startsWith("WTA") ||
      v2LeagueLabel.startsWith("Grand Slam");
    const rawTournText = tennisTournamentSearchText(
      ev.tournament,
    ).toLowerCase();
    const isMainTourRaw =
      rawTournText.includes("wta") ||
      rawTournText.includes("atp") ||
      rawTournText.includes("grand slam") ||
      rawTournText.includes("wimbledon") ||
      rawTournText.includes("roland") ||
      rawTournText.includes("australian") ||
      rawTournText.includes("us open");
    if (!isMainTourLabel && !isMainTourRaw) continue;
    // finalResultOnly=true means the API is only showing the final score → match ended
    if (ev.finalResultOnly === true) continue;
    // Also deduplicate by player pair (API can return same match with different IDs).
    // Keep the entry with the HIGHER status code (later in the match = more authoritative).
    const h = v2TeamName(ev.homeTeam).toLowerCase();
    const a = v2TeamName(ev.awayTeam).toLowerCase();
    const pairKey = `${h}|${a}`;
    if (seenPairs.has(pairKey)) continue;
    seenPairs.add(pairKey);
    const id = `tennis-v2-${ev.id}`;
    currentIds.add(id);
    const existing = liveMatchState.get(id);
    const code = v2StatusCode(ev);
    const statusStr = v2StatusStr(ev.status);
    // Skip matches that are definitively not live
    const sLow = statusStr.toLowerCase();
    const notLive =
      code === 100 || // finished (SportsApiPro code)
      code === 110 || // postponed
      code === 120 || // abandoned
      (code === 0 &&
        (sLow === "" ||
          sLow.includes("not start") ||
          sLow.includes("schedul"))) ||
      sLow.includes("ended") ||
      sLow.includes("finished") ||
      sLow.includes("complete") ||
      sLow.includes("not start") ||
      sLow.includes("postpone") ||
      sLow.includes("cancel") ||
      sLow.includes("walkover") ||
      sLow.includes("retired") ||
      sLow.includes("abandon") ||
      sLow.includes("awarded") ||
      sLow.includes("default");
    const matchAgeSeconds =
      ev.startTimestamp !== undefined ? nowSec - ev.startTimestamp : 0;
    // Zombie detection: match claims to be in progress but started too long ago.
    // Tennis best-of-3 ≤ ~3h; best-of-5 ≤ ~5h. If still "playing" after 4h, the
    // API is stuck — treat as finished and skip.
    const isZombie =
      matchAgeSeconds > 4 * 3600 &&
      (code === 8 ||
        code === 9 ||
        code === 10 ||
        sLow.includes("set") ||
        sLow.includes("playing") ||
        sLow.includes("progress"));
    if (isZombie) continue;
    if (notLive) continue;
    const fromUpcoming = hasRecentUpcomingEligibility("tennis", ev.id);
    if (
      !existing &&
      !fromUpcoming &&
      ev.startTimestamp !== undefined &&
      matchAgeSeconds > 5 * 60
    )
      continue;
    // Accept everything else: "Playing", "1st Set", "2nd Set", "In Progress",
    // "Break Time", "Advantage", "Tiebreak", "Suspended", "Paused", etc.

    const homeTeam = v2TeamName(ev.homeTeam);
    const awayTeam = v2TeamName(ev.awayTeam);
    const hS =
      typeof ev.homeScore === "object" && ev.homeScore !== null
        ? (ev.homeScore as SAPIV2ScoreObj)
        : null;
    const aS =
      typeof ev.awayScore === "object" && ev.awayScore !== null
        ? (ev.awayScore as SAPIV2ScoreObj)
        : null;
    const homeScore = hS?.current ?? v2CurrentScore(ev.homeScore);
    const awayScore = aS?.current ?? v2CurrentScore(ev.awayScore);

    // Build sets from period1..5
    const sets: Array<[number, number]> = [];
    if (hS && aS) {
      (
        ["period1", "period2", "period3", "period4", "period5"] as Array<
          keyof SAPIV2ScoreObj
        >
      ).forEach((p) => {
        const h = hS[p] as number | undefined;
        const a = aS[p] as number | undefined;
        if (h !== undefined && a !== undefined) sets.push([h, a]);
      });
    }

    // ── Game score: use real point score from API when available ───────────────
    // hS.point / aS.point = "0" | "15" | "30" | "40" | "AD" — provided by V2 live
    const parsePoint = (p: string | undefined): number | string => {
      if (p === undefined) return 0;
      if (p === "AD") return "AD";
      const n = parseInt(p, 10);
      return isNaN(n) ? p : n; // pass through "15", "30", "40" as numbers; "D"/"A" as string
    };
    const realHPt = hS?.point;
    const realAPt = aS?.point;
    const currentPoints: [number | string, number | string] =
      realHPt !== undefined && realAPt !== undefined
        ? [parsePoint(realHPt), parsePoint(realAPt)]
        : advanceTennisGamePts(`tennis-v2-${ev.id}`);

    const serving =
      (ev.id ? _tennisServingCache.get(ev.id)?.serving : undefined) ??
      existing?._liveExtra?.serving;

    // ── Odds: prefer real bookmaker live odds (from cache), else fall back to
    //    a reactive model that responds to sets, current-set games and points. ──
    const realLiveOdds = ev.id ? _tennisLiveOddsCache.get(ev.id) : undefined;
    const preMatchPairKey = _tennisPairKey(homeTeam, awayTeam);
    const cachedSetScoreOdds = _tennisPreMatchSetScoreOdds.get(preMatchPairKey);
    const baseOdds = makeTennisBaseOdds(homeTeam, awayTeam);
    const liveOddsState = computeTennisLiveOdds(
      baseOdds,
      sets,
      homeScore,
      awayScore,
      currentPoints,
      serving,
      realLiveOdds,
    );
    const liveOdds = liveOddsState.odds;

    // ── Market suspension: detect point played and compute duration ─────────────
    // A point is played when currentPoints or sets changes compared to last tick.
    // Guard: buildTennisLiveV2 is called TWICE per request (live feed + todayStarted).
    // The 2nd call sees state just saved by the 1st and would falsely detect a point.
    // Only treat a change as a real point if the state was saved > 1.5 s ago (= previous poll).
    const prevPoints = existing?._liveExtra?.currentPoints;
    const prevSets = existing?._liveExtra?.sets;
    const lastTennisUpdate = existing?._oddsUpdatedAt ?? 0;
    const isDifferentPollCycle = now - lastTennisUpdate > 1500;
    const pointPlayed =
      isDifferentPollCycle &&
      prevPoints !== undefined &&
      (JSON.stringify(prevPoints) !== JSON.stringify(currentPoints) ||
        JSON.stringify(prevSets) !== JSON.stringify(sets));

    // Settled set markets: permanently suspend once a set is done
    const doneSets = sets.filter(([h, a]) => {
      const maxG = Math.max(h, a);
      const minG = Math.min(h, a);
      return (maxG >= 6 && maxG - minG >= 2) || maxG === 7;
    }).length;
    const currentSetNum = Math.max(1, Math.min(3, doneSets + 1));
    const SETTLED = now + 30 * 24 * 60 * 60 * 1000;
    const settledSusp: Record<string, number> = {};
    const phaseHoldSusp: Record<string, number> = {};
    if (doneSets >= 1) settledSusp["firstSet"] = SETTLED;
    if (doneSets >= 2) settledSusp["set2"] = SETTLED;
    if (currentSetNum < 2) phaseHoldSusp["set2"] = SETTLED;
    if (currentSetNum < 3) phaseHoldSusp["set3"] = SETTLED;

    let marketSuspension: Record<string, number> | undefined =
      existing?.marketSuspension
        ? Object.fromEntries(
            Object.entries(existing.marketSuspension).filter(([key, ts]) => {
              if (ts <= now) return false;
              if (
                (key === "set2" || key === "set3") &&
                ts > now + 60 * 60 * 1000 &&
                settledSusp[key] === undefined &&
                phaseHoldSusp[key] === undefined
              ) {
                return false;
              }
              return true;
            }),
          )
        : undefined;
    // Merge settled set suspensions (these are permanent — never expire)
    if (
      Object.keys(settledSusp).length > 0 ||
      Object.keys(phaseHoldSusp).length > 0
    ) {
      marketSuspension = {
        ...(marketSuspension ?? {}),
        ...settledSusp,
        ...phaseHoldSusp,
      };
    }

    let suspensionReason = existing?._suspensionReason;

    if (pointPlayed) {
      const suspMs = tennisSuspensionMs(
        currentPoints,
        sets,
        homeScore,
        awayScore,
      );
      if (suspMs > 0) {
        const pointSusp = Object.fromEntries(
          TENNIS_SUSP_KEYS.map((k) => [k, now + suspMs]),
        );
        // Merge: settled markets keep their permanent timestamp; point suspension overrides temporary ones
        marketSuspension = {
          ...(marketSuspension ?? {}),
          ...pointSusp,
          ...settledSusp,
          ...phaseHoldSusp,
        };
        suspensionReason = "PONTO EM JOGO";
      }
    } else if (marketSuspension && Object.keys(marketSuspension).length === 0) {
      marketSuspension = undefined;
      suspensionReason = undefined;
    } else if (!pointPlayed && suspensionReason === "PONTO EM JOGO") {
      // Suspension has expired — clear the reason
      const active = marketSuspension
        ? Object.entries(marketSuspension).filter(
            ([k, ts]) => ts > now && settledSusp[k] === undefined,
          )
        : [];
      suspensionReason = active.length > 0 ? suspensionReason : undefined;
    }

    const displayStatus = statusStr;

    // ── Tennis live markets for V2 matches ────────────────────────────────────
    const v2HomeP =
      liveOdds.home > 0 && liveOdds.away > 0
        ? 1 / liveOdds.home / (1 / liveOdds.home + 1 / liveOdds.away)
        : 0.5;
    const v2TennisExtra = computeLiveTennisExtras(
      v2HomeP,
      sets,
      homeScore,
      awayScore,
      currentSetNum,
      currentPoints,
      serving,
    );

    const v2Markets = {
      ...makeAdvancedMarketsFromTeams(homeTeam, awayTeam),
      tennisExtra: v2TennisExtra,
    } as unknown as AdvancedMarkets;

    const state: LiveMatchState = {
      id,
      home: homeTeam,
      away: awayTeam,
      homeTeamId:
        typeof ev.homeTeam === "object" && ev.homeTeam?.id != null
          ? String(ev.homeTeam.id)
          : ev.homeTeamId != null
            ? String(ev.homeTeamId)
            : undefined,
      awayTeamId:
        typeof ev.awayTeam === "object" && ev.awayTeam?.id != null
          ? String(ev.awayTeam.id)
          : ev.awayTeamId != null
            ? String(ev.awayTeamId)
            : undefined,
      league: tennisTournLabel(ev.tournament),
      country: v2TournCountry(ev),
      sport: "tennis",
      homeScore,
      awayScore,
      minute: currentSetNum * 20,
      status: displayStatus,
      hasRealOdds: liveOddsState.hasRealOdds,
      odds: liveOdds,
      markets: v2Markets,
      events: [],
      _firstSeenAt: existing?._firstSeenAt ?? now,
      _liveExtra: {
        sets: sets.length > 0 ? sets : [],
        currentPoints,
        ...(serving ? { serving } : {}),
      },
      marketSuspension:
        marketSuspension && Object.keys(marketSuspension).length > 0
          ? marketSuspension
          : undefined,
      _suspensionReason: suspensionReason,
    };
    liveMatchState.set(id, state);
    result.push(state);
  }

  // Garbage collect tennis states no longer in the feed.
  // Grace period of 45 s: transient feed gaps (Tyler/Challenger matches that briefly
  // disappear between polls) don't cause the match to vanish from the UI.
  for (const id of liveMatchState.keys()) {
    if (!id.startsWith("tennis-v2-") && !id.startsWith("tennis-v1-")) continue;
    const cached = liveMatchState.get(id);
    if (!cached) {
      _tennisMissingFrom.delete(id);
      continue;
    }
    const tooOld = now - (cached._firstSeenAt ?? now) > MAX_LIVE_STATE_MS;
    if (tooOld) {
      rememberFinishedTennisState(id, cached, now);
      liveMatchState.delete(id);
      _tennisMissingFrom.delete(id);
      continue;
    }
    if (!currentIds.has(id)) {
      const firstMissing = _tennisMissingFrom.get(id) ?? now;
      _tennisMissingFrom.set(id, firstMissing);
      if (now - firstMissing > 45_000) {
        rememberFinishedTennisState(id, cached, now);
        liveMatchState.delete(id);
        _tennisMissingFrom.delete(id);
      } else {
        // Within grace period: only include in result for the first 8 s of the gap.
        // This covers transient feed blips (1-4 polls) without surfacing finished matches
        // that have permanently left the feed.  State is retained for the full 45 s so
        // we can resume accurately if the match genuinely returns.
        const finished = isTennisFinishedStatusText(cached.status);
        if (finished) {
          rememberFinishedTennisState(id, cached, now);
          liveMatchState.delete(id);
          _tennisMissingFrom.delete(id);
        } else if (now - firstMissing < 8_000) {
          result.push(cached);
        }
      }
    } else {
      _tennisMissingFrom.delete(id); // back in feed — reset grace timer
    }
  }

  return result;
}

// ─── Per-match cycling game score — simulation fallback ──────────────────────
// V2 API DOES provide point scores via homeScore.point / awayScore.point
// ("0"|"15"|"30"|"40"|"A"). buildTennisLiveV2 uses real API values when present
// and falls back to this simulation only when the field is missing (e.g. ITF
// matches where the API sometimes omits the point field).

type TennisGamePtState = { h: number; a: number; lastAdvance: number };
const _tennisGamePts = new Map<string, TennisGamePtState>();

function advanceTennisGamePts(
  matchId: string,
): [number | string, number | string] {
  const now = Date.now();
  let st = _tennisGamePts.get(matchId);
  if (!st) {
    // Stagger starting points per match to avoid all matches syncing
    const seed = matchId.split("").reduce((s, c) => s + c.charCodeAt(0), 0);
    st = { h: seed % 3, a: (seed >> 2) % 3, lastAdvance: now - (seed % 5000) };
    _tennisGamePts.set(matchId, st);
  }
  if (now - st.lastAdvance >= 5_000) {
    // Award next point (slight home bias from hash)
    const seed = matchId.split("").reduce((s, c) => s + c.charCodeAt(0), 0);
    const homeP = 0.45 + (seed % 11) / 100;
    if (Math.random() < homeP) st.h++;
    else st.a++;
    // Game over when one player reaches 4+ with ≥2 gap (or 5+)
    const gameOver =
      (st.h >= 4 && st.h - st.a >= 2) ||
      (st.a >= 4 && st.a - st.h >= 2) ||
      st.h >= 5 ||
      st.a >= 5;
    if (gameOver) {
      st.h = 0;
      st.a = 0;
    }
    st.lastAdvance = now;
  }
  const toDisplay = (n: number): number | string => {
    if (n === 0) return 0;
    if (n === 1) return 15;
    if (n === 2) return 30;
    return 40;
  };
  // Deuce / advantage
  if (st.h >= 3 && st.a >= 3) {
    if (st.h === st.a) return ["D", "D"];
    return st.h > st.a ? ["AD", 40] : [40, "AD"];
  }
  return [toDisplay(st.h), toDisplay(st.a)];
}

// ─── Tennis simulation — fallback when V2 live + today both return empty ───────
//
// Maintains 2 persistent in-memory matches that advance their scores over time.
// Scores drift every ~8s (one game), sets are best-of-3. Match resets when
// a player reaches 2 sets. This only activates as a last resort; whenever real
// V2 data is available, buildTennisLiveV2 takes priority.

type TennisSimState = {
  homeScore: number;
  awayScore: number;
  sets: Array<[number, number]>;
  setNum: number;
  updatedAt: number;
  seed: number; // deterministic bias so one player "leads"
};

const _tennisSimMap = new Map<string, TennisSimState>();

const TENNIS_SIM_PLAYERS: Array<{
  home: string;
  away: string;
  tournament: string;
  country: string;
}> = [
  {
    home: "C. Alcaraz",
    away: "H. Hurkacz",
    tournament: "Roland Garros",
    country: "France",
  },
  {
    home: "I. Swiatek",
    away: "A. Sabalenka",
    tournament: "Roland Garros",
    country: "France",
  },
];

function _advanceTennisSim(id: string, idx: number): TennisSimState {
  const now = Date.now();
  const existing = _tennisSimMap.get(id);
  if (!existing) {
    const st: TennisSimState = {
      homeScore: 0,
      awayScore: 0,
      sets: [[idx === 0 ? 2 : 1, idx === 0 ? 1 : 3]], // start mid-set
      setNum: 1,
      updatedAt: now,
      seed: 0.52 + idx * 0.04,
    };
    _tennisSimMap.set(id, st);
    return st;
  }
  if (now - existing.updatedAt < 8_000) return existing;

  const st: TennisSimState = {
    ...existing,
    sets: existing.sets.map((s) => [s[0], s[1]] as [number, number]),
  };
  st.updatedAt = now;

  // Advance one game in the current set
  const homeWins = Math.random() < st.seed;
  const cur = st.sets[st.sets.length - 1]!;
  if (homeWins) cur[0]++;
  else cur[1]++;

  const h = cur[0],
    a = cur[1];
  const setWonByHome = (h >= 6 && h - a >= 2) || h === 7;
  const setWonByAway = (a >= 6 && a - h >= 2) || a === 7;
  if (setWonByHome) {
    st.homeScore++;
    if (st.homeScore < 2) {
      st.sets.push([0, 0]);
      st.setNum++;
    }
  } else if (setWonByAway) {
    st.awayScore++;
    if (st.awayScore < 2) {
      st.sets.push([0, 0]);
      st.setNum++;
    }
  }

  // Reset when match is over (best of 3 = 2 sets)
  if (st.homeScore >= 2 || st.awayScore >= 2) {
    st.homeScore = 0;
    st.awayScore = 0;
    st.sets = [[0, 0]];
    st.setNum = 1;
  }

  _tennisSimMap.set(id, st);
  return st;
}

function buildTennisSimulation(): LiveMatchState[] {
  return TENNIS_SIM_PLAYERS.map(({ home, away, tournament, country }, idx) => {
    const id = `tennis-sim-${idx}`;
    const st = _advanceTennisSim(id, idx);
    const odds = makeOddsFromTeams(home, away);
    const diff = st.homeScore - st.awayScore;
    let liveOdds = { ...odds, draw: 0 };
    if (diff !== 0) {
      const factor = Math.min(0.55, Math.abs(diff) * 0.22);
      liveOdds =
        diff > 0
          ? {
              home: Math.max(1.01, +(odds.home * (1 - factor)).toFixed(2)),
              draw: 0,
              away: Math.min(50, +(odds.away * (1 + factor)).toFixed(2)),
            }
          : {
              home: Math.min(50, +(odds.home * (1 + factor)).toFixed(2)),
              draw: 0,
              away: Math.max(1.01, +(odds.away * (1 - factor)).toFixed(2)),
            };
    }
    const currentPoints = advanceTennisGamePts(id);
    return {
      id,
      home,
      away,
      league: tournament,
      country,
      sport: "tennis" as const,
      homeScore: st.homeScore,
      awayScore: st.awayScore,
      minute: st.setNum * 20,
      status: `Set ${st.setNum}`,
      hasRealOdds: false,
      odds: liveOdds,
      markets: makeAdvancedMarketsFromTeams(home, away),
      events: [],
      _liveExtra: { sets: st.sets, currentPoints },
    };
  });
}

// ─── Routes ───────────────────────────────────────────────────────────────────

// ── Upcoming matches cache (Em Breve section) ─────────────────────────────────
// Upcoming matches change slowly (every few minutes), so we cache them for 30s.
// Live score data is always rebuilt fresh (pure in-memory, sub-millisecond).
// This means a V1 score patch triggers a broadcast in ~5ms instead of ~200ms.
let _allUpcomingCache: UpcomingMatch[] = [];
let _allUpcomingCacheBuiltAt = 0;
const UPCOMING_CACHE_TTL_MS = 30_000;
let _upcomingRebuildInProgress = false;

/**
 * Normalise a team/player name for fuzzy lookup (lowercase, alphanumeric only).
 */
function _normTeam(n: string): string {
  return n.toLowerCase().replace(/[^a-z0-9]/g, "");
}

/**
 * Look up real V5 pre-match 1x2 odds for a football match in the upcoming
 * cache (rebuilt every 30 s).  Returns null when not found.
 * Used as a fallback between the bookmaker odds API and the ELO/Poisson model
 * so club teams not in the ELO table (e.g. Bodø/Glimt, KFUM Oslo) get
 * sensible, market-based prices instead of arbitrary hash-ELO values.
 */
function getUpcomingPreMatchOdds(
  home: string,
  away: string,
): { home: number; draw: number; away: number } | null {
  if (_allUpcomingCache.length === 0) return null;
  const hn = _normTeam(home);
  const an = _normTeam(away);
  for (const m of _allUpcomingCache) {
    if (!m.hasRealOdds) continue;
    if (m.sport !== "football") continue;
    if (
      _normTeam(m.home) === hn &&
      _normTeam(m.away) === an &&
      m.odds.home > 1.01 &&
      m.odds.draw > 1.01 &&
      m.odds.away > 1.01
    ) {
      return { home: m.odds.home, draw: m.odds.draw, away: m.odds.away };
    }
  }
  return null;
}

async function rebuildUpcomingCache(): Promise<void> {
  if (_upcomingRebuildInProgress) return;
  _upcomingRebuildInProgress = true;
  const empty: UpcomingMatch[] = [];
  try {
    // Fetch tennis odds first so refreshTennisV2LeagueCache populates city→ATP/WTA tier labels
    // before buildTennisUpcoming() runs (enrichTennisV1League depends on the cache).
    const tennisOdds = await getTennisOdds().catch(
      () => [] as TennisOddsEntry[],
    );
    const [
      upFootball,
      upTennisBase,
      upBasketball,
      upHockey,
      upVolleyball,
      upBaseball,
      upMma,
      upCricket,
      upHandball,
      upFormula1,
      // V5 prematch events — fetched in parallel, merged below
      v5Football,
      v5Basketball,
      v5Hockey,
      v5Tennis,
      v5Baseball,
      v5Volleyball,
    ] = await Promise.all([
      buildUpcomingMatches().catch(() => empty),
      buildTennisUpcoming().catch(() => empty),
      buildBasketballUpcoming().catch(() => empty),
      buildHockeyUpcoming().catch(() => empty),
      buildVolleyballUpcoming().catch(() => empty),
      buildBaseballUpcoming().catch(() => empty),
      getExtraUpcomingEventsV2("boxing").then((events) => buildExtraUpcomingV2("boxing", events)).catch(() => empty),
      getExtraUpcomingEventsV2("cricket").then((events) => buildExtraUpcomingV2("cricket", events)).catch(() => empty),
      getExtraUpcomingEventsV2("handball").then((events) => buildExtraUpcomingV2("handball", events)).catch(() => empty),
      getFormula1Upcoming().catch(() => empty),
      // V5 — 1xBet prematch feed (real odds: 1x2 + DC + totals + BTTS + DNB + handicap)
      buildV5Upcoming(1, 200).catch(() => empty), // football
      buildV5Upcoming(3, 100).catch(() => empty), // basketball
      buildV5Upcoming(2, 80).catch(() => empty),  // hockey
      buildV5Upcoming(4, 80).catch(() => empty),  // tennis
      buildV5Upcoming(5, 80).catch(() => empty),  // baseball
      buildV5Upcoming(6, 60).catch(() => empty),  // volleyball
    ]);
    const upTennis = mergeTennisUpcomingSources(
      upTennisBase,
      buildTennisUpcomingFromOddsEntries(tennisOdds),
    );

    // Merge V5 events into each sport's V1 list
    // — matching events get real V5 odds injected
    // — new V5-only events are appended
    const finalFootball   = mergeV5IntoUpcoming(upFootball,   v5Football);
    const finalBasketball = mergeV5IntoUpcoming(upBasketball, v5Basketball);
    const finalHockey     = mergeV5IntoUpcoming(upHockey,     v5Hockey);
    const finalTennis     = mergeV5IntoUpcoming(upTennis,     v5Tennis);
    const finalBaseball   = mergeV5IntoUpcoming(upBaseball,   v5Baseball);
    const finalVolleyball = mergeV5IntoUpcoming(upVolleyball, v5Volleyball);

    rememberUpcomingFootballEligibility(finalFootball);
    rememberUpcomingEligibility([
      ...finalFootball,
      ...finalTennis,
      ...finalBasketball,
      ...finalHockey,
      ...finalVolleyball,
      ...finalBaseball,
      ...upMma,
      ...upCricket,
      ...upHandball,
      ...upFormula1,
    ]);
    // Upcoming order: Futebol → Ténis → Hóquei → Basquete → Voleibol → Beisebol → outros
    _allUpcomingCache = [
      ...finalFootball,
      ...finalTennis,
      ...finalHockey,
      ...finalBasketball,
      ...finalVolleyball,
      ...finalBaseball,
      ...upMma,
      ...upCricket,
      ...upHandball,
      ...upFormula1,
    ];
    _allUpcomingCacheBuiltAt = Date.now();
  } catch {
    /* keep stale */
  } finally {
    _upcomingRebuildInProgress = false;
  }
}

// Shared payload builder — used by both /live HTTP route and SSE broadcast
async function buildLivePayload(): Promise<{ matches: LiveMatchState[] }> {
  const now = Date.now();
  // Warm the upcoming cache in the background — never block the live path.
  // On cold start the cache is empty; upcoming-based fallbacks simply won't fire
  // until the first background rebuild completes (~1-2 s later).
  if (
    _allUpcomingCacheBuiltAt === 0 ||
    Date.now() - _allUpcomingCacheBuiltAt > UPCOMING_CACHE_TTL_MS
  ) {
    rebuildUpcomingCache().catch(() => {});
  }
  const allUpcoming = _allUpcomingCache;

  // ── Fast path: live data from in-memory WS caches (sub-ms each) ──────────
  const [
    footballEvents,
    basketballEvents,
    hockeyEvents,
    baseballEvents,
    tennisEvents,
    tennisTodayEvents,
    tennisV1LivePart,
    mmaEvents,
    cricketEvents,
    handballEvents,
    formula1Fresh,
    mlbLiveTournaments,
    nbaLiveTournaments,
    volleyballLiveTournaments,
  ] = await Promise.all([
    getFootballLiveV2(),
    getBasketballLiveV2(),
    getHockeyLiveV2(),
    getBaseballLiveV2(),
    getTennisLiveV2(),
    getTennisTodayV2(),
    buildTennisLiveV1Cached(), // runs in parallel — does not depend on other results
    getExtraLiveEventsV2("boxing"),
    getExtraLiveEventsV2("cricket"),
    getExtraLiveEventsV2("handball"),
    getFormula1Live(),
    getMLBLive(),          // Statpal /v1/mlb/livescores — innings, hits, errors, outs
    getNBALive(),          // Statpal /v1/nba/livescores — quarter-by-quarter scores
    getVolleyballLive(),   // Statpal /v1/volleyball/livescores
  ]);
  // Populate V1 tennis league label cache from V2 today events (city → "ATP 250 · City")
  if (tennisTodayEvents && tennisTodayEvents.length > 0) {
    refreshTennisV2LeagueCache(tennisTodayEvents);
  }
  // Fire-and-forget odds cache warmers — don't block the broadcast path
  getTennisOdds().catch(() => {});
  getMLBOdds().catch(() => {});
  // Tennis live: v2 feed (usually empty for tennis) + v1 native live + today fallback.
  // The tennis API does not support v2 live/today endpoints (returns 404).
  // Primary source: v1/tennis/live (buildTennisLiveV1). The v2 path is kept as
  // a fallback for any future API upgrade that enables a v2 tennis live endpoint.
  const tennisSourceRank = (m: LiveMatchState): number => {
    const id = String(m.id);
    const prefixRank = id.startsWith("tennis-v2-")
      ? 4
      : id.startsWith("tennis-v1-")
        ? 3
        : 1;
    const realOddsRank = m.hasRealOdds ? 2 : 0;
    const liveDetailRank =
      (m._liveExtra?.currentPoints ? 1 : 0) +
      Math.min(3, m._liveExtra?.sets?.length ?? 0);
    return prefixRank * 100 + realOddsRank * 10 + liveDetailRank;
  };
  const dedupeTennisLiveMatches = (
    matches: LiveMatchState[],
  ): LiveMatchState[] => {
    const bestByPair = new Map<string, LiveMatchState>();
    for (const match of matches) {
      const pairKey = _tennisPairKey(match.home, match.away);
      const current = bestByPair.get(pairKey);
      if (!current || tennisSourceRank(match) > tennisSourceRank(current)) {
        bestByPair.set(pairKey, match);
      }
    }
    return matches.filter(
      (match) =>
        bestByPair.get(_tennisPairKey(match.home, match.away)) === match,
    );
  };

  const tennisV2Part = buildTennisLiveV2(tennisEvents);
  const seededTennisLivePairs = new Set(
    [...tennisV2Part, ...tennisV1LivePart].map((m) =>
      _tennisPairKey(m.home, m.away),
    ),
  );
  const allLiveIds = new Set(
    [...tennisV2Part, ...tennisV1LivePart].map((m) => String(m.id)),
  );
  const todayStartedExtra = buildTennisLiveV2(
    (tennisTodayEvents ?? []).filter(
      (ev) => !allLiveIds.has(`tennis-v2-${ev.id}`),
    ),
  ).filter(
    (m) =>
      !allLiveIds.has(String(m.id)) &&
      !seededTennisLivePairs.has(_tennisPairKey(m.home, m.away)),
  );
  const tennisLivePart = dedupeTennisLiveMatches([
    ...tennisV2Part,
    ...tennisV1LivePart,
    ...todayStartedExtra,
  ]);
  const tennisLivePairKeys = new Set(
    tennisLivePart.map((m) => _tennisPairKey(m.home, m.away)),
  );
  const startedUpcomingTennisCandidates = allUpcoming.filter((up) => {
    if (up.sport !== "tennis") return false;
    if (!up.id || !String(up.id).startsWith("tennis-v2-")) return false;
    const id = String(up.id);
    if (allLiveIds.has(id)) return false;
    if (tennisLivePairKeys.has(_tennisPairKey(up.home, up.away))) return false;
    const kickoffMs = parseUpcomingKickoffMs(up);
    if (!kickoffMs) return false;
    if (kickoffMs > now + 2 * 60_000) return false;
    if (now - kickoffMs > 4 * 60 * 60_000) return false;
    return !!up.home && !!up.away;
  });
  const startedUpcomingTennisDetails = new Map<
    number,
    TennisLiveDetailSnapshot
  >();
  await Promise.all(
    startedUpcomingTennisCandidates.slice(0, 16).map(async (up) => {
      const providerId = Number(String(up.id).replace(/^tennis-v2-/, ""));
      if (!Number.isFinite(providerId)) return;
      const detail = await getTennisMatchDetailV2(providerId).catch(() => null);
      if (detail) startedUpcomingTennisDetails.set(providerId, detail);
    }),
  );
  const startedUpcomingTennisPart = (() => {
    const existing = new Set(tennisLivePart.map((m) => String(m.id)));
    const out: LiveMatchState[] = [];
    for (const up of startedUpcomingTennisCandidates) {
      const id = String(up.id);
      if (existing.has(id)) continue;
      const providerId = Number(String(id).replace(/^tennis-v2-/, ""));
      const detail = Number.isFinite(providerId)
        ? startedUpcomingTennisDetails.get(providerId)
        : undefined;
      if (!detail || !detail.sets?.length) continue;
      const sets: [number, number][] = detail.sets;
      const currentPoints = detail?.currentPoints;
      const serving = detail?.serving;
      const currentSetNum = Math.max(1, sets.length);
      const completedSets = Math.max(0, currentSetNum - 1);
      const homeSetsWon = sets
        .slice(0, completedSets)
        .filter(([homeGames, awayGames]) => homeGames > awayGames).length;
      const awaySetsWon = sets
        .slice(0, completedSets)
        .filter(([homeGames, awayGames]) => awayGames > homeGames).length;
      const pairKey = _tennisPairKey(up.home, up.away);
      const baseOdds = makeTennisBaseOdds(up.home, up.away);
      const liveOddsState = computeTennisLiveOdds(
        baseOdds,
        sets,
        homeSetsWon,
        awaySetsWon,
        currentPoints,
        serving,
        Number.isFinite(providerId)
          ? _tennisLiveOddsCache.get(providerId)
          : undefined,
      );
      const liveOdds = liveOddsState.odds;
      const homeProb =
        liveOdds.home > 0 && liveOdds.away > 0
          ? 1 / liveOdds.home / (1 / liveOdds.home + 1 / liveOdds.away)
          : 0.5;
      out.push({
        id,
        home: up.home,
        away: up.away,
        league: up.league ?? "Tennis",
        country: up.country ?? "",
        sport: "tennis",
        homeScore: homeSetsWon,
        awayScore: awaySetsWon,
        minute: currentSetNum * 20,
        status: detail?.status ?? tennisSetLabel(currentSetNum),
        hasRealOdds: liveOddsState.hasRealOdds,
        odds: liveOdds,
        markets: {
          ...makeAdvancedMarketsFromTeams(up.home, up.away),
          tennisExtra: computeLiveTennisExtras(
            homeProb,
            sets,
            homeSetsWon,
            awaySetsWon,
            currentSetNum,
            currentPoints,
            serving,
          ),
        } as AdvancedMarkets,
        events: [],
        _liveExtra: {
          sets,
          ...(currentPoints ? { currentPoints } : {}),
          ...(serving ? { serving } : {}),
        },
      });
      if (out.length >= 60) break;
    }
    return out;
  })();
  // Apply per-sport anti-flicker: if a sport's API temporarily returns empty,
  // keep the last good data for up to SPORT_FALLBACK_TTL_MS (35s).
  const footballLive = sportWithFallback(
    "football",
    await buildFootballLiveV2(footballEvents),
  );
  // Basketball live: merge Statpal NBA livescores + SportsAPI V2.
  // Statpal wins when it has quarter detail (q1–q4, OT).
  // SportsAPI V2 fills games not yet flipped to live by Statpal.
  const statpalNBALive = buildNBALiveMatches(nbaLiveTournaments);
  const sapiv2NBALive = await buildBasketballLiveV2(basketballEvents);
  const statpalNBAPairs = new Set(
    statpalNBALive.map((m) => `${m.home}|${m.away}`),
  );
  const mergedBasketballLive = [
    ...statpalNBALive,
    ...sapiv2NBALive.filter(
      (m) => !statpalNBAPairs.has(`${m.home}|${m.away}`),
    ),
  ];
  const basketballLive = sportWithFallback("basketball", mergedBasketballLive);
  const hockeyLive = sportWithFallback(
    "hockey",
    buildHockeyLiveV2(hockeyEvents),
  );
  // Baseball live: merge SportsAPI V2 + Statpal livescores.
  // Statpal wins when it has inning detail (innings, hits, errors, outs).
  // SportsAPI V2 wins for games Statpal hasn't yet flipped to live (sticky guard).
  const statpalMLBLive = buildMLBLiveMatches(mlbLiveTournaments);
  const sapiv2MLBLive = buildBaseballLiveV2(baseballEvents);
  // Deduplicate: a game seen in both feeds → prefer the Statpal entry (richer
  // inning data).  Games only in SportsAPI V2 are kept as fallback.
  const statpalMLBPairs = new Set(
    statpalMLBLive.map((m) => `${m.home}|${m.away}`),
  );
  const mergedBaseballLive = [
    ...statpalMLBLive,
    ...sapiv2MLBLive.filter(
      (m) => !statpalMLBPairs.has(`${m.home}|${m.away}`),
    ),
  ];
  const baseballLive = sportWithFallback("baseball", mergedBaseballLive);
  const volleyballLiveItems = sportWithFallback(
    "volleyball",
    buildVolleyballLiveMatches(volleyballLiveTournaments),
  );
  const tennisLive = sportWithFallback("tennis", tennisLivePart);
  const boxingLive = sportWithFallback(
    "boxing",
    buildExtraLiveV2("boxing", mmaEvents),
  );
  const cricketLive = sportWithFallback(
    "cricket",
    buildExtraLiveV2("cricket", cricketEvents),
  );
  const handballLive = sportWithFallback(
    "handball",
    buildExtraLiveV2("handball", handballEvents),
  );
  const formula1Live = sportWithFallback("formula1", formula1Fresh);

  // ── Live feed order: Futebol → Ténis → Hóquei → Basquete → Voleibol → Beisebol → outros
  // mergeStickyLive: re-injects any match seen in the last 5 min that the API
  // temporarily omitted. Fresh data always wins; injected matches use last-known
  // score/status so the match never disappears mid-game.
  const livePart = mergeStickyLive([
    ...footballLive,
    ...tennisLive,
    ...hockeyLive,
    ...basketballLive,
    ...volleyballLiveItems,
    ...baseballLive,
    ...boxingLive,
    ...cricketLive,
    ...handballLive,
    ...formula1Live,
    ...startedUpcomingTennisPart,
  ]);

  const liveIds = new Set(livePart.map((m) => String(m.id)));
  // Deduplicate by team pair — prevents upcoming duplicating a match already in the live feed
  const liveTeamPairs = new Set(livePart.map((m) => `${m.home}|${m.away}`));

  // Max minutes ahead a match can be to appear as "Em Breve", per sport
  const SOON_WINDOW: Record<string, number> = {
    football: 3,
    soccer: 3,   // só aparecem em "Em Breve" a ≤ 3 min do início
    basketball: 3,
    hockey: 3,
    tennis: 3,   // jogos já iniciados são promovidos via startedUpcomingTennisCandidates
  };
  const DEFAULT_SOON_WINDOW = 3; // ≤ 3 min antes do início para todos os desportos
  const startingSoonCandidates = allUpcoming
    .filter((m) => {
      // Tennis always has computed odds even without a real bookmaker price — allow all.
      // Other sports require real odds to avoid showing matches with no betting context.
      if (m.sport !== "tennis" && !m.hasRealOdds) return false;
      const si = matchStartsInMinutes(m.date, m.time);
      const maxSi = SOON_WINDOW[m.sport] ?? DEFAULT_SOON_WINDOW;
      return (
        isFinite(si) &&
        si >= -60 &&
        si <= maxSi &&
        !liveIds.has(String(m.id)) &&
        !liveTeamPairs.has(`${m.home}|${m.away}`)
      );
    })
    .sort(
      (a, b) =>
        matchStartsInMinutes(a.date, a.time) -
        matchStartsInMinutes(b.date, b.time),
    )
    .slice(0, 50);

  // Promote tennis "Em Breve" matches that started >2 min ago into the live feed.
  // The Statpal /live endpoint can lag 5-15 min for Challenger events; this bridges
  // the gap by showing them as live (0-0, "1st set") until real data arrives.
  const promotedTennis: LiveMatchState[] = [];
  const startingSoonFinal: LiveMatchState[] = [];
  for (const m of startingSoonCandidates) {
    const realStartsIn = matchStartsInMinutes(m.date, m.time);
    const startsIn = Math.max(
      0,
      Math.round(realStartsIn <= 2 ? 0 : realStartsIn),
    );
    if (m.sport === "tennis") {
      const providerStatusGroup = m.providerStatusGroup;
      const providerStatusText = m.providerStatusText ?? "";
      const winnerKnown = m.providerWinnerKnown === true;
      const tennisFinished =
        winnerKnown || isTennisFinishedStatusText(providerStatusText);
      if (tennisFinished) continue;

      if (providerStatusGroup === 1) {
        promotedTennis.push({
          id: m.id,
          home: m.home,
          away: m.away,
          league: m.league,
          country: m.country,
          sport: m.sport,
          homeScore: 0,
          awayScore: 0,
          minute: 20,
          status: providerStatusText || "Em Jogo",
          hasRealOdds: m.hasRealOdds,
          odds: m.odds,
          markets: m.markets,
          events: [],
          _liveExtra: { sets: [[0, 0]], currentPoints: ["0", "0"] },
        });
        continue;
      }

      if (providerStatusGroup !== undefined && providerStatusGroup !== 2)
        continue;

      if (startsIn === 0) {
        if (
          isFinite(realStartsIn) &&
          realStartsIn < -2 &&
          realStartsIn > -240
        ) {
          promotedTennis.push({
            id: m.id,
            home: m.home,
            away: m.away,
            league: m.league,
            country: m.country,
            sport: m.sport,
            homeScore: 0,
            awayScore: 0,
            minute: 20,
            status: "1st set",
            hasRealOdds: m.hasRealOdds,
            odds: m.odds,
            markets: m.markets,
            events: [],
            _liveExtra: { sets: [[0, 0]], currentPoints: ["0", "0"] },
          });
          continue;
        }
      }
    }
    startingSoonFinal.push({
      id: m.id,
      home: m.home,
      away: m.away,
      league: m.league,
      country: m.country,
      sport: m.sport,
      homeScore: 0,
      awayScore: 0,
      minute: 0,
      status: "Em Breve",
      hasRealOdds: m.hasRealOdds,
      odds: m.odds,
      markets: m.markets,
      events: [],
      date: m.date,
      time: m.time,
      startsIn,
      scheduledTime: m.time,
      scheduledDate: m.date,
    });
  }

  syncLiveCompetitionCatalog([
    ...livePart.map((m) => ({
      eventId: String(m.id),
      providerEventId: String(m.id),
      sport: m.sport,
      name: m.league,
      country: m.country,
      provider: "sportsapi_live",
      status: m.status,
      suspensionReason: m._suspensionReason ?? null,
    })),
    ...promotedTennis.map((m) => ({
      eventId: String(m.id),
      providerEventId: String(m.id),
      sport: m.sport,
      name: m.league,
      country: m.country,
      provider: "sportsapi_live",
      status: m.status,
      suspensionReason: m._suspensionReason ?? null,
    })),
    ...startingSoonFinal.map((m) => ({
      eventId: String(m.id),
      providerEventId: String(m.id),
      sport: m.sport,
      name: m.league,
      country: m.country,
      provider: "sportsapi_upcoming",
      status: m.status,
      suspensionReason: null,
    })),
  ]);

  const liveDecisions = await getCompetitionCatalogDecisions(
    [...livePart, ...promotedTennis].map((m) => ({
      eventId: String(m.id),
      sport: m.sport,
      league: m.league,
      country: m.country,
    })),
    "live",
  );
  const prematchDecisions = await getCompetitionCatalogDecisions(
    startingSoonFinal.map((m) => ({
      eventId: String(m.id),
      sport: m.sport,
      league: m.league,
      country: m.country,
    })),
    "prematch",
  );

  const sortByCatalogPriority = (
    matches: LiveMatchState[],
    decisions: Map<string, { priority: number | null }>,
    fallbackSort?: (a: LiveMatchState, b: LiveMatchState) => number,
  ): LiveMatchState[] => {
    return matches
      .map((match, index) => ({
        match,
        index,
        priority: decisions.get(String(match.id))?.priority ?? null,
      }))
      .sort((a, b) => {
        const aPrio = a.priority ?? 999;
        const bPrio = b.priority ?? 999;
        if (aPrio !== bPrio) return aPrio - bPrio;
        if (fallbackSort) {
          const fallback = fallbackSort(a.match, b.match);
          if (fallback !== 0) return fallback;
        }
        return a.index - b.index;
      })
      .map((entry) => entry.match);
  };

  const filteredLive = sortByCatalogPriority(
    [...livePart, ...promotedTennis].filter(
      (m) => liveDecisions.get(String(m.id))?.visible ?? true,
    ),
    liveDecisions,
  );
  const filteredPrematch = sortByCatalogPriority(
    startingSoonFinal.filter(
      (m) => prematchDecisions.get(String(m.id))?.visible ?? true,
    ),
    prematchDecisions,
    (a, b) =>
      matchStartsInMinutes(a.date ?? "", a.time ?? "") -
      matchStartsInMinutes(b.date ?? "", b.time ?? ""),
  );

  const applyOperationalDecision = (
    match: LiveMatchState,
    decision?: {
      state: string | null;
      tradingStatus: string | null;
      suspensionReason: string | null;
    },
  ): LiveMatchState => {
    if (!decision) return match;
    const mustSuspend =
      decision.state === "SUSPENDED" ||
      decision.state === "TRADING_RESTRICTED" ||
      decision.tradingStatus === "manual_suspend" ||
      decision.tradingStatus === "trading_restricted" ||
      decision.tradingStatus === "restricted";
    if (!mustSuspend) return match;
    return {
      ...match,
      marketSuspension: {
        ...(match.marketSuspension ?? {}),
        __admin__: Date.now() + 24 * 60 * 60 * 1000,
      },
      _suspensionReason: decision.suspensionReason ?? "SUSPENSO MANUALMENTE",
    };
  };

  const dedupedLive = dedupeLiveMatchesByIdentity(
    filteredLive.map((match) =>
      applyOperationalDecision(match, liveDecisions.get(String(match.id))),
    ),
  );
  const dedupedPrematch = dedupeLiveMatchesByIdentity(
    filteredPrematch.map((match) =>
      applyOperationalDecision(match, prematchDecisions.get(String(match.id))),
    ),
  ).filter(
    (prematch) =>
      !dedupedLive.some(
        (live) => liveMatchIdentityKey(live) === liveMatchIdentityKey(prematch),
      ),
  );

  const result = {
    matches: [...dedupedLive, ...dedupedPrematch],
  };
  if (result.matches.length > 0) {
    livePayloadFallbackCache = { payload: result, builtAt: Date.now() };
  }
  return result;
}

const LIVE_PAYLOAD_FALLBACK_TTL_MS = 45_000;
let livePayloadFallbackCache: {
  payload: { matches: LiveMatchState[] };
  builtAt: number;
} | null = null;
const LIVE_PAYLOAD_CACHE_TTL_MS = 1_500;
let livePayloadCache: {
  payload: { matches: LiveMatchState[] };
  builtAt: number;
} | null = null;
let livePayloadInFlight: Promise<{ matches: LiveMatchState[] }> | null = null;

// Per-sport last-good-data anti-flicker caches.
// When a sport's live API returns empty (transient failure/rate-limit), use the last
// non-empty result for up to SPORT_FALLBACK_TTL_MS before showing an empty section.
const SPORT_FALLBACK_TTL_MS = 35_000;
const _lastGoodSport = new Map<
  string,
  { matches: LiveMatchState[]; savedAt: number }
>();

function sportWithFallback(
  sport: string,
  fresh: LiveMatchState[],
): LiveMatchState[] {
  const now = Date.now();
  if (fresh.length > 0) {
    _lastGoodSport.set(sport, { matches: fresh, savedAt: now });
    return fresh;
  }
  const cached = _lastGoodSport.get(sport);
  if (cached && now - cached.savedAt < SPORT_FALLBACK_TTL_MS)
    return cached.matches;
  return fresh; // genuinely empty — nothing cached or cache expired
}

// ── Per-match sticky live cache ───────────────────────────────────────────────
// Once a match enters the live feed it stays for STICKY_LIVE_TTL_MS even when
// the API temporarily omits it (API hiccup, rate-limit, V1 rotation).
// Score/status shown is the last known snapshot — better than making the match
// disappear and reappear mid-game.
const STICKY_LIVE_TTL_MS = 5 * 60_000; // 5 minutes since last seen
const _stickyLive = new Map<
  string,
  { match: LiveMatchState; lastSeenAt: number }
>();

function mergeStickyLive(freshMatches: LiveMatchState[]): LiveMatchState[] {
  const now = Date.now();

  // Update sticky cache entries for every match in the fresh feed
  for (const m of freshMatches) {
    _stickyLive.set(String(m.id), { match: m, lastSeenAt: now });
  }

  // Evict expired entries (not seen for > STICKY_LIVE_TTL_MS)
  for (const [id, entry] of _stickyLive) {
    if (now - entry.lastSeenAt > STICKY_LIVE_TTL_MS) _stickyLive.delete(id);
  }

  // Build lookup sets for deduplication
  const freshIds = new Set(freshMatches.map((m) => String(m.id)));
  const freshPairs = new Set(
    freshMatches.map((m) => `${m.home.toLowerCase()}|${m.away.toLowerCase()}`),
  );

  // Re-inject matches that are sticky but not in the current fresh feed
  const injected: LiveMatchState[] = [];
  for (const [id, entry] of _stickyLive) {
    if (freshIds.has(id)) continue; // already in fresh feed
    const pair = `${entry.match.home.toLowerCase()}|${entry.match.away.toLowerCase()}`;
    if (freshPairs.has(pair)) continue; // same game under different id (e.g. V1→V2 transition)
    injected.push(entry.match);
  }

  return [...freshMatches, ...injected];
}

function normalizeMatchIdentityPart(value: string | undefined): string {
  return String(value ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    // strip common Spanish/Portuguese prepositions that differ between V1 and V2 feeds
    // e.g. "9 de Julio Rafaela" (V1) vs "9 de Julio de Rafaela" (V2) → both become "9 julio rafaela"
    .replace(/\b(de|do|da|di|del)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function liveMatchIdentityKey(
  match: Pick<LiveMatchState, "sport" | "home" | "away">,
): string {
  return [
    normalizeMatchIdentityPart(match.sport),
    normalizeMatchIdentityPart(match.home),
    normalizeMatchIdentityPart(match.away),
  ].join("|");
}

function pickPreferredLiveMatch(
  current: LiveMatchState,
  candidate: LiveMatchState,
): LiveMatchState {
  const currentIsV2 = String(current.id).includes("-v2-") ? 1 : 0;
  const candidateIsV2 = String(candidate.id).includes("-v2-") ? 1 : 0;
  if (candidateIsV2 !== currentIsV2)
    return candidateIsV2 > currentIsV2 ? candidate : current;

  const currentLive = current.startsIn === undefined ? 1 : 0;
  const candidateLive = candidate.startsIn === undefined ? 1 : 0;
  if (candidateLive !== currentLive)
    return candidateLive > currentLive ? candidate : current;

  const currentLeagueId = current.leagueId ? 1 : 0;
  const candidateLeagueId = candidate.leagueId ? 1 : 0;
  if (candidateLeagueId !== currentLeagueId)
    return candidateLeagueId > currentLeagueId ? candidate : current;

  const currentScoreSignal =
    (current.homeScore ?? 0) + (current.awayScore ?? 0);
  const candidateScoreSignal =
    (candidate.homeScore ?? 0) + (candidate.awayScore ?? 0);
  if (candidateScoreSignal !== currentScoreSignal)
    return candidateScoreSignal > currentScoreSignal ? candidate : current;

  const currentMinute = Number(current.minute ?? 0);
  const candidateMinute = Number(candidate.minute ?? 0);
  if (candidateMinute !== currentMinute)
    return candidateMinute > currentMinute ? candidate : current;

  const currentOdds = current.hasRealOdds ? 1 : 0;
  const candidateOdds = candidate.hasRealOdds ? 1 : 0;
  if (candidateOdds !== currentOdds)
    return candidateOdds > currentOdds ? candidate : current;

  const currentEvents = current.events?.length ?? 0;
  const candidateEvents = candidate.events?.length ?? 0;
  if (candidateEvents !== currentEvents)
    return candidateEvents > currentEvents ? candidate : current;

  return String(candidate.id) > String(current.id) ? candidate : current;
}

function dedupeLiveMatchesByIdentity(
  matches: LiveMatchState[],
): LiveMatchState[] {
  const byIdentity = new Map<string, LiveMatchState>();
  const order: string[] = [];

  for (const match of matches) {
    const key = liveMatchIdentityKey(match);
    const existing = byIdentity.get(key);
    if (!existing) {
      byIdentity.set(key, match);
      order.push(key);
      continue;
    }
    byIdentity.set(key, pickPreferredLiveMatch(existing, match));
  }

  return order.map((key) => byIdentity.get(key)!).filter(Boolean);
}

function getLivePayloadFallback(): { matches: LiveMatchState[] } | null {
  if (!livePayloadFallbackCache) return null;
  if (
    Date.now() - livePayloadFallbackCache.builtAt >
    LIVE_PAYLOAD_FALLBACK_TTL_MS
  )
    return null;
  return livePayloadFallbackCache.payload;
}

router.get("/team-logo/:sport/:teamId", async (req: Request, res: Response) => {
  const sport = String(req.params["sport"] ?? "")
    .trim()
    .toLowerCase();
  const teamId = String(req.params["teamId"] ?? "").trim();
  const imageVersion = String(req.query["imageVersion"] ?? "").trim();

  if (!teamId) {
    res.status(400).end();
    return;
  }

  const v2ImageBase = (() => {
    if (sport === "football")
      return "https://v2.football.sportsapipro.com/images/teams";
    if (sport === "basketball")
      return "https://v2.basketball.sportsapipro.com/images/teams";
    if (sport === "hockey")
      return "https://v2.hockey.sportsapipro.com/images/teams";
    if (sport === "tennis")
      return "https://v2.tennis.sportsapipro.com/images/teams";
    if (sport === "baseball")
      return "https://v2.baseball.sportsapipro.com/images/teams";
    if (sport === "volleyball")
      return "https://v2.volleyball.sportsapipro.com/images/teams";
    return null;
  })();

  if (sport === "football" && imageVersion) {
    const url = new URL(
      `https://v1.football.sportsapipro.com/images/competitors/${encodeURIComponent(teamId)}`,
    );
    url.searchParams.set("imageVersion", imageVersion);
    res.setHeader("Cache-Control", "public, max-age=21600, s-maxage=21600");
    res.redirect(url.toString());
    return;
  }

  if (!v2ImageBase) {
    res.status(404).end();
    return;
  }

  try {
    const resp = await fetch(`${v2ImageBase}/${encodeURIComponent(teamId)}`, {
      signal: AbortSignal.timeout(10_000),
      headers: sapiHeaders(),
    });

    if (!resp.ok) {
      if (sport === "football") {
        const fallback = new URL(
          `https://v1.football.sportsapipro.com/images/competitors/${encodeURIComponent(teamId)}`,
        );
        if (imageVersion)
          fallback.searchParams.set("imageVersion", imageVersion);
        res.setHeader("Cache-Control", "public, max-age=21600, s-maxage=21600");
        res.redirect(fallback.toString());
        return;
      }
      res.status(resp.status === 404 ? 404 : 502).end();
      return;
    }

    const contentType = resp.headers.get("content-type") ?? "image/png";
    const body = Buffer.from(await resp.arrayBuffer());
    res.setHeader("Cache-Control", "public, max-age=21600, s-maxage=21600");
    res.setHeader("Content-Type", contentType);
    res.send(body);
  } catch {
    if (sport === "football") {
      const fallback = new URL(
        `https://v1.football.sportsapipro.com/images/competitors/${encodeURIComponent(teamId)}`,
      );
      if (imageVersion) fallback.searchParams.set("imageVersion", imageVersion);
      res.setHeader("Cache-Control", "public, max-age=21600, s-maxage=21600");
      res.redirect(fallback.toString());
      return;
    }
    res.status(502).end();
  }
});

function refreshLivePayloadInBackground(): Promise<{
  matches: LiveMatchState[];
}> {
  if (livePayloadInFlight) return livePayloadInFlight;
  livePayloadInFlight = buildLivePayload()
    .then((payload) => {
      livePayloadCache = { payload, builtAt: Date.now() };
      return payload;
    })
    .finally(() => {
      livePayloadInFlight = null;
    });
  return livePayloadInFlight;
}

async function getLivePayloadCached(
  forceFresh = false,
): Promise<{ matches: LiveMatchState[] }> {
  if (
    !forceFresh &&
    livePayloadCache &&
    Date.now() - livePayloadCache.builtAt < LIVE_PAYLOAD_CACHE_TTL_MS
  ) {
    return livePayloadCache.payload;
  }

  // Stale-while-revalidate: once ANY payload has ever been built, never make
  // an HTTP request block on a fresh upstream rebuild (upstream sports APIs
  // can take several seconds on a cold per-sport cache). Serve the stale
  // cache immediately and kick off a rebuild in the background — the next
  // request (or the SSE broadcast / proactive warm-up interval) will pick up
  // the fresh data. Only block-wait when there is truly no cache yet (the
  // very first request after a server restart).
  if (!forceFresh && livePayloadCache) {
    refreshLivePayloadInBackground().catch(() => {});
    return livePayloadCache.payload;
  }

  return refreshLivePayloadInBackground();
}

// Broadcast payload to all connected SSE + WebSocket clients; prune dead connections.
// Guards: (1) skip if no clients, (2) if a broadcast is already in progress, set
// broadcastPending so the update is sent immediately after — never silently dropped.
// (3) avoid sending empty matches unless confirmed, to keep the last good state on clients.
async function broadcastLive(): Promise<void> {
  if (sseClients.size === 0 && wsLiveClients.size === 0) return;
  if (broadcastInProgress) {
    broadcastPending = true; // queue a follow-up — don't drop the score update
    return;
  }
  broadcastInProgress = true;
  broadcastPending = false;
  try {
    const payload = await getLivePayloadCached(true);
    const effectivePayload =
      payload.matches.length === 0
        ? (getLivePayloadFallback() ?? payload)
        : payload;
    if (effectivePayload.matches.length === 0) {
      consecutiveEmptyBroadcasts += 1;
      if (consecutiveEmptyBroadcasts < 3) return;
    } else {
      consecutiveEmptyBroadcasts = 0;
    }
    // Only serialize once
    const wsMsgObj = { type: "snapshot", ...effectivePayload };
    const jsonStr = JSON.stringify(wsMsgObj);

    // SSE clients
    const sseChunk = `data: ${jsonStr}\n\n`;
    for (const client of sseClients) {
      try {
        client.write(sseChunk);
      } catch {
        sseClients.delete(client);
      }
    }
    // WebSocket clients
    for (const ws of wsLiveClients) {
      try {
        if (ws.readyState === 1 /* OPEN */) ws.send(jsonStr);
        else wsLiveClients.delete(ws);
      } catch {
        wsLiveClients.delete(ws);
      }
    }
  } catch {
    /* ignore — keep clients connected */
  } finally {
    broadcastInProgress = false;
    lastBroadcastAt = Date.now();
    // If a score update arrived while we were building, send it now immediately.
    if (broadcastPending) {
      broadcastPending = false;
      setTimeout(() => {
        broadcastLive().catch(() => {});
      }, 0);
    }
  }
}

/**
 * Broadcasts a partial update (delta) for a single match to all connected clients (SSE & WS).
 * This is used for sub-second updates of scores and odds.
 */
export function broadcastMatchDelta(
  matchId: string,
  delta: Partial<LiveMatchState>,
): void {
  broadcastBatchDelta([{ matchId, delta }]);
}

/**
 * Broadcasts a batch of partial updates to all connected clients.
 * Reduces overhead by sending multiple updates in a single network packet.
 */
export function broadcastBatchDelta(
  updates: Array<{ matchId: string; delta: Partial<LiveMatchState> }>,
): void {
  if (updates.length === 0) return;

  // Add to global buffer
  pendingBatchUpdates.push(...updates);

  // If buffer getting large, flush immediately; otherwise wait 100ms
  if (pendingBatchUpdates.length > 50) {
    flushBatchUpdates();
  } else if (!batchFlushTimer) {
    batchFlushTimer = setTimeout(flushBatchUpdates, 100);
  }
}

router.get("/live", async (req: Request, res: Response) => {
  res.setHeader(
    "Cache-Control",
    "no-store, no-cache, must-revalidate, max-age=0",
  );
  const lean = String(req.query["lean"] ?? "0") === "1";
  const limitRaw = parseInt(String(req.query["limit"] ?? ""), 10);
  const limit = Number.isFinite(limitRaw)
    ? Math.max(0, Math.min(500, limitRaw))
    : 0;
  try {
    const payload = await getLivePayloadCached();
    const effectivePayload =
      payload.matches.length === 0
        ? (getLivePayloadFallback() ?? payload)
        : payload;
    const matches =
      limit > 0
        ? effectivePayload.matches.slice(0, limit)
        : effectivePayload.matches;
    if (!lean) {
      res.json({ matches });
      return;
    }
    const out = matches.map((m) => {
      const anyM = m as any;
      const { markets, events, ...rest } = anyM;
      return rest;
    });
    res.json({ matches: out });
  } catch (err) {
    logger.error({ err }, "[live route] unexpected error");
    res.json(getLivePayloadFallback() ?? { matches: [] });
  }
});

router.get("/live-match/:id", async (req: Request, res: Response) => {
  res.setHeader(
    "Cache-Control",
    "no-store, no-cache, must-revalidate, max-age=0",
  );
  const id = String(req.params["id"] ?? "");
  const forceFresh = String(req.query["fresh"] ?? "0") === "1";
  if (!id) {
    res.json({ match: null });
    return;
  }
  try {
    const payload = await getLivePayloadCached(forceFresh);
    const effectivePayload =
      payload.matches.length === 0
        ? (getLivePayloadFallback() ?? payload)
        : payload;
    const match =
      effectivePayload.matches.find((m) => String(m.id) === id) ?? null;
    res.json({ match });
  } catch {
    const fallback = getLivePayloadFallback();
    res.json({
      match: fallback?.matches.find((m) => String(m.id) === id) ?? null,
    });
  }
});

