function buildTennisUpcomingFromOddsEntries(
  odds: TennisOddsEntry[],
): UpcomingMatch[] {
  const seen = new Set<string>();
  const out: UpcomingMatch[] = [];
  for (const entry of odds) {
    const home = entry.players?.[0]?.name?.trim() ?? "";
    const away = entry.players?.[1]?.name?.trim() ?? "";
    if (!home || !away) continue;
    const id = `tennis-v2-${entry.matchId}`;
    if (seen.has(id)) continue;
    seen.add(id);
    out.push({
      id,
      home,
      away,
      league: entry.tournamentName || "Tennis",
      country: "",
      date: entry.date,
      time: entry.time,
      sport: "tennis",
      hasRealOdds: entry.matchOdds[0] > 0 && entry.matchOdds[1] > 0,
      odds: { home: entry.matchOdds[0], draw: 0, away: entry.matchOdds[1] },
      markets:
        (entry.markets as AdvancedMarkets) ??
        makeAdvancedMarketsFromTeams(home, away),
    });
  }
  return out;
}

function _normTennisName(n: string): string {
  return n
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function mergeTennisUpcomingSources(
  base: UpcomingMatch[],
  oddsBased: UpcomingMatch[],
): UpcomingMatch[] {
  const merged = new Map<string, UpcomingMatch>();

  // Build player-pair index from oddsBased (real odds — highest priority).
  // Keys are sorted so "A|B" and "B|A" both match.
  const oddsPlayerIndex = new Map<string, UpcomingMatch>();
  for (const m of oddsBased) {
    const pk = [_normTennisName(m.home), _normTennisName(m.away)]
      .sort()
      .join("|");
    oddsPlayerIndex.set(pk, m);
    merged.set(String(m.id), m);
  }

  // Add V1 matches that have no V2 odds counterpart (same players on same day).
  for (const m of base) {
    const pk = [_normTennisName(m.home), _normTennisName(m.away)]
      .sort()
      .join("|");
    if (oddsPlayerIndex.has(pk)) continue; // V2 odds version exists — skip V1 duplicate
    merged.set(String(m.id), m);
  }

  return [...merged.values()];
}

// ─── Top-level upcoming cache — 60s TTL so repeated 30s polls are instant ─────
type UpcomingTopCache = {
  football: UpcomingMatch[];
  tennis: UpcomingMatch[];
  basketball: UpcomingMatch[];
  hockey: UpcomingMatch[];
  volleyball: UpcomingMatch[];
  baseball: UpcomingMatch[];
  boxing: UpcomingMatch[];
  cricket: UpcomingMatch[];
  handball: UpcomingMatch[];
  formula1: UpcomingMatch[];
  fetchedAt: number;
};
let upcomingTopCache: UpcomingTopCache | null = null;
let upcomingTopInFlight: Promise<UpcomingTopCache> | null = null;
const UPCOMING_TOP_TTL = 60_000;
const UPCOMING_TO_LIVE_ELIGIBILITY_MS = 6 * 60 * 60 * 1000;
const recentUpcomingFootballIds = new Map<string, number>();
const recentUpcomingV2Ids = new Map<string, number>();

function parseUpcomingKickoffMs(
  match: Pick<UpcomingMatch, "date" | "time">,
): number | null {
  if (!match.date || !match.time) return null;
  try {
    if (/^\d{4}-\d{2}-\d{2}$/.test(match.date)) {
      const [hStr = "0", mStr = "0"] = match.time.split(":");
      return new Date(
        `${match.date}T${String(parseInt(hStr, 10)).padStart(2, "0")}:${mStr}:00Z`,
      ).getTime();
    }
    const [dd, mm, yyyy] = match.date.split(".");
    if (!dd || !mm || !yyyy) return null;
    const offsetH = lisbonOffsetHours();
    const [hStr = "0", mStr = "0"] = match.time.split(":");
    const hUtc = (parseInt(hStr, 10) - offsetH + 24) % 24;
    return new Date(
      `${yyyy}-${mm}-${dd}T${String(hUtc).padStart(2, "0")}:${mStr}:00Z`,
    ).getTime();
  } catch {
    return null;
  }
}

function normalizeUpcomingVisibilityKey(
  match: Pick<UpcomingMatch, "sport" | "home" | "away" | "league">,
): string {
  const norm = (value: string | undefined) =>
    String(value ?? "")
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();

  return [
    norm(match.sport),
    norm(match.home),
    norm(match.away),
    norm(match.league),
  ].join("|");
}

function isFinishedVisibilityStatus(status: string | undefined): boolean {
  const s = String(status ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim()
    .toLowerCase();
  if (!s) return false;
  return (
    s === "ft" ||
    s === "aet" ||
    s === "ap" ||
    s.includes("fin") ||
    s.includes("final") ||
    s.includes("finished") ||
    s.includes("ended") ||
    s.includes("complete") ||
    s.includes("full time") ||
    s.includes("after extra") ||
    s.includes("after penalties") ||
    s.includes("retired") ||
    s.includes("abandon") ||
    s.includes("cancel") ||
    s.includes("awarded") ||
    s.includes("default")
  );
}

function rememberUpcomingFootballEligibility(matches: UpcomingMatch[]): void {
  const now = Date.now();
  for (const [id, expiryAt] of recentUpcomingFootballIds.entries()) {
    if (expiryAt <= now) recentUpcomingFootballIds.delete(id);
  }
  for (const match of matches) {
    if ((match.sport ?? "football") !== "football") continue;
    const scheduledMs = parseUpcomingKickoffMs(match);
    const expiryAt = scheduledMs
      ? Math.max(now + 30 * 60 * 1000, scheduledMs + 4 * 60 * 60 * 1000)
      : now + UPCOMING_TO_LIVE_ELIGIBILITY_MS;
    recentUpcomingFootballIds.set(String(match.id), expiryAt);
  }
}

function hasRecentUpcomingFootballEligibility(
  eventId: number | string,
): boolean {
  const key = `fb-v2-${eventId}`;
  const expiryAt = recentUpcomingFootballIds.get(key);
  if (!expiryAt) return false;
  if (expiryAt <= Date.now()) {
    recentUpcomingFootballIds.delete(key);
    return false;
  }
  return true;
}

function rememberUpcomingEligibility(matches: UpcomingMatch[]): void {
  const now = Date.now();
  for (const [k, expiryAt] of recentUpcomingV2Ids.entries()) {
    if (expiryAt <= now) recentUpcomingV2Ids.delete(k);
  }
  for (const match of matches) {
    const sport = String(match.sport ?? "football");
    const idRaw = String(match.id ?? "");
    const m = idRaw.match(
      /^(fb-v2|football-v2|bball-v2|hockey-v2|tennis-v2|baseball-v2|mlb-v2|volley-odds|volley-live|boxing-v2|cricket-v2|handball-v2|formula1-statpal)-(.+)$/,
    );
    if (!m) continue;
    const providerId = m[2] ?? "";
    if (!providerId) continue;

    const scheduledMs = parseUpcomingKickoffMs(match);
    const expiryAt = scheduledMs
      ? Math.max(now + 30 * 60 * 1000, scheduledMs + 4 * 60 * 60 * 1000)
      : now + UPCOMING_TO_LIVE_ELIGIBILITY_MS;
    recentUpcomingV2Ids.set(`${sport}:${providerId}`, expiryAt);
  }
}

function hasRecentUpcomingEligibility(
  sport: SportKey,
  providerId: number | string,
): boolean {
  const key = `${sport}:${String(providerId)}`;
  const expiryAt = recentUpcomingV2Ids.get(key);
  if (!expiryAt) return false;
  if (expiryAt <= Date.now()) {
    recentUpcomingV2Ids.delete(key);
    return false;
  }
  return true;
}

async function refreshUpcomingTop(): Promise<UpcomingTopCache> {
  const empty: UpcomingMatch[] = [];
  const [
    footballV1,
    tennisBase,
    tennisOdds,
    basketball,
    hockey,
    volleyball,
    baseball,
    boxing,
    cricket,
    handball,
    formula1,
    v5Football,
    v5Basketball,
    v5Hockey,
    v5Tennis,
    v5Baseball,
    v5Volleyball,
  ] = await Promise.all([
    buildUpcomingMatches().catch(() => empty),
    buildTennisUpcoming().catch(() => empty),
    getTennisOdds().catch(() => [] as TennisOddsEntry[]),
    buildBasketballUpcoming().catch(() => empty),
    buildHockeyUpcoming().catch(() => empty),
    buildVolleyballUpcoming().catch(() => empty),
    buildBaseballUpcoming().catch(() => empty),
    getExtraUpcomingEventsV2("boxing").then((events) => buildExtraUpcomingV2("boxing", events)).catch(() => empty),
    getExtraUpcomingEventsV2("cricket").then((events) => buildExtraUpcomingV2("cricket", events)).catch(() => empty),
    getExtraUpcomingEventsV2("handball").then((events) => buildExtraUpcomingV2("handball", events)).catch(() => empty),
    getFormula1Upcoming().catch(() => empty),
    buildV5Upcoming(1, 200).catch(() => empty),
    buildV5Upcoming(3, 200).catch(() => empty),
    buildV5Upcoming(2, 200).catch(() => empty),
    buildV5Upcoming(4, 200).catch(() => empty),
    buildV5Upcoming(5, 200).catch(() => empty),
    buildV5Upcoming(6, 200).catch(() => empty),
  ]);
  const tennis = mergeTennisUpcomingSources(
    tennisBase,
    buildTennisUpcomingFromOddsEntries(tennisOdds),
  );
  const football = mergeV5IntoUpcoming(footballV1, v5Football);
  const basketballMerged = mergeV5IntoUpcoming(basketball, v5Basketball);
  const hockeyMerged = mergeV5IntoUpcoming(hockey, v5Hockey);
  const tennisMerged = mergeV5IntoUpcoming(tennis, v5Tennis);
  const volleyballMerged = mergeV5IntoUpcoming(volleyball, v5Volleyball);
  const baseballMerged = mergeV5IntoUpcoming(baseball, v5Baseball);
  rememberUpcomingFootballEligibility(football);
  rememberUpcomingEligibility([
    ...football,
    ...tennisMerged,
    ...basketballMerged,
    ...hockeyMerged,
    ...volleyballMerged,
    ...baseballMerged,
      ...boxing,
    ...cricket,
    ...handball,
    ...formula1,
  ]);
  upcomingTopCache = {
    football,
    tennis: tennisMerged,
    basketball: basketballMerged,
    hockey: hockeyMerged,
    volleyball: volleyballMerged,
    baseball: baseballMerged,
    boxing,
    cricket,
    handball,
    formula1,
    fetchedAt: Date.now(),
  };
  return upcomingTopCache;
}

async function getUpcomingAll(): Promise<UpcomingTopCache> {
  const now = Date.now();
  if (upcomingTopCache && now - upcomingTopCache.fetchedAt < UPCOMING_TOP_TTL)
    return upcomingTopCache;
  if (upcomingTopCache) {
    if (!upcomingTopInFlight) {
      upcomingTopInFlight = refreshUpcomingTop().finally(() => {
        upcomingTopInFlight = null;
      });
    }
    return upcomingTopCache;
  }
  if (!upcomingTopInFlight) {
    upcomingTopInFlight = refreshUpcomingTop().finally(() => {
      upcomingTopInFlight = null;
    });
  }
  return upcomingTopInFlight;
}

